-- Poems batch 49
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6d56a819-85e1-4c64-8fbe-47d50c3afc71','聽琴','無名氏','唐','唐诗','tang','','[]','六律鏗鏘間宮徵，伶倫寫入梧桐尾。',64,'全唐诗/poet.tang.43000.json','["六律鏗鏘間宮徵，伶倫寫入梧桐尾。", "七條瘦玉叩寒星，萬派流泉哭纖指。", "空山雨腳隨雲起，古木燈青嘯山鬼。", "田文墮淚曲未終，子規啼血哀猿死。"]'),
('a1d7d12e-2f91-4569-887b-49d28eac2942','石榴','無名氏','唐','唐诗','tang','','[]','蟬嘯秋雲槐葉齊，石榴香老庭枝低。',66,'全唐诗/poet.tang.43000.json','["蟬嘯秋雲槐葉齊，石榴香老庭枝低。", "流霞色染紫罌粟，黃蠟紙苞紅瓠犀。", "玉刻冰壺[含]露溼，斒斑似帶湘娥泣。", "蕭娘初嫁嗜甘酸，嚼破水精千萬粒。"]'),
('70612bca-2824-47e1-8b3f-23d5a6ad4374','秦家行','無名氏','唐','唐诗','tang','','[]','彗孛飛光照天地，九天瓦裂屯冤氣。',64,'全唐诗/poet.tang.43000.json','["彗孛飛光照天地，九天瓦裂屯冤氣。", "鬼哭聲聲怨趙高，宮花滴盡扶蘇淚。", "禍起蕭牆不知戢，羽書催築長城急。", "劒上忠臣血未乾，沛公已向函關入。"]'),
('49c1cbd4-b16d-473d-b2c7-99297fc099ea','小蘇家','無名氏','唐','唐诗','tang','','[]','雙月謳䛩輾秋碧，細風斜掩神仙宅。',64,'全唐诗/poet.tang.43000.json','["雙月謳䛩輾秋碧，細風斜掩神仙宅。", "麥門冬長馬鬣青，茱萸蘂綻蠅頭赤。", "流蘇斗帳懸高壁，綵鳳盤龍繳香額。", "堂內月娥橫剪波，倚門腸斷鰕鬚隔。"]'),
('252c496a-f8eb-47bf-ac64-878be7e60767','斑竹','無名氏','唐','唐诗','tang','','[]','濃綠疎莖遶湘水，春風抽出蛟龍尾。',96,'全唐诗/poet.tang.43000.json','["濃綠疎莖遶湘水，春風抽出蛟龍尾。", "色抱霜花粉黛光，枝撑蜀錦紅霞起。", "交戛敲欹無俗聲，滿林風曳刀槍橫。", "殷痕苦雨洗不落，猶帶湘娥淚血腥。", "嫋娜梢頭掃秋月，影穿林下疑殘雪。", "我今慙愧子猷心，解愛此君名不滅。"]'),
('3f37ef9c-df1a-4094-a68b-144ae3ac9bac','天竺國胡僧水晶念珠','無名氏','唐','唐诗','tang','','[]','天竺胡僧踏雲立，紅精素貫鮫人泣。',96,'全唐诗/poet.tang.43000.json','["天竺胡僧踏雲立，紅精素貫鮫人泣。", "細影疑隨焰火銷，圓光恐滴袈裟溼。", "夜梵西天千佛聲，指輪次第驅寒星。", "若非葉下滴秋露，則是井底圓春冰。", "淒清妙麗應難並，眼界真如意珠靜。", "碧蓮花下獨提攜，堅潔何如幻泡影。"]'),
('91cdfcea-aa76-4815-a8e9-39fc6b3e8b26','白雪歌','無名氏','唐','唐诗','tang','','[]','皇穹何處飛瓊屑，散下人間作春雪。',128,'全唐诗/poet.tang.43000.json','["皇穹何處飛瓊屑，散下人間作春雪。", "五花馬踏白雲衢，七香車碾瑤墀月。", "蘇嵒乳洞擁山家，澗藤古栗盤銀虵。", "寒郊複疊鋪柳絮，古磧爛熳吹蘆花。", "流泉不下孤汀咽，斷臂老猿聲欲絕。", "鳥啄冰潭玉鏡開，風敲簷溜水晶折。", "拂戶初疑粉蝶飛，看山又訝白鷗歸。", "孫康凍死讀書圍，火井不煖溫泉微。"]'),
('c1d4b676-6d0a-42b5-9aca-d8122661b76c','琵琶','無名氏','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','粉胸繡臆誰家女，香撥星星共春語。',128,'全唐诗/poet.tang.43000.json','["粉胸繡臆誰家女，香撥星星共春語。", "七盤嶺上走鸞鈴，十二峯頭弄雲雨。", "千悲萬恨四五弦，弦中甲馬聲駢闐。", "山僧撲破瑠璃鉢，壯士擊折珊瑚鞭。", "珊瑚鞭折聲交戛，玉盤傾瀉真珠滑。", "海神驅趁夜濤回，江娥蹙踏春冰裂。", "滿坐紅妝盡淚垂，望鄉之客不勝悲。", "曲終調絕忽飛去，洞庭月落孤雲歸。"]'),
('d61c8a78-805b-4e68-bfd7-7593670a86bf','傷哉行','無名氏','唐','唐诗','tang','','[]','兔走烏飛不相見，人事依稀速如電。',96,'全唐诗/poet.tang.43000.json','["兔走烏飛不相見，人事依稀速如電。", "王母夭桃一度開，玉樓紅粉千回變。", "車馳馬走咸陽道，石家舊宅空荒草。", "秋雨無情不惜花，芙蓉一一驚顛倒。", "勸君莫謾栽荆棘，秦皇虛費驅山力。", "英風一去更無言，白骨沈埋暮山碧。"]'),
('9592f274-8188-4339-8a33-11fbf76a3c83','留贈偃師主人','無名氏','唐','唐诗','tang','','[]','孤城漏未殘，徒侶拂征鞍。',48,'全唐诗/poet.tang.43000.json','["孤城漏未殘，徒侶拂征鞍。", "洛北去愁遠，淮南歸夢闌。", "曉燈迴壁暗，晴雪卷簾寒。", "更盡主人酒，出門行路難。"]'),
('8f535f0f-23fa-473f-91e0-e6afa433b99b','長門','無名氏','唐','唐诗','tang','','[]','悵望黃金屋，恩衰似越逃。',48,'全唐诗/poet.tang.43000.json','["悵望黃金屋，恩衰似越逃。", "花生針眼刺，月送剪腸刀。", "地近歡娛遠，天低雨露高。", "時看迴輦處，淚臉濕夭桃。"]'),
('eb323057-9632-4475-85e8-fad977214766','宴李家宅','無名氏','唐','唐诗','tang','','[]','畫屏深掩瑞雲光，羅綺花飛白玉堂。',64,'全唐诗/poet.tang.43000.json','["畫屏深掩瑞雲光，羅綺花飛白玉堂。", "銀榼酒傾魚尾倒，金鑪灰滿鴨心香。", "輕搖綠水青蛾歛，亂觸紅絲皓腕狂。", "今日恩榮許同聽，不辭沈醉一千觴。"]'),
('837555e0-34d6-466e-9164-1f8603fc593b','長信宮','無名氏','唐','唐诗','tang','','[]','細草侵堦亂碧鮮，宮門深鎖綠楊天。',64,'全唐诗/poet.tang.43000.json','["細草侵堦亂碧鮮，宮門深鎖綠楊天。", "珠簾欲捲擡秋水，羅幌微開動冷煙。", "風引漏聲過枕上，月移花影到窗前。", "獨挑殘燭魂堪斷，却恨青蛾誤少年。"]'),
('84f8885e-652d-4352-83c9-bf18d12b0394','驪山感懷','無名氏','唐','唐诗','tang','','[]','武帝尋仙駕海遊，禁門高閉水空流。',64,'全唐诗/poet.tang.43000.json','["武帝尋仙駕海遊，禁門高閉水空流。", "深宮帶日年年色，翠柏凝煙夜夜愁。", "鸞鳳影沈歸萬古，歌鐘聲斷夢千秋。", "晚來惆悵無人會，雲雨能飛傍玉樓。"]'),
('a5cb9070-ac9a-4086-9b20-4a52128a4ed0','絕句','無名氏','唐','唐诗','tang','','[]','石沈遼海闊，劒別楚山長。',24,'全唐诗/poet.tang.43000.json','["石沈遼海闊，劒別楚山長。", "會合知無日，離心滿夕陽。"]'),
('3b9c5d37-8ba4-4c8e-ae62-fd37c09da846','聽唱鷓鴣','無名氏','唐','唐诗','tang','','[]','金谷歌傳第一流，鷓鴣清怨碧雲愁。',32,'全唐诗/poet.tang.43000.json','["金谷歌傳第一流，鷓鴣清怨碧雲愁。", "夜來省得曾聞處，萬里月明湘水流。"]'),
('3aa68c92-a7da-48d8-8523-f16ecbc00928','雜詩 一','無名氏','唐','唐诗','tang','','[]','勸君莫惜金縷衣，勸君須惜少年時。',32,'全唐诗/poet.tang.43000.json','["勸君莫惜金縷衣，勸君須惜少年時。", "有花堪折直須折，莫待無花空折枝。"]'),
('46fd701e-778c-40a9-b80a-e41bc65b2dd6','雜詩 二','無名氏','唐','唐诗','tang','','[]','青天無雲月如燭，露泣梨花白如玉。',32,'全唐诗/poet.tang.43000.json','["青天無雲月如燭，露泣梨花白如玉。", "子規一夜啼到明，美人獨在空房宿。"]'),
('db56fd2f-189a-492a-8e26-22b0c1a8eac0','雜詩 三','無名氏','唐','唐诗','tang','','[]','空賜羅衣不賜恩，一薰香後一銷魂。',32,'全唐诗/poet.tang.43000.json','["空賜羅衣不賜恩，一薰香後一銷魂。", "雖然舞袖何曾舞，常對春風裛淚痕。"]'),
('dde072f7-3a49-4fae-9da7-7627fce5bf71','雜詩 四','無名氏','唐','唐诗','tang','','[]','不洗殘粧凭繡牀，也同女伴繡鴛鴦。',32,'全唐诗/poet.tang.43000.json','["不洗殘粧凭繡牀，也同女伴繡鴛鴦。", "迴鍼刺到雙飛處，憶著征夫淚數行。"]'),
('54543804-e7ce-42e5-b871-a117755880bf','雜詩 五','無名氏','唐','唐诗','tang','','[]','眼想心思夢裏驚，無人知我此時情。',32,'全唐诗/poet.tang.43000.json','["眼想心思夢裏驚，無人知我此時情。", "不如池上鴛鴦鳥，雙宿雙飛過一生。"]'),
('3b618330-f54e-4dfd-a2d0-f603d076b8a3','雜詩 六','無名氏','唐','唐诗','tang','','[]','一去遼陽繫夢魂，忽傳征騎到中門。',32,'全唐诗/poet.tang.43000.json','["一去遼陽繫夢魂，忽傳征騎到中門。", "紗窗不肯施紅粉，徒遣蕭郎問淚痕。"]'),
('45d15f0f-3fdf-4dfa-8d8c-701255b5ab91','雜詩 七','無名氏','唐','唐诗','tang','','[]','鸎啼露冷酒初醒，罨畫樓西曉角鳴。',32,'全唐诗/poet.tang.43000.json','["鸎啼露冷酒初醒，罨畫樓西曉角鳴。", "翠羽帳中人夢覺，寶釵斜墜枕函聲。"]'),
('9397f505-cf4b-48d2-b26d-9de799b8cb88','雜詩 八','無名氏','唐','唐诗','tang','','[]','行人南北分征路，流水東西接御溝。',32,'全唐诗/poet.tang.43000.json','["行人南北分征路，流水東西接御溝。", "終日坡前怨離別，謾名長樂是長愁。"]'),
('952f107b-d061-43a8-a750-8c93a6400d05','雜詩 九','無名氏','唐','唐诗','tang','','[]','偏倚繡床愁不起，雙垂玉筯翠鬟低。',32,'全唐诗/poet.tang.43000.json','["偏倚繡床愁不起，雙垂玉筯翠鬟低。", "卷簾相待無消息，夜合花前日又西。"]'),
('3ae7fde3-76e8-4415-9f55-ed486a6302c6','雜詩 十','無名氏','唐','唐诗','tang','','[]','悔將淚眼向東開，特地愁從望裏來。',32,'全唐诗/poet.tang.43000.json','["悔將淚眼向東開，特地愁從望裏來。", "三十六峯猶不見，況伊如鷰這身材。"]'),
('054435f1-48f9-4765-9571-6e289cf04fc7','雜詩 十一','無名氏','唐','唐诗','tang','','[]','滿目笙歌一段空，萬般離恨總隨風。',32,'全唐诗/poet.tang.43000.json','["滿目笙歌一段空，萬般離恨總隨風。", "多情爲謝殘陽意，與展晴霞片片紅。"]'),
('03a67886-8eeb-4d0e-aeb6-5e5640b3f07e','雜詩 十二','無名氏','唐','唐诗','tang','','[]','兩心不語暗知情，燈下裁縫月下行。',32,'全唐诗/poet.tang.43000.json','["兩心不語暗知情，燈下裁縫月下行。", "行到堦前知未睡，夜深聞放剪刀聲。"]'),
('31e9a6b0-5035-4b1b-a9d3-ff1c279f53b6','雜詩 十三','無名氏','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5bd2\u98df\u8282", "\u4e03\u8a00\u7edd\u53e5", "\u601d\u4e61", "\u611f\u4f24"]','近寒食雨草萋萋，著麥苗風柳映堤。',32,'全唐诗/poet.tang.43000.json','["近寒食雨草萋萋，著麥苗風柳映堤。", "早是有家歸未得，杜鵑休向耳邊啼。"]'),
('9fdef021-d2c3-4a5a-b8ed-2c8505b61294','雜詩 十四','無名氏','唐','唐诗','tang','','["\u5931\u604b", "\u7231\u60c5"]','水紋珍簟思悠悠，千里佳期一夕休。',32,'全唐诗/poet.tang.43000.json','["水紋珍簟思悠悠，千里佳期一夕休。", "從此無心愛良夜，任他明月下西樓。"]'),
('763aac84-d842-4758-a3c3-d53a4d43b0bf','雜詩 十五','無名氏','唐','唐诗','tang','','[]','數日相隨兩不忘，郎心如妾妾如郎。',32,'全唐诗/poet.tang.43000.json','["數日相隨兩不忘，郎心如妾妾如郎。", "出門便是東西路，把取紅牋各斷腸。"]'),
('59473944-8de7-43a0-a63a-86c48132adbb','雜詩 十六','無名氏','唐','唐诗','tang','','[]','無定河邊暮角聲，赫連臺畔旅人情。',32,'全唐诗/poet.tang.43000.json','["無定河邊暮角聲，赫連臺畔旅人情。", "函關歸路千餘里，一夕秋風白髮生。"]'),
('47742bce-f9c3-4192-9c50-10fe206eee55','雜詩 十七','無名氏','唐','唐诗','tang','','[]','花落長川草色青，暮山重疊兩冥冥。',32,'全唐诗/poet.tang.43000.json','["花落長川草色青，暮山重疊兩冥冥。", "逢春便覺飄蓬苦，今日分飛一涕零。"]'),
('4e256a71-4613-4f65-bb15-f0a8e67c70d3','雜詩 十八','無名氏','唐','唐诗','tang','','[]','洛陽才子隣簫恨，湘水佳人錦瑟愁。',32,'全唐诗/poet.tang.43000.json','["洛陽才子隣簫恨，湘水佳人錦瑟愁。", "今昔兩成惆悵事，臨邛春盡暮江流。"]'),
('b4efe75c-a2ee-4ba6-9fe1-fe9472f6ebe8','雜詩 十九','無名氏','唐','唐诗','tang','','[]','浙江輕浪去悠悠，望海樓吹望海愁。',32,'全唐诗/poet.tang.43000.json','["浙江輕浪去悠悠，望海樓吹望海愁。", "莫怪鄉心隨魄斷，十年爲客在他州。"]'),
('098c0261-265f-413b-bbbf-4bef538e9f49','初過漢江','無名氏','唐','唐诗','tang','','[]','襄陽好向峴亭看，人物蕭條值歲闌。',32,'全唐诗/poet.tang.43000.json','["襄陽好向峴亭看，人物蕭條值歲闌。", "爲報習家多置酒，夜來風雪過江寒。"]'),
('e2e743c1-8f09-494f-9025-cccb68d3382f','讀庾信集','無名氏','唐','唐诗','tang','','[]','四朝十帝盡風流，建業長安兩醉游。',32,'全唐诗/poet.tang.43000.json','["四朝十帝盡風流，建業長安兩醉游。", "惟有一篇楊柳曲，江南江北爲君愁。"]'),
('d14f18b1-3b2f-493e-804e-d6c7b1f44f50','題長樂驛壁','無名氏','唐','唐诗','tang','','[]','三十驊騮一烘塵，來時不鎖杏園春。',32,'全唐诗/poet.tang.43000.json','["三十驊騮一烘塵，來時不鎖杏園春。", "楊花滿地如飛雪，應有偷游曲水人。"]'),
('1b54b321-35d0-489f-a2fe-a33a297418b5','絕句','無名氏','唐','唐诗','tang','','[]','傳聞天子訪沈淪，萬里懷書西入秦。',32,'全唐诗/poet.tang.43000.json','["傳聞天子訪沈淪，萬里懷書西入秦。", "早知不用無媒客，恨別江南楊柳春。"]'),
('a7917717-cd6e-4a0e-af0b-7b97eb085ba7','題取經詩','無名氏','唐','唐诗','tang','','[]','晉宋齊梁唐代間，高僧求法離長安。',64,'全唐诗/poet.tang.43000.json','["晉宋齊梁唐代間，高僧求法離長安。", "去人成百歸無十，後者安知前者難。", "路遠碧天唯冷結，沙河遮日力疲殫。", "後賢如未諳斯旨，往往將經容易看。"]'),
('0c2d6131-6a10-4183-8d96-a7246587ba9f','題水心寺水軒','無名氏','唐','唐诗','tang','','[]','分飛南渡春風晚，却返家林事業空。',32,'全唐诗/poet.tang.43000.json','["分飛南渡春風晚，却返家林事業空。", "無限離情似楊柳，萬條垂向楚江東。"]'),
('be4100ce-db2b-47f4-a022-3c6e9266a993','王昭君','無名氏','唐','唐诗','tang','','[]','猗蘭恩寵歇，昭陽幸御稀。',36,'全唐诗/poet.tang.43000.json','["猗蘭恩寵歇，昭陽幸御稀。", "朝辭漢闕去，夕見胡塵飛。", "寄信秦樓下，因書秋雁歸。"]'),
('78aacbc1-0ecd-4e40-b8f1-682175855943','王昭君','無名氏','唐','唐诗','tang','','[]','一回望月一回悲，望月月移人不移。',32,'全唐诗/poet.tang.43000.json','["一回望月一回悲，望月月移人不移。", "何時得見漢朝使，爲妾傳書斬畫師。"]'),
('364e745d-66d7-4904-87cc-2f7863144ef6','粉牋題詩','無名氏','唐','唐诗','tang','','[]','三月江南花滿枝，風輕簾幕燕爭飛。',32,'全唐诗/poet.tang.43000.json','["三月江南花滿枝，風輕簾幕燕爭飛。", "游人休惜夜秉燭，楊柳陰濃春欲歸。"]'),
('e275b62a-85de-4aa2-a6c1-17e1d1c171a1','詠美人騎馬','無名氏','唐','唐诗','tang','','[]','駿馬嬌仍穩，春風灞岸晴。',36,'全唐诗/poet.tang.43000.json','["駿馬嬌仍穩，春風灞岸晴。", "促來金鐙短，扶上玉人輕。", "帽束雲鬟亂，鞭籠翠袖明。"]'),
('d29d0432-2c5c-4d1f-922a-b2cf2f7f7ac3','六言詩','無名氏','唐','唐诗','tang','','[]','把酒留君聽琴，那堪歲暮離心。',42,'全唐诗/poet.tang.43000.json','["把酒留君聽琴，那堪歲暮離心。", "霜葉無風自落，秋天不雨多陰。", "人愁荒村路遠，馬怯寒溪水深。"]'),
('91c6be59-8b61-4de3-b770-dc1dce751378','胡笳曲','無名氏','唐','唐诗','tang','','[]','月明星稀霜滿野，氈車夜宿陰山下。',32,'全唐诗/poet.tang.43000.json','["月明星稀霜滿野，氈車夜宿陰山下。", "漢家自失李將軍，單于公然來牧馬。"]'),
('32fa2b8e-0571-4ef1-acc2-fde440203005','桃源行送友人','無名氏','唐','唐诗','tang','','[]','武陵川徑入幽遐，中有雞犬秦人家，家傍流水多桃花。',152,'全唐诗/poet.tang.43000.json','["武陵川徑入幽遐，中有雞犬秦人家，家傍流水多桃花。", "桃花兩邊種來久，流水一道何時有？", "垂條落蕊暗春風，夾岸芳菲至山口。", "歲歲年年能寂寥，林下青苔日爲厚。", "時有仙鳥來銜花，曾無世人此攜手。", "可憐不知若爲名，君往從之多所更。", "古驛荒橋平路盡，崩湍怪石小谿行。", "相見維舟登覽處，紅堤綠岸宛然成。", "多君此去從仙隱，令人晚節悔營營。"]'),
('9e31368c-8afb-4a94-93a2-6d0ceb248349','唐衢墓','無名氏','唐','唐诗','tang','','[]','京洛先生三尺墳，陰風慘慘土和雲。',32,'全唐诗/poet.tang.43000.json','["京洛先生三尺墳，陰風慘慘土和雲。", "從來有感君皆哭，今日無君誰哭君。"]'),
('2fc96a52-850b-46e6-b991-ca341cd0cce4','宮詞','無名氏','唐','唐诗','tang','','[]','花萼樓前春正濃，濛濛柳絮舞晴空。',32,'全唐诗/poet.tang.43000.json','["花萼樓前春正濃，濛濛柳絮舞晴空。", "金錢擲罷嬌無力，笑倚欄干屈曲中。"]'),
('daba8726-c799-41a4-a3d2-f00c17448fd0','拋毬詩','無名氏','唐','唐诗','tang','','[]','侍宴黃昏未肯休，玉階夜色月如流。',32,'全唐诗/poet.tang.43000.json','["侍宴黃昏未肯休，玉階夜色月如流。", "朝來自詫承恩最，笑倩傍人認繡毬。"]'),
('977be29a-c260-414e-82a1-3f669eafc0a1','豔歌','無名氏','唐','唐诗','tang','','[]','月裏嫦娥不畫眉，只將雲霧作羅衣。',32,'全唐诗/poet.tang.43000.json','["月裏嫦娥不畫眉，只將雲霧作羅衣。", "不知夢逐青鸞去，猶把花枝蓋面歸。"]'),
('41fa2c63-f207-4fdd-9fbf-742484a5b842','楊柳枝','無名氏','唐','唐诗','tang','','["\u957f\u6c5f"]','萬里長江一帶開，岸邊楊柳幾千栽。',32,'全唐诗/poet.tang.43000.json','["萬里長江一帶開，岸邊楊柳幾千栽。", "錦帆未落西風起，惆悵龍舟去不迴。"]'),
('49241ff1-8ea2-4878-a549-921812d5a53b','河中石刻','無名氏','唐','唐诗','tang','','[]','雨滴空堦曉，無心換夕香。',24,'全唐诗/poet.tang.43000.json','["雨滴空堦曉，無心換夕香。", "井梧花落盡，一半在銀床。"]'),
('0a355887-3e7d-4cdb-a6ac-bc2fb243d06b','古硯','無名氏','唐','唐诗','tang','','[]','癖性愛古物，終歲求不得。',48,'全唐诗/poet.tang.43000.json','["癖性愛古物，終歲求不得。", "昨朝得古硯，蘭河灘之側。", "波濤所擊觸，背面生隟隙。", "質狀朴且醜，令人作不得。"]'),
('746fb9e8-8d20-4272-ba30-1584afaa9671','絕句','無名氏','唐','唐诗','tang','','[]','釣罷孤舟繫葦梢，酒開新甕鮓開包。',32,'全唐诗/poet.tang.43000.json','["釣罷孤舟繫葦梢，酒開新甕鮓開包。", "自從江浙爲漁父，二十餘年手不扠。"]'),
('09bb4165-7761-43b4-98c0-7c79f1ad24ec','題童氏畫','無名氏','唐','唐诗','tang','','[]','林下材華雖可尚，筆端人物更清妍。',32,'全唐诗/poet.tang.43000.json','["林下材華雖可尚，筆端人物更清妍。", "如何不出深閨裏，能以丹青寫外邊。"]'),
('e824b012-fe2c-45ae-a412-97d471b18ced','失題','無名氏','唐','唐诗','tang','','[]','春朝散微雨，庭樹開芸綠。',60,'全唐诗/poet.tang.43000.json','["春朝散微雨，庭樹開芸綠。", "上有懷春鳥，間關斷復續。", "謂言□野中，定是珠城曲。", "我自牽時幸，以慚羈旅束。", "爾下鳴幽林，來此將何欲。"]'),
('658cf5bd-a4cc-44b5-8240-3507bc7a500c','姜宣彈小胡笳引歌','無名氏','唐','唐诗','tang','','[]','雷氏金徽琴，王君寶重輕千金。',190,'全唐诗/poet.tang.43000.json','["雷氏金徽琴，王君寶重輕千金。", "三峽流中將得來，明窗拂席幽匣開。", "朱弦宛轉盤鳳足，驟擊數聲風雨迴。", "哀笳慢指董家本，姜宣得之妙思忖。", "汎徽胡雁咽蕭蕭，繞指轆轤圓衮衮。", "吞恨含情乍輕激，故國關山心歷歷。", "潺湲疑是舞鸊鵜，砉騞如聞發鳴鏑。", "流宮變徵漸幽咽，別鶴欲飛猨欲絕。", "秋霜滿樹葉辭風，寒雛墜地烏啼血。", "哀弦已罷春恨長，恨長何如懷我鄉。", "我鄉安在長城窟，聞君膚奏心飄忽。", "何時窄袖短貂裘，臙脂山下彎明月。"]'),
('df559fd7-2153-42e2-ac50-e33f7bd06020','羅浮山','無名氏','唐','唐诗','tang','','[]','四百餘峯海上排，根連蓬島蔭天台。',32,'全唐诗/poet.tang.43000.json','["四百餘峯海上排，根連蓬島蔭天台。", "百靈若爲移中土，嵩華都爲一小堆。"]'),
('de5a817b-5c58-4aa7-943f-dcdea3d7f64d','湯周山','無名氏','唐','唐诗','tang','','[]','湯周二大仙，廬此得昇天。',48,'全唐诗/poet.tang.43000.json','["湯周二大仙，廬此得昇天。", "風俗因興廟，春秋不記年。", "錦雲張紫蓋，琴溜瀉鳴泉。", "丹竈猶存鼎，仙花發故園。"]'),
('302144a7-ed89-4073-80e0-dbb916c83a0a','永州舜廟詩','無名氏','唐','唐诗','tang','','[]','游湘有餘怨，豈是聖人心。',60,'全唐诗/poet.tang.43000.json','["游湘有餘怨，豈是聖人心。", "行路猿啼古，祠宮夢草深。", "素風傳舊俗，異跡閉荒林。", "巡狩去不返，煙雲愁至今。", "九嶷天一半，山盡海沈沈。"]'),
('d3214588-84a1-4046-b426-a233efe2ddf8','絕句','無名氏','唐','唐诗','tang','','[]','綠楊陰轉畫橋斜，舟有笙歌岸有花。',32,'全唐诗/poet.tang.43000.json','["綠楊陰轉畫橋斜，舟有笙歌岸有花。", "盡日會稽山色裏，蓬萊清淺水仙家。"]'),
('cebd753a-47a0-480f-b9d4-5ddb39723435','三學山盤陀石上刻詩','無名氏','唐','唐诗','tang','','[]','拔地山巒秀，排空殿閣斜。',48,'全唐诗/poet.tang.43000.json','["拔地山巒秀，排空殿閣斜。", "雲供數州雨，樹獻九天花。", "夜月摩峰頂，秋鐘徹海涯。", "長松拂星漢，一一是仙槎。"]'),
('bb12da5f-2601-4a4a-9ef3-5548d37a5b71','合水縣玉泉石崖刻','無名氏','唐','唐诗','tang','','[]','山脉逗飛泉，泓澄傍巖石。',48,'全唐诗/poet.tang.43000.json','["山脉逗飛泉，泓澄傍巖石。", "亂垂寒玉篠，碎灑珍珠滴。", "澄波涵萬象，明鏡瀉天色。", "有時乘月來，賞詠還自適。"]'),
('21797f1d-5ae3-4c66-98cc-99680a9d88a1','紀遊東觀山','無名氏','唐','唐诗','tang','','[]','瑰奇恣搜討，貝闕青瑤房。',146,'全唐诗/poet.tang.43000.json','["瑰奇恣搜討，貝闕青瑤房。", "才隘疑永巷，俄敞如華堂。", "玉梁窈浮溪，瓊戶正當窗。", "仙佛肖彷彿，鐘鼓鍧擊撞。", "贔贔左顧龜，狺狺欲吠[尨]。", "丹竈儼亡恙，芝田靄生香。", "搏噬千怪聚，絢爛五色光。", "更無一塵涴，但覺六月涼。", "玲瓏穿屢折，詰曲通三湘。", "神鬼若剜刻，乾坤真混茫。", "入如深夜暗，出喜皦日光。", "隔世驚瞬息，異境難揣量。"]'),
('b337d13d-301b-42a5-bd39-3888a294def3','題焚經臺','無名氏','唐','唐诗','tang','','[]','門徑蕭蕭長綠苔，一回登此一徘徊。',64,'全唐诗/poet.tang.43000.json','["門徑蕭蕭長綠苔，一回登此一徘徊。", "青牛謾說函關去，白馬親從印土來。", "確實是非憑烈焰，要分真僞築高臺。", "春風也解嫌狼籍，吹盡當年道教灰。"]'),
('7cb4f06f-75b2-4d42-8ad4-e3cad515de5f','日暮山河清','無名氏','唐','唐诗','tang','','[]','天高爽氣晶，馳景忽西傾。',72,'全唐诗/poet.tang.43000.json','["天高爽氣晶，馳景忽西傾。", "山列千重靜，河流一帶明。", "想同金鏡澈，寧讓玉壺清。", "纖翳無由出，浮埃不復生。", "榮紆分漢苑，表裏見秦城。", "逸興終難繫，抽毫仰此情。"]'),
('148ea71b-3f6a-4f6b-a0a8-ea84620db56f','秋日懸清光','無名氏','唐','唐诗','tang','','["\u4e50\u89c2", "\u79cb\u5929", "\u5199\u666f", "\u79ef\u6781"]','寥廓涼天靜，晶明白日秋。',72,'全唐诗/poet.tang.43000.json','["寥廓涼天靜，晶明白日秋。", "圓光含萬象，碎影人閑流。", "迥與青冥合，遙同江甸浮。", "晝陰殊衆木，斜影下危樓。", "宋玉登高怨，張衡望遠愁。", "餘輝如可託，雲路豈悠悠。"]'),
('17052128-5f54-48c9-b74b-24a16433faf2','落日山照曜','無名氏','唐','唐诗','tang','','[]','裴回空山下，晼晚殘陽落。',72,'全唐诗/poet.tang.43000.json','["裴回空山下，晼晚殘陽落。", "圓影過峰巒，半規入林薄。", "餘光澈羣岫，亂彩分重壑。", "石鏡共澄明，巖光同照灼。", "棲禽去杳杳，夕煙生漠漠。", "此境誰復知，獨懷謝康樂。"]'),
('3f72fcb6-286c-4b53-93e1-37c95d4b801d','月映清淮流','無名氏','唐','唐诗','tang','','[]','淮月秋偏靜，含虛夜轉明。',72,'全唐诗/poet.tang.43000.json','["淮月秋偏靜，含虛夜轉明。", "桂花窺鏡發，蟾影映波生。", "澹灩輪初上，裴回魄正盈。", "遙塘分草樹，近浦寫山城。", "桐柏流光逐，蠙珠濯景清。", "孤舟方利涉，更喜照前程。"]'),
('28d42f62-a639-4631-8629-03706b1937c8','壽星見','無名氏','唐','唐诗','tang','','[]','玄象今何應，時和政亦平。',72,'全唐诗/poet.tang.43000.json','["玄象今何應，時和政亦平。", "祥爲一人壽，色映九霄明。", "皎潔垂銀漢，光芒近斗城。", "合規同月滿，表瑞得天清。", "甘露盈條降，祥煙向日生。", "無如此嘉祉，率土荷秋成。"]'),
('1a98f776-9a84-4f37-8262-fb78e4ef0a48','華山慶雲見','無名氏','唐','唐诗','tang','','[]','聖主祠名岳，高風發慶雲。',72,'全唐诗/poet.tang.43000.json','["聖主祠名岳，高風發慶雲。", "金柯初繚繞，玉葉漸氛氳。", "氣色含珠日，光明吐翠雰。", "依稀來鶴態，髣髴列仙羣。", "萬樹流光影，千潭寫錦文。", "蒼生忻有望，祥瑞在吾君。"]'),
('a8580f60-6a8c-4cfa-8ab4-46e6bf57e17e','清風戒寒','無名氏','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','蕭颯清風至，悠然發思端。',72,'全唐诗/poet.tang.43000.json','["蕭颯清風至，悠然發思端。", "入林翻別葉，繞樹敗紅蘭。", "曉拂輕霜度，宵分遠籟攢。", "稍依簾隙靜，徧覺坐隅寒。", "乍逐驚蓬振，偏催急漏殘。", "遙知洞庭水，此夕起波瀾。"]'),
('eb9a7402-69f3-4ddb-b1da-e410e328d08e','空水共澄鮮','無名氏','唐','唐诗','tang','','[]','悠然四望通，渺渺水無窮。',72,'全唐诗/poet.tang.43000.json','["悠然四望通，渺渺水無窮。", "海鶴飛天際，煙林出鏡中。", "雲消澄徧碧，霞起澹微紅。", "落日浮光滿，遙山翠色同。", "樵聲喧竹嶼，櫂唱入蓮藂。", "遠客舟中興，煩襟暫一空。"]'),
('e9909e0d-fea0-4dd5-97b5-22a3b88d8b81','寒流聚細文','無名氏','唐','唐诗','tang','','[]','曉野方閑眺，橫溪賞亂流。',72,'全唐诗/poet.tang.43000.json','["曉野方閑眺，橫溪賞亂流。", "寒文趨浦急，圓折逐煙浮。", "不謂飄疎雨，非關浴遠鷗。", "觀魚鱗共細，間石影疑稠。", "獵獵風泠夕，潺潺瀨響秋。", "仙槎如共泛，天漢適淹留。"]'),
('3f93ea94-02e3-4c07-bf9f-2fd98ca4d9e3','長安早春','無名氏','唐','唐诗','tang','','[]','杳靄三春色，先從帝里芳。',72,'全唐诗/poet.tang.43000.json','["杳靄三春色，先從帝里芳。", "折楊猶恨短，測景已忻長。", "鶯和紅樓樂，花連紫禁香。", "躍魚驚太液，佳氣接溫湯。", "風送飛珂響，塵蒙翠輦光。", "熙熙晴煦遠，徒欲奉堯觴。"]'),
('2148c3cd-4896-4713-8b27-57888307ec05','嘉和合頴','無名氏','唐','唐诗','tang','','[]','天祚皇王德，神呈瑞穀嘉。',72,'全唐诗/poet.tang.43000.json','["天祚皇王德，神呈瑞穀嘉。", "感時苗特秀，證道葉方華。", "氣轉騰佳色，雲披映早霞。", "薰風浮合頴，湛露淨祥花。", "六穗垂兼倒，孤莖嫋復斜。", "影同唐叔獻，稱慶比周家。"]'),
('e91d71f2-ecc1-4784-ae49-768d25323fc4','膏澤多豐年','無名氏','唐','唐诗','tang','','[]','帝德方多澤，莓莓井徑同。',72,'全唐诗/poet.tang.43000.json','["帝德方多澤，莓莓井徑同。", "八方甘雨布，四遠報年豐。", "厫慶千廂在，山流萬壑通。", "候時勤稼穡，擊壤樂農功。", "畎畝人無惰，田廬歲不空。", "何須憂伏臘，千載賀堯風。"]'),
('bd558c28-8f0e-42f7-b9c8-bce4f32ec8e1','玉壺冰','無名氏','唐','唐诗','tang','','[]','玄律陰風勁，堅冰在玉壺。',72,'全唐诗/poet.tang.43000.json','["玄律陰風勁，堅冰在玉壺。", "暗中花更出，曉後色全無。", "涸沍誰能伴，淒清詎可渝。", "任圓空似璧，照物不成珠。", "素質情方契，孤明道豈殊。", "幽人若相比，還得詠生芻。"]'),
('89d829fd-4c57-4567-8945-c0404741bc20','望禁苑祥光','無名氏','唐','唐诗','tang','','[]','佳氣生天苑，蔥蘢幾效祥。',72,'全唐诗/poet.tang.43000.json','["佳氣生天苑，蔥蘢幾效祥。", "樹遙三殿際，日映九城傍。", "山霧寧同色，卿雲未可彰。", "眺汾疑鼎氣，臨渭想榮光。", "當並舂陵發，應開聖曆長。", "微臣時一望，短羽欲飛翔。"]'),
('a13de6ae-a369-4b06-b7b0-d3a7249217b6','晨光動翠華','無名氏','唐','唐诗','tang','','[]','早朝開紫殿，佳氣逐清晨。',72,'全唐诗/poet.tang.43000.json','["早朝開紫殿，佳氣逐清晨。", "北闕華旌在，東方曙景新。", "影連香霧合，光媚慶雲頻。", "鳥羽飄初定，龍文照轉真。", "直疑冠佩入，長愛冕旒親。", "搖動祥雲裏，朝朝映侍臣。"]'),
('7d4dcc10-0724-4036-918a-87e95751042b','觀南郊回仗','無名氏','唐','唐诗','tang','','[]','傳警千門寂，南郊綵仗迴。',72,'全唐诗/poet.tang.43000.json','["傳警千門寂，南郊綵仗迴。", "但驚龍再見，誰識日雙開。", "德澤施雲雨，恩光變燼灰。", "閱兵貔武振，聽樂鳳凰來。", "候刻移宸輦，尊時集觀臺。", "多慙遠臣賤，不得禮容陪。"]'),
('fa5786ec-bf1b-49c3-8ac1-35babbd3a710','謁見日將至雙闕','無名氏','唐','唐诗','tang','','[]','曉色臨雙闕，微臣禮位陪。',72,'全唐诗/poet.tang.43000.json','["曉色臨雙闕，微臣禮位陪。", "遠驚龍鳳覩，誰識冕旒開。", "藹藹千年盛，顒顒萬國來。", "天文標日月，時令布雲雷。", "迥出黃金殿，全分白玉臺。", "雕蟲意何取，瞻戀不知迴。"]'),
('804c508c-5ffe-4513-a6b0-870404b04f52','尚書郎上直聞春漏','無名氏','唐','唐诗','tang','','[]','地即尚書省，人惟鴛鷺行。',72,'全唐诗/poet.tang.43000.json','["地即尚書省，人惟鴛鷺行。", "審時傳玉漏，直夜遞星郎。", "歷歷聞仙暑，泠泠出建章。", "自空來斷續，隨月散淒鏘。", "物靜知聲遠，寒輕覺夜長。", "聽餘殘月落，曙色滿東方。"]'),
('b366a21d-8b6c-46b6-becf-dc903861948b','華清宮望幸','無名氏','唐','唐诗','tang','','[]','驪岫接新豐，岧嶤駕碧空。',72,'全唐诗/poet.tang.43000.json','["驪岫接新豐，岧嶤駕碧空。", "鑿山開祕殿，隱霧蔽仙宮。", "絳闕猶棲鳳，雕梁尚帶虹。", "溫泉曾浴日，華館舊迎風。", "肅穆瞻雲輦，深沈閉綺櫳。", "東郊望幸處，瑞氣靄濛濛。"]'),
('ae730d3a-61cd-43d2-9b6d-cc9302dda7fb','御題國子監','無名氏','唐','唐诗','tang','','[]','宸翰符玄造，榮題國子門。',72,'全唐诗/poet.tang.43000.json','["宸翰符玄造，榮題國子門。", "筆鋒迴日月，字勢動乾坤。", "簷下雲光繞，梁間鵲影翻。", "張英聖莫擬，索靖妙難言。", "爲著盤龍迹，能彰舞鳳蹲。", "更隨垂露像，常以沐皇恩。"]'),
('b3d37a10-351a-4863-afe1-91dbd5a5eb4f','郊壇聽雅樂','無名氏','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','泰壇恭祀事，彩仗下寒坰。',72,'全唐诗/poet.tang.43000.json','["泰壇恭祀事，彩仗下寒坰。", "展禮陳嘉樂，齋心動衆靈。", "韻長飄更遠，曲度靜宜聽。", "泛響何清越，隨風散杳冥。", "徹懸和氣聚，旋退曉山青。", "本自鈞天降，還疑列洞庭。"]'),
('e5a14fed-7272-4132-abbc-6f9ca1470477','冊上公太常奏雅樂','無名氏','唐','唐诗','tang','','[]','司樂陳金石，逶迤引上公。',72,'全唐诗/poet.tang.43000.json','["司樂陳金石，逶迤引上公。", "奏音人語絕，清韻佩聲通。", "應律煙雲改，來儀鳥獸同。", "得賢因舉頌，修禮便觀風。", "聖壽三稱內，天歡九奏中。", "寂寥高曲盡，猶自滿宸聰。"]'),
('a05802fa-082b-48af-a717-8f12efc75832','聽霜鐘','無名氏','唐','唐诗','tang','','[]','渺渺飛霜夜，寥寥遠岫鐘。',72,'全唐诗/poet.tang.43000.json','["渺渺飛霜夜，寥寥遠岫鐘。", "出雲疑斷續，入戶乍舂容。", "度枕頻驚夢，隨風幾韻松。", "悠揚來不已，杳靄去何從。", "髣髴煙嵐隔，依俙巖嶠重。", "此時聊一聽，餘響繞千峰。"]'),
('994d44c0-6514-4394-976d-a8503ed82085','聽霜鐘','無名氏','唐','唐诗','tang','','[]','寥亮來豐嶺，分明辨古鐘。',72,'全唐诗/poet.tang.43000.json','["寥亮來豐嶺，分明辨古鐘。", "應霜如自擊，中節每相從。", "靜聽非閑扣，潛應蘊聖蹤。", "風間時斷續，雲外更舂容。", "虛警和清籟，雄鳴隔亂峰。", "因之論知己，感激更難逢。"]'),
('80ba8cc0-caca-4935-b8dc-c7081ae6fbff','笙磬同音','無名氏','唐','唐诗','tang','','[]','笙磬聞何處，淒鏘宛在東。',72,'全唐诗/poet.tang.43000.json','["笙磬聞何處，淒鏘宛在東。", "激揚音自徹，高下曲宜同。", "歷歷俱盈耳，泠泠遞散空。", "獸因繁奏舞，人感至和通。", "詎間洪纖韻，能齊搏拊功。", "四懸今盡美，一聽辨移風。"]'),
('17733bea-3744-4068-a752-d862d94df3cf','玉巵無當','無名氏','唐','唐诗','tang','','[]','共惜連城寶，翻爲無當巵。',72,'全唐诗/poet.tang.43000.json','["共惜連城寶，翻爲無當巵。", "詎慙君子貴，深訝拙工隳。", "泛蟻功全少，如虹色不移。", "可憐珍礫石，何計辨糟醨。", "江海誠難滿，盤筵莫妄施。", "縱乖斟酌意，猶得奉光儀。"]'),
('02dd0c30-49c0-43ee-a4a4-af61216a9f61','府試古鏡','無名氏','唐','唐诗','tang','','[]','舊是秦時鏡，今來古匣中。',72,'全唐诗/poet.tang.43000.json','["舊是秦時鏡，今來古匣中。", "龍盤初挂月，鳳舞欲生風。", "石黛曾留殿，朱光適在宮。", "應祥知道泰，監物覺神通。", "肝膽誠難隱，妍媸信易窮。", "幸居君子室，長願免塵蒙。"]'),
('c225bfc0-186c-425a-bce4-c21edb0cfb5c','焚裘','無名氏','唐','唐诗','tang','','[]','今主臨前殿，懲奢爇異裘。',72,'全唐诗/poet.tang.43000.json','["今主臨前殿，懲奢爇異裘。", "忽看陽焰發，如覩吉光流。", "麗彩辭宸扆，餘香在御樓。", "火隨餘燼滅，氣逐遠煙浮。", "素朴回風變，凋華逐志休。", "永垂恭儉德，千古揖皇猷。"]'),
('102bb61e-3d81-4f54-b884-496c116761af','送薛大夫和蕃','無名氏','唐','唐诗','tang','','[]','戎王歸漢命，魏絳諭皇恩。',72,'全唐诗/poet.tang.43000.json','["戎王歸漢命，魏絳諭皇恩。", "旌斾辭雙闕，風沙上五原。", "往途遵塞道，出祖耀都門。", "策令天文盛，宣威使者尊。", "澄波望四海，入貢佇諸蕃。", "秋杪迎迴騎，無勞枉夢魂。"]'),
('f5727a45-db62-47b7-9c3b-ad1059a4eb7c','觀劒南獻捷','無名氏','唐','唐诗','tang','','[]','遐圻新破虜，名將舊登壇。',72,'全唐诗/poet.tang.43000.json','["遐圻新破虜，名將舊登壇。", "戎馘西南至，氈裘長幼觀。", "邊疆氛已息，矛戟血猶殘。", "紫陌歡聲動，丹墀喜氣盤。", "唐虞方德易，衛霍比功難。", "共覩俘囚入，賡歌萬國安。"]'),
('0083e1ea-b686-46b1-9822-402df77cc81c','雲母屏風隔坐','無名氏','唐','唐诗','tang','','[]','彩障成雲母，丹墀隔上公。',72,'全唐诗/poet.tang.43000.json','["彩障成雲母，丹墀隔上公。", "才彰二紀盛，榮播一朝同。", "近玉初齊白，臨花乍散紅。", "凝姿分縹緲，轉佩辨𤫩瓏。", "意愜恩偏厚，名新寵更崇。", "誰知歷千古，猶自仰清風。"]'),
('ae7fb822-b8b3-4444-a032-d711433237c3','白受采','無名氏','唐','唐诗','tang','','[]','皛皛金方色，遷移妙不窮。',72,'全唐诗/poet.tang.43000.json','["皛皛金方色，遷移妙不窮。", "輕衣塵跡化，淨壁繢文通。", "沙變藍溪漬，冰渝墨沼空。", "似甘言受和，由禮學資忠。", "皎潔形無定，玄黃用莫同。", "素心如可教，願染古人風。"]'),
('d3e0e39c-f02a-4f15-8b2e-bf382e8c4bac','人不易知','無名氏','唐','唐诗','tang','','[]','權衡諒匪易，愚智信難移。',96,'全唐诗/poet.tang.43000.json','["權衡諒匪易，愚智信難移。", "九德皆殊進，三端豈易施。", "同稱崑岫寶，共握桂林枝。", "鄭鼠今奚別，齊竽或濫吹。", "瑤臺有光鑑，屢照不應疲。", "片善當無掩，先鳴貴在斯。", "龍門峻且極，驥足庶來馳。", "太息李元禮，期君幸一知。"]'),
('d76152bd-203c-404f-895a-3ef6220baf72','晦日同志昆明池汎舟','無名氏','唐','唐诗','tang','','[]','靈沼疑河漢，蕭條見斗牛。',72,'全唐诗/poet.tang.43000.json','["靈沼疑河漢，蕭條見斗牛。", "煙生知岸近，水淨覺天秋。", "落月低前樹，清輝滿去舟。", "興因孤嶼起，心爲白蘋留。", "曉吹兼漁笛，閑雲伴客愁。", "龍津如可上，長嘯且乘流。"]'),
('d19ebe2a-3d00-491b-9e8d-807ea30aa9af','禮闈階前春草生','無名氏','唐','唐诗','tang','','[]','河畔雖同色，南宮淑景先。',72,'全唐诗/poet.tang.43000.json','["河畔雖同色，南宮淑景先。", "微開曳履處，常對講經前。", "得地風塵隔，依林雨露偏。", "已逢霜候改，初寄日華妍。", "影與叢蘭雜，榮將衆卉連。", "哲人如不薙，生意在芳年。"]'),
('e76d5e57-ed32-492f-955b-9d9f095759db','秋風生桂枝','無名氏','唐','唐诗','tang','','[]','寒桂秋風動，蕭蕭自一枝。',72,'全唐诗/poet.tang.43000.json','["寒桂秋風動，蕭蕭自一枝。", "方將擊林變，不假舞松移。", "散翠幽花落，搖青密葉離。", "哀猨驚助褭，花露滴爭垂。", "遺韻連波聚，流音萬木隨。", "常聞小山裏，逋客最先知。"]'),
('e5c9128d-f819-4a62-929f-60e8daac6d26','幽人折芳桂','無名氏','唐','唐诗','tang','','[]','厚地生芳桂，遙林聳榦長。',72,'全唐诗/poet.tang.43000.json','["厚地生芳桂，遙林聳榦長。", "葉開風裏色，花吐月中光。", "曙鳥啼餘翠，幽人愛早芳。", "動時垂露滴，攀處拂衣香。", "古調聲猶苦，孤高力自強。", "一枝終是折，榮耀在東堂。"]'),
('50614ad6-187f-4b43-bf6b-321bcb48bb2f','霜菊','無名氏','唐','唐诗','tang','','[]','秋盡北風去，律移寒氣肅。',72,'全唐诗/poet.tang.43000.json','["秋盡北風去，律移寒氣肅。", "淅瀝降繁霜，離披委殘菊。", "華滋尚照灼，幽氣含紛郁。", "的的冒空園，萋萋被幽谷。", "騷人有遺詠，陶令曾盈掬。", "儻使懷袖中，猶堪襲餘馥。"]'),
('a665d08f-4042-43ff-9349-4862435449c1','金谷園花發懷古','無名氏','唐','唐诗','tang','','[]','春風生梓澤，遲景映花林。',72,'全唐诗/poet.tang.43000.json','["春風生梓澤，遲景映花林。", "欲問當時事，因傷此日心。", "繁華人已歿，桃李意何深。", "澗咽歌聲在，雲歸蓋影沈。", "地形同萬古，笑價失千金。", "遺跡應無限，芳菲不可尋。"]'),
('90e592bb-5f0c-457a-a957-05a45de95677','驪龍','無名氏','唐','唐诗','tang','','[]','有美爲鱗族，潛蟠得所從。',72,'全唐诗/poet.tang.43000.json','["有美爲鱗族，潛蟠得所從。", "標奇初韞寶，表智即稱龍。", "大壑長千里，深泉固九重。", "奮髯雲乍起，矯首浪還衝。", "荀氏傳高譽，莊生冀絕蹤。", "仍知流淚在，何幸此相逢。"]'),
('22b71614-1f07-4576-a51e-5afc6ab2cd5d','鶴鳴九臯','無名氏','唐','唐诗','tang','','[]','胎化呈仙質，長鳴在九臯。',72,'全唐诗/poet.tang.43000.json','["胎化呈仙質，長鳴在九臯。", "排空散清唳，映日委霜毛。", "萬里思寥廓，千山望鬱陶。", "香凝光不見，風積韻彌高。", "鳳侶攀何及，雞羣思忽勞。", "昇天如有應，飛舞出蓬蒿。"]'),
('a1e218e3-02e1-409c-a94f-b274f233d608','霜隼下晴臯','無名氏','唐','唐诗','tang','','[]','九臯霜氣勁，翔隼下初晴。',72,'全唐诗/poet.tang.43000.json','["九臯霜氣勁，翔隼下初晴。", "風動閑雲卷，星馳白草平。", "稜稜方厲疾，肅肅自縱橫。", "掠地秋毫迥，投身逸翮輕。", "高墉全失影，逐雀作飛聲。", "薄暮寒郊外，悠悠萬里情。"]'),
('df60674c-73ca-432a-a47a-d566f928513d','河鯉登龍門','無名氏','唐','唐诗','tang','','[]','年久還求變，今來有所從。',72,'全唐诗/poet.tang.43000.json','["年久還求變，今來有所從。", "得名當是鯉，無點可成龍。", "備歷艱難徧，因期造化容。", "泥沙寧不阻，釣餌莫相逢。", "擊浪因成勢，纖鱗莫繼蹤。", "若令搖尾去，雨露此時濃。"]'),
('cee0f10c-161a-41cd-86b3-2d42886fdaf3','改九子山爲九華山聯句','李白','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','妙有分二氣，靈山開九華。',48,'全唐诗/poet.tang.43000.json','["妙有分二氣，靈山開九華。", "層標遏遲日，半壁明朝霞。", "積雪曜陰壑，飛流歕陽崖。", "青瑩玉樹色，縹緲羽人家。"]'),
('415052da-08ac-43f0-bb9b-9ce383e55bf0','夏夜李尚書筵送宇文石首赴縣聯句','杜甫','唐','唐诗','tang','','[]','愛客尚書貴，之官宅相賢。',96,'全唐诗/poet.tang.43000.json','["愛客尚書貴，之官宅相賢。", "酒香傾坐側，帆影駐江邊。", "翟表郎官瑞，鳧看令宰仙。", "雨稀雲葉斷，夜久燭花偏。", "數語敧紗帽，高文擲彩箋。", "興饒行處樂，離惜醉中眠。", "單父長多暇，河陽實少年。", "客居逢自出，爲別幾悽然。"]'),
('9e491ab0-edcf-41b9-8c91-fa4a9e61a96c','登峴山觀李左相石尊聯句','顏真卿','唐','唐诗','tang','','[]','李公登飲處，因石爲窪尊。',288,'全唐诗/poet.tang.43000.json','["李公登飲處，因石爲窪尊。", "人事歲年改，峴山今古存。", "榛蕪掩前跡，苔蘚餘舊痕。", "叔子尚遺德，山公此迴軒。", "維舟陪高興，感昔情彌敦。", "藹藹賢哲事，依依離別言。", "嶇嶔橫道周，迢遰連山根。", "餘烈曖林野，衆芳揖蘭蓀。", "德暉映巖足，勝賞延高原。", "遠水明匹練，因晴見吳門。", "陪遊追盛美，揆德欣討論。", "器有成形用，功資造化元。", "流霞方泔淡，別鶴遽翩飜。", "舊規傾逸賞，新興麗初暾。", "醉後接㒿倒，歸時騶騎喧。", "遲迴向遺跡，離別益傷魂。", "覽事古興屬，送人歸思繁。", "懷賢久徂謝，贈遠空攀援。", "八座欽懿躅，高名播乾坤。", "松深引閑步，葛弱供險捫。", "花氣酒中馥，雲華衣上屯。", "森沈列湖樹，牢落望郊園。", "白日半巖岫，清風滿丘樊。", "旌麾間翠幄，簫鼓來朱轓。"]'),
('ca540fa1-8bdf-4128-b51a-355f70e94afd','水堂送諸文士戲贈潘丞聯句','顏真卿','唐','唐诗','tang','','[]','居人未可散，上客須留著。',168,'全唐诗/poet.tang.43000.json','["居人未可散，上客須留著。", "莫唱阿嚲迴，應云夜半樂。", "詩教刻燭賦，酒任連盤酌。", "從他白眼看，終戀青山郭。", "林栖非姓許，寺住那名約。", "會異永和年，才同建安作。", "何煩問更漏，但遣催弦索。", "共說長句能，皆言早歸惡。", "那知殊出處，還得同笑謔。", "雅韻雖暫歡，禪心肯拋却。", "一宿同高會，幾人歸下若。", "簾開北陸風，燭焯南枝鵲。", "文場苦叨竊，釣渚甘漂泊。", "弱質幸見容，菲才誠重諾。"]'),
('212bfdd6-0a39-4ebc-b923-6053c4288e21','與耿湋水亭詠風聯句','顏真卿','唐','唐诗','tang','','[]','清風何處起，拂檻復縈洲。',144,'全唐诗/poet.tang.43000.json','["清風何處起，拂檻復縈洲。", "回入飄華幕，輕來疊晚流。", "桃竹今已展，羽翣且從收。", "經竹吹彌切，過松韻更幽。", "直散青蘋末，偏隨白浪頭。", "山山催雨過，浦浦發行舟。", "動樹蟬爭噪，開簾客罷愁。", "度弦方解慍，臨水已迎秋。", "涼爲開襟至，清因作頌留。", "周回隨遠夢，騷屑滿離憂。", "豈獨銷繁暑，偏能入迥樓。", "王風今若此，誰不荷明休。"]'),
('d9019b3c-87a2-4698-ae6a-4de907ee9cc4','又溪館聽蟬聯句','顏真卿','唐','唐诗','tang','','[]','高樹多涼吹，疎蟬足斷聲。',120,'全唐诗/poet.tang.43000.json','["高樹多涼吹，疎蟬足斷聲。", "已催居客感，更使別人驚。", "晚夏猶知急，新秋別有情。", "危湍和不似，細管學難成。", "當斅附金重，無貪曜火明。", "青松四面落，白髮一重生。", "向夕音彌厲，迎風翼更輕。", "單嘶出迥樹，餘響思空城。", "嘒唳松間坐，蕭寥竹裏行。", "如何長飲露，高潔未能名。"]'),
('bd9065e4-e444-45f2-8126-4d5c6b8ba4f1','送耿湋拾遺聯句','顏真卿','唐','唐诗','tang','','[]','堯舜逢明主，嚴徐得侍臣。',96,'全唐诗/poet.tang.43000.json','["堯舜逢明主，嚴徐得侍臣。", "分行接三事，高興柏梁新。", "楚國千山道，秦城萬里人。", "鏡中看齒髮，河上有煙塵。", "望闕飛青翰，朝天憶紫宸。", "喜來歡宴洽，愁去詠歌頻。", "顧盼情非一，睽攜處亦頻。", "吳興賢太守，臨水最殷勤。"]'),
('a565fcb7-9e68-4ded-b859-c1a5a0a86d30','五言月夜啜茶聯句','顏真卿','唐','唐诗','tang','','[]','泛花邀坐客，代飲引情言。',84,'全唐诗/poet.tang.43000.json','["泛花邀坐客，代飲引情言。", "醒酒宜華席，留僧想獨園。", "不須攀月桂，何假樹庭萱。", "御史秋風勁，尚書北斗尊。", "流華淨肌骨，疏瀹滌心原。", "不似春醪醉，何辭綠菽繁。", "素瓷傳靜夜，芳氣滿閑軒。"]'),
('fb18d8b0-a09a-4511-8bd2-0415c73204ee','五言夜宴詠燈聯句','顏真卿','唐','唐诗','tang','','[]','桂酒牽詩興，蘭釭照客情。',60,'全唐诗/poet.tang.43000.json','["桂酒牽詩興，蘭釭照客情。", "詎慙珠乘朗，不讓月輪明。", "破暗光初白，浮雲色轉清。", "帶花疑在樹，比燎欲分庭。", "顧己慙微照，開簾識近汀。"]'),
('38f5ca4e-d53f-4c40-872d-a07eaf8d5c47','三言喜皇甫侍御見過南樓玩月','顏真卿','唐','唐诗','tang','','[]','喜嘉客，闢前軒。',88,'全唐诗/poet.tang.43000.json','["喜嘉客，闢前軒。", "天月淨，水雲昏。", "雁聲苦，蟾影寒。", "聞裛浥，滴檀欒。", "歡宴處，江湖間。", "卷翠幕，吟嘉句。", "恨清光，留不住。", "高駕動，清角催。", "惜歸去，重裴回。", "露欲晞，客將醉。", "猶宛轉，照深意。"]'),
('100f1b25-d4bc-4d80-9f55-040330a1fd83','七言重聯句','顏真卿','唐','唐诗','tang','','[]','頃持憲簡推高步，獨占詩流橫素波。',160,'全唐诗/poet.tang.43000.json','["頃持憲簡推高步，獨占詩流橫素波。", "不是中情深惠好，誰能千里遠經過。", "詩書宛似陪康樂，少長還同宴永和。", "夜酌此時看碾玉，晨趨幾日重鳴珂。", "萬井更深空寂寞，千方霧起隱嵯峨。", "熒熒遠火分漁浦，歷歷寒枝露鳥窠。", "漢朝舊學君公隱，魯國今從弟子科。", "只自傾心慙煦濡，何曾將口恨蹉跎。", "獨賞謝吟山照耀，共知殷歎樹婆娑。", "華轂苦嫌雲路隔，衲衣長向雪峰何。"]'),
('3279f99d-f0ab-4c4f-9155-eb2bf4a81145','五言送李侍御聯句','顏真卿','唐','唐诗','tang','','[]','吾友駐行輪，遲遲惜上春。',48,'全唐诗/poet.tang.43000.json','["吾友駐行輪，遲遲惜上春。", "東西出餞路，惆悵獨歸人。", "歡會期他日，驅馳恨此身。", "須知貢公望，從此願相因。"]'),
('36e556d5-dcc6-4cd0-a80c-1c71b044a699','五言翫初月重遊聯句','顏真卿','唐','唐诗','tang','','[]','春谿與岸平，初月出谿明。',48,'全唐诗/poet.tang.43000.json','["春谿與岸平，初月出谿明。", "璧彩寒仍潔，金波夜轉清。", "孤光遠近滿，練色往來輕。", "望望隨蘭櫂，依依出柳城。"]'),
('2e432373-9952-4686-8ab2-4cabc8c1b3a2','五言重送橫飛聯句','顏真卿','唐','唐诗','tang','','[]','春田草未齊，春水滿長溪。',36,'全唐诗/poet.tang.43000.json','["春田草未齊，春水滿長溪。", "出餞風初暖，攀光日漸西。", "歸期江上遠，別思月中迷。"]'),
('2bdf81be-dfc6-4b8b-b88a-87664c4704e8','五言夜集聯句','顏真卿','唐','唐诗','tang','','[]','寒花護月色，墜葉占風音。',24,'全唐诗/poet.tang.43000.json','["寒花護月色，墜葉占風音。", "茲夕無塵慮，高雲共片心。"]'),
('5c1a6976-1e2e-4570-bd5e-299cdf32dbf0','三言擬五雜組聯句','顏真卿','唐','唐诗','tang','','[]','五雜組，盤上葅。',144,'全唐诗/poet.tang.43000.json','["五雜組，盤上葅。", "往復還，頭嬾梳。", "不得已，罾裏魚。", "五雜組，郊外蕪。", "往復還，櫪上駒。", "不得已，谷中愚。", "五雜組，繡與錦。", "往復還，興又寢。", "不得已，病伏枕。", "五雜組，酒與肉。", "往復還，東籬菊。", "不得已，醉便宿。", "五雜組，闤闠間。", "往復還，門上關。", "不得已，鬢毛斑。", "五雜組，繡紋線。", "往復還，春來燕。", "不得已，入征戰。"]'),
('a847a272-c46f-4b77-b88b-e5deda4210cf','三言重擬五雜組聯句','顏真卿','唐','唐诗','tang','','[]','五雜組，四豪客。',96,'全唐诗/poet.tang.43000.json','["五雜組，四豪客。", "往復還，阡與陌。", "不得已，長沙謫。", "五雜組，五辛盤。", "往復還，馬上鞍。", "不得已，左降官。", "五雜組，甘鹹醋。", "往復還，烏與兔。", "不得已，韶光度。", "五雜組，五色絲。", "往復還，回文詩。", "不得已，失喜期。"]'),
('92a91c9f-b861-457d-8f64-201de001ee13','七言大言聯句','顏真卿','唐','唐诗','tang','','[]','高歌閬風步瀛洲，燂鵬爚鯤餐未休。',32,'全唐诗/poet.tang.43000.json','["高歌閬風步瀛洲，燂鵬爚鯤餐未休。", "四方上下無外頭，一啜頓涸滄溟流。"]'),
('21219b75-ade8-45fc-ab22-b8764ecd51e9','七言小言聯句','顏真卿','唐','唐诗','tang','','[]','長路迢遙吞吐絲，蟭螟蚊睫察難知。',16,'全唐诗/poet.tang.43000.json','["長路迢遙吞吐絲，蟭螟蚊睫察難知。"]'),
('5c1c5d5b-fdca-41e1-b244-4c6443c6287a','七言樂語聯句','顏真卿','唐','唐诗','tang','','[]','苦河既濟真僧喜，新知滿座笑相視。',32,'全唐诗/poet.tang.43000.json','["苦河既濟真僧喜，新知滿座笑相視。", "戍客歸來見妻子，學生放假偷向市。"]'),
('a94b5f2c-ecc9-4e11-a901-731efd3b0f30','七言嚵語聯句','顏真卿','唐','唐诗','tang','','[]','拈䭔舐指不知休，欲炙侍立涎交流。',32,'全唐诗/poet.tang.43000.json','["拈䭔舐指不知休，欲炙侍立涎交流。", "過屠大嚼肯知羞，食店門外強淹留。"]'),
('1109c90a-36a4-4e56-a6f2-0f01062b3a20','七言滑語聯句','顏真卿','唐','唐诗','tang','','[]','雨裏下山蹋榆皮，莓苔石橋步難移。',40,'全唐诗/poet.tang.43000.json','["雨裏下山蹋榆皮，莓苔石橋步難移。", "蕪荑醬醋喫煮葵，縫靴蠟線油塗錐。", "急逢龍背須且騎。"]'),
('a974cf5f-cfdf-4d27-8a0c-52f5d3f72565','七言醉語聯句','顏真卿','唐','唐诗','tang','','[]','逢糟遇麯便酩酊，覆車墜馬皆不醒。',32,'全唐诗/poet.tang.43000.json','["逢糟遇麯便酩酊，覆車墜馬皆不醒。", "倒著接㒿髮垂領，狂心亂語無人竝。"]'),
('4d351384-9f44-454f-b5b9-da9a1bf6b155','建元寺晝公與崔秀才見過聯句與鄭奉禮部同作','皇甫曾','唐','唐诗','tang','','[]','人閑宜歲晚，道者訪幽期。',120,'全唐诗/poet.tang.43000.json','["人閑宜歲晚，道者訪幽期。", "獨與寒山別，行當暮雪時。", "柏臺辭漢主，竹寺寄潛師。", "荷策知君待，開門笑我遲。", "暮階縣雨足，寒吹繞松枝。", "理辯塵心妄，經分梵字疑。", "久承黃紙詔，曾賦碧雲詩。", "然諾驚相許，風流話所思。", "筌忘心已默，磬發夜何其。", "願結求羊侶，名山從所之。"]'),
('98c9c233-06c2-47de-8f9d-36b34fcc353d','建元寺西院寄李員外縱聯句','皇甫曾','唐','唐诗','tang','','[]','寄隱霜臺客，相思粉署人。',120,'全唐诗/poet.tang.43000.json','["寄隱霜臺客，相思粉署人。", "誠知阡陌近，無奈別離頻。", "夜色迷雙樹，鐘聲警四鄰。", "散才徒仰鮑，歸夢遠知秦。", "雨帶清笳發，花驚夕漏春。", "招搖隨步錫，髣髴聽行輪。", "要路推高足，空林寄一身。", "盛名知獨擅，良會憶相親。", "稍滌心中垢，都遺陌上塵。", "今宵此堂集，何事少遺民。"]'),
('78fb6cf1-def1-4f59-9e4a-d878dfa3a72b','中元日鮑端公宅遇吳天師聯句','嚴維','唐','唐诗','tang','','[]','道流爲柱史，教戒下真仙。',168,'全唐诗/poet.tang.43000.json','["道流爲柱史，教戒下真仙。", "共契中元會，初修內景篇。", "遊方依地僻，卜室喜牆連。", "寶笥開金籙，華池漱玉泉。", "怪龍隨羽翼，青節降雲煙。", "昔去遺丹竈，今來變海田。", "養形奔二景，鍊骨度千年。", "騎竹投陂裏，攜壺挂牖邊。", "洞中嘗入靜，河上舊談玄。", "伊洛笙歌遠，蓬壺日月偏。", "青騾薊訓引，白犬伯陽牽。", "法受相君後，心存象帝先。", "道成能縮地，功滿欲升天。", "何意迷孤性，含情戀數賢。"]'),
('4ae3e161-6143-44f6-af95-6c1f44f0d45e','酒語聯句各分一字','嚴維','唐','唐诗','tang','','[]','山簡酣歌倒接㒿，看朱成碧無所知。',88,'全唐诗/poet.tang.43000.json','["山簡酣歌倒接㒿，看朱成碧無所知。", "耳鳴目眩駟馬馳，口稱童羖腹鴟夷。", "兀然落帽灌酒巵，太常吏部相對時。", "藉糟枕麴浮酒池，瓮間籬下臥不移。", "叫呼不應無事悲，千日一醒知是誰。", "左傾右倒人避之。"]'),
('1ad1b7d6-54fe-435e-93e3-d2f56b628413','一字至九字詩聯句','嚴維','唐','唐诗','tang','','[]','東，西。',108,'全唐诗/poet.tang.43000.json','["東，西。", "步月，尋溪。", "鳥已宿，猨又啼。", "狂流礙石，迸筍穿磎。", "望望人煙遠，行行蘿徑迷。", "探題只應盡墨，持贈更欲封泥。", "松下流時何歲月，雲中幽處屢攀躋。", "乘興不知山路遠近，緣情莫問日過高低。", "靜聽林下潺潺足湍瀨，厭問城中喧喧多鼓鼙。"]'),
('36a514e0-92f1-4f74-82b3-7245297fa4ee','宣上人病中相尋聯句','李益','唐','唐诗','tang','','[]','策杖迎詩客，歸房理病身。',48,'全唐诗/poet.tang.43000.json','["策杖迎詩客，歸房理病身。", "閑收無效藥，徧寄有情人。", "草木分千品，方書問六陳。", "還知一室內，我爾即天親。"]'),
('9d83c748-a0ad-444f-8be9-b215cf82edd9','八月十五夜宣上人獨遊安國寺山庭院步人遲明將至因話昨宵乘興聯句','李益','唐','唐诗','tang','','[]','九重城接天花界，三五秋生一夜風。',64,'全唐诗/poet.tang.43000.json','["九重城接天花界，三五秋生一夜風。", "行聽漏聲雲散後，遙聞天語月明中。", "含涼閣迥通仙掖，承露盤高出上宮。", "誰問獨愁門外客，清談不與此宵同。"]'),
('5dee34f3-98c5-4e93-9f0d-8524840ef3b4','重陽夜集蘭陵居與宣上人聯句','李益','唐','唐诗','tang','','[]','蟋蟀催寒服，茱萸滴露房。',48,'全唐诗/poet.tang.43000.json','["蟋蟀催寒服，茱萸滴露房。", "酒巡明刻燭，籬菊暗尋芳。", "新月和秋露，繁星混夜霜。", "登高今夕事，九九是天長。"]'),
('23aeab81-c690-4383-8b10-2d0e105aec60','與宣供奉攜癭尊歸杏溪園聯句','李益','唐','唐诗','tang','','[]','千畦抱甕園，一酌癭尊酒。',48,'全唐诗/poet.tang.43000.json','["千畦抱甕園，一酌癭尊酒。", "唯有沃洲僧，時過杏溪叟。", "追歡君適性，獨飲我空口。", "儒釋事雖殊，文章意多偶。"]'),
('d63384dc-4f83-43cb-b8a7-c7020a3ac904','蘭陵僻居聯句','李益','唐','唐诗','tang','','[]','潘岳閑居賦，陶潛獨酌謠。',72,'全唐诗/poet.tang.43000.json','["潘岳閑居賦，陶潛獨酌謠。", "二賢成往事，三徑是今朝。", "生幸逢唐運，昌時奉帝堯。", "進思諧啓沃，退混即漁樵。", "蠹簡封延閣，彫闌閟上霄。", "相從清曠地，秋露挹蘭苕。"]'),
('53bc96df-8ea0-4936-b697-2fc94a3bdef3','天津橋南山中各題一句','李益','唐','唐诗','tang','','[]','野坐分苔席，山行繞菊叢。',24,'全唐诗/poet.tang.43000.json','["野坐分苔席，山行繞菊叢。", "雲衣惹不破，秋色望來空。"]'),
('830df6a7-5eb1-4c62-979c-eeaeade0a0b9','紅樓下聯句','李益','唐','唐诗','tang','','[]','佛剎接重城，紅樓切太清。',72,'全唐诗/poet.tang.43000.json','["佛剎接重城，紅樓切太清。", "紫雲連照耀，丹檻鬱崢嶸。", "榱棟煙虹入，軒窗日月平。", "參差五陵晚，分背八川明。", "松韻風初過，蓮陂浪欲傾。", "敬瞻疑涌見，圍繞學無生。"]'),
('c5311e29-eab3-4f14-9363-c6d81b786aa3','賦應門照綠苔','李益','唐','唐诗','tang','','[]','宮闕何年月，應門何歲苔。',48,'全唐诗/poet.tang.43000.json','["宮闕何年月，應門何歲苔。", "清光一以照，白露共裴回。", "珠履久行絕，玉房重未開。", "妾心正如此，昭陽歌吹來。"]'),
('e74f69c0-ed7a-4ab3-adeb-650db1cc262e','寄司空曙李端聯句','耿湋','唐','唐诗','tang','','[]','長安一分首，萬里隔煙波。',120,'全唐诗/poet.tang.43000.json','["長安一分首，萬里隔煙波。", "海上青山暮，天涯白髮多。", "尋僧因看竹，訪道或求鵝。", "雲樹無猨鳥，陰崖足薜蘿。", "醉中留越客，興裏眄庭柯。", "黃葉身仍逐，丹霄背未摩。", "別愁連旦暮，歸夢繞關河。", "高柳寒蟬對，空階夜雨和。", "年華空荏苒，名宦轉蹉跎。", "南陌東城路，春來幾度過。"]'),
('1746c11d-447f-4bff-bdb0-33ed521c2572','連句多暇贈陸三山人','耿湋','唐','唐诗','tang','','[]','一生爲墨客，幾世作茶仙。',144,'全唐诗/poet.tang.43000.json','["一生爲墨客，幾世作茶仙。", "喜是攀闌者，慙非負鼎賢。", "禁門聞曙漏，顧渚入晨煙。", "拜井孤城裏，攜籠萬壑前。", "閑喧悲異趣，語默取同年。", "歷落驚相偶，衰羸猥見憐。", "詩書聞講誦，文雅接蘭荃。", "未敢重芳席，焉能弄綵箋。", "黑池流研水，徑石澀苔錢。", "何事親香案，無端狎釣船。", "野中求逸禮，江上訪遺編。", "莫發搜歌意，予心或不然。"]'),
('7a8d86eb-2bee-45f2-a790-2452dca33f58','道州春日感興','李景儉','唐','唐诗','tang','','[]','始見花滿枝，又看花滿地。',48,'全唐诗/poet.tang.43000.json','["始見花滿枝，又看花滿地。", "且持增氣酒，莫滴傷心淚。", "深誠長鬱結，芳晨自妍媚。", "嘯歌聊永日，誰知此時意。"]'),
('d3bf982c-4340-4c31-b79c-e498fc2762cb','中秋夜聽歌聯句','武元衡','唐','唐诗','tang','','[]','此夕來奔月，何時去上天。',72,'全唐诗/poet.tang.43000.json','["此夕來奔月，何時去上天。", "雲鬟方自照，玉腕更呈鮮。", "燕婉人間意，飄颻物外緣。", "詩裁明月扇，歌索想夫憐。", "暗染荀香久，長隨楚夢偏。", "會當來彩鳳，髣髴逐神仙。"]'),
('86a91e4c-1580-41d9-8bb4-68b3c9ef6e49','春池泛舟聯句','裴度','唐','唐诗','tang','','[]','鳳池新雨後，池上好風光。',120,'全唐诗/poet.tang.43000.json','["鳳池新雨後，池上好風光。", "取酒愁春盡，留賓喜日長。", "柳絲迎畫舸，水鏡寫雕梁。", "潭洞迷仙府，煙霞認醉鄉。", "鶯聲隨笑語，竹色入壺觴。", "晚景含澄澈，時芳得豔陽。", "飛鳧拂輕浪，綠柳暗迴塘。", "逸韻追安石，高居勝辟彊。", "杯停新令舉，詩動綵牋忙。", "顧謂同來客，歡遊不可忘。"]'),
('ca763363-874c-4da2-b0db-57665365d49e','西池落泉聯句','裴度','唐','唐诗','tang','','[]','東閣聽泉落，能令野興多。',96,'全唐诗/poet.tang.43000.json','["東閣聽泉落，能令野興多。", "散時猶帶沫，淙處即跳波。", "偏洗磷磷石，還驚泛泛鵝。", "色清塵不染，光白月相和。", "噴雪縈松竹，攢珠濺芰荷。", "對吟時合響，觸樹更搖柯。", "照圃紅分藥，侵階綠浸莎。", "日斜車馬散，餘韻逐鳴珂。"]'),
('acd05cdb-edc1-44ff-8c33-6f6056e295b0','首夏猶清和聯句','裴度','唐','唐诗','tang','','[]','記得謝家詩，清和即此時。',120,'全唐诗/poet.tang.43000.json','["記得謝家詩，清和即此時。", "餘花數種在，密葉幾重垂。", "芳謝人人惜，陰成處處宜。", "水萍爭點綴，梁燕共追隨。", "亂蝶憐疎蘂，殘鶯戀好枝。", "草香殊未歇，雲勢漸多奇。", "單服初寧體，新篁已出籬。", "與春爲別近，覺日轉行遲。", "繞樹風光少，侵階苔蘚滋。", "惟思奉歡樂，長得在西池。"]'),
('b0f07ca0-3738-4724-8051-0f86d096819f','薔薇花聯句','裴度','唐','唐诗','tang','','[]','似錦如霞色，連春接夏開。',96,'全唐诗/poet.tang.43000.json','["似錦如霞色，連春接夏開。", "波紅分影入，風好帶香來。", "得地依東閣，當階奉上台。", "淺深皆有態，次第暗相催。", "滿地愁英落，緣堤惜櫂迴。", "芳濃濡雨露，明麗隔塵埃。", "似著臙脂染，如經巧婦裁。", "奈花無別計，只有酒殘杯。"]'),
('d2363f79-9196-4ea4-b497-a4b677f6a600','喜遇劉二十八偶書兩韻聯句','裴度','唐','唐诗','tang','','[]','病來佳興少，老去舊遊稀。',96,'全唐诗/poet.tang.43000.json','["病來佳興少，老去舊遊稀。", "笑語縱橫作，杯觴絡繹飛。", "清談如水玉，逸韻貫珠璣。", "高位當金鉉，虛懷似布衣。", "已容狂取樂，仍任醉忘機。", "捨眷將何適，留歡便是歸。", "鳳儀常欲附，蚊力自知微。", "願假尊罍末，膺門自此依。"]'),
('74c131c2-ecdb-4ff5-86c1-dbf6a6589549','劉二十八自汝赴左馮塗經洛中相見聯句','裴度','唐','唐诗','tang','','[]','不歸丹掖去，銅竹漫云云。',192,'全唐诗/poet.tang.43000.json','["不歸丹掖去，銅竹漫云云。", "唯喜因過我，須知未賀君。", "詩聞安石詠，香見令公熏。", "欲首函關路，來披緱嶺雲。", "貂蟬公獨步，鴛鷺我同羣。", "插羽先飛酒，交鋒便戰文。", "鎮嵩知表德，定鼎爲銘勳。", "顧鄙容商洛，徵歡候汝墳。", "頻年多謔浪，此夕任喧紛。", "故態猶應在，行期未要聞。", "遊藩榮已久，捧袂惜將分。", "詎厭杯行疾，唯愁日向曛。", "窮陰初莽蒼，離思漸氤氳。", "殘雪午橋岸，斜陽伊水濆。", "上謨尊右掖，全略靜東軍。", "萬頃徒稱量，滄溟詎有垠。"]'),
('a0ce3d80-fd8a-4adf-b24b-58e25c5d20ea','度自到洛中與樂天爲文酒之會時時搆詠樂不可支則慨然共憶夢得而夢得亦分司至止歡愜可知因爲聯句','裴度','唐','唐诗','tang','','[]','成周文酒會，吾友勝鄒枚。',288,'全唐诗/poet.tang.43000.json','["成周文酒會，吾友勝鄒枚。", "唯憶劉夫子，而今又到來。", "欲迎先倒屣，亦坐便傾杯。", "飲許伯倫右，詩推公幹才。", "久曾聆郢唱，重喜上燕臺。", "晝話牆陰轉，宵歡斗柄迴。", "新聲還共聽，故態復相咍。", "遇物皆先賞，從花半未開。", "起時烏帽側，散處玉山頹。", "墨客喧東閣，文星犯上台。", "詠吟君稱首，疎放我爲魁。", "憶戴何勞訪，留髠不用猜。", "奉觴承麴糵，落筆捧瓊瑰。", "醉弁無妨側，詞鋒不可摧。", "水軒看翡翠，石徑踐莓苔。", "童子能騎竹，佳人解詠梅。", "洛中三可矣，鄴下七悠哉。", "自向風光急，不須弦管催。", "樂觀魚踴躍，閑愛鶴裴回。", "煙柳青凝黛，波萍綠撥醅。", "春榆初改火，律管又飛灰。", "紅藥多遲發，碧松宜亂栽。", "馬嘶駝陌上，鷁泛鳳城隈。", "色色時堪惜，些些病莫推。"]'),
('369fe5ec-66fe-4e22-be52-eeefe1db519c','宴興化池亭送白二十二東歸聯句','裴度','唐','唐诗','tang','','[]','東洛言歸去，西園告別來。',192,'全唐诗/poet.tang.43000.json','["東洛言歸去，西園告別來。", "白頭青眼客，池上手中杯。", "離瑟殷勤奏，仙舟委曲回。", "征輪今欲動，賓閣爲誰開。", "坐弄琉璃水，行登綠縟堆。", "花低妝照影，萍散酒吹醅。", "岸蔭新抽竹，亭香欲變梅。", "隨遊多笑傲，遇勝且裴回。", "澄澈連天鏡，潺湲出地雷。", "林塘難共賞，鞍馬莫相催。", "信及魚還樂，機忘鳥不猜。", "晚晴槐起露，新雨石添苔。", "擬作雲泥別，尤思頃刻陪。", "歌停珠貫斷，飲罷玉峰頹。", "雖有逍遙志，其如磊落才。", "會當重入用，此去肯悠哉。"]'),
('eadd607d-a93b-48ef-97d7-9e343d1faa23','西池送白二十二東歸兼寄令狐相公聯句','裴度','唐','唐诗','tang','','[]','促坐宴回塘，送君歸洛陽。',108,'全唐诗/poet.tang.43000.json','["促坐宴回塘，送君歸洛陽。", "彼都留上宰，爲我說中腸。", "威鳳池邊別，冥鴻天際翔。", "披雲見居守，望日拜封章。", "春盡年華少，舟通景氣長。", "送行歡共惜，寄遠意難忘。", "東道瞻軒蓋，西園醉羽觴。", "謝公深眷眄，商皓信輝光。", "舊德推三友，新篇代八行。"]'),
('31b156c5-85d6-41be-9fe5-276ce8ea4f67','杏園聯句','李絳','唐','唐诗','tang','','[]','杏園千樹欲隨風，一醉同人此暫同。',64,'全唐诗/poet.tang.43000.json','["杏園千樹欲隨風，一醉同人此暫同。", "老態忽忘絲管裏，衰顏宜解酒杯中。", "曲江日暮殘紅在，翰苑年深舊事空。", "二十四年流落者，故人相引到花叢。"]'),
('7f83432c-c443-41fd-b105-78ea725537d7','花下醉中聯句','李絳','唐','唐诗','tang','','[]','共醉風光地，花飛落酒杯。',96,'全唐诗/poet.tang.43000.json','["共醉風光地，花飛落酒杯。", "殘春猶可賞，晚景莫相催。", "酒幸年年有，花應歲歲開。", "且當金韻擲，莫遣玉山頹。", "高會彌堪惜，良時不易陪。", "誰能拉花住，爭換得春回。", "我輩尋常有，佳人早晚來。", "寄言三相府，欲散且裴回。"]'),
('3d6dc54e-a5bf-4741-8ee8-d8305e89fb66','樂天是月長齋鄙夫此時愁臥里閭非遠雲霧難披因以寄懷遂爲聯句所期解悶焉敢驚禪','劉禹錫','唐','唐诗','tang','','[]','五月長齋月，文心苦行心。',288,'全唐诗/poet.tang.43000.json','["五月長齋月，文心苦行心。", "蘭蔥不入戶，薝蔔自成林。", "護戒先辭酒，嫌喧亦徹琴。", "塵埃賓位靜，香火道場深。", "我靜馴狂象，餐餘施衆禽。", "定知於佛佞，豈復向書淫。", "闌藥凋紅豔，庭槐換綠陰。", "風光徒滿目，雲霧未披襟。", "樹爲清涼倚，池因盥漱臨。", "蘋芳遭燕拂，蓮坼待蠭尋。", "舍下環流水，窗中列遠岑。", "苔斑錢剝落，石怪玉嶔岑。", "鵲頂迎秋禿，鶯喉入夏瘖。", "綠楊垂嫩色，綖棘露長鍼。", "散秩身猶幸，趨朝力不任。", "官將方共拙，年與病交侵。", "徇樂非時選，忘機似陸沈。", "鑒容稱四皓，捫腹有三壬。", "攜手慙連璧，同心許斷金。", "紫芝雖繼唱，白雪少知音。", "憶罷吳門守，相逢楚水潯。", "舟中頻曲宴，夜後各加斟。", "濁酒銷殘漏，弦聲間遠砧。", "酡顏舞長袖，密坐接華簪。"]'),
('0426e00e-b755-4169-bd3a-edeb00645dd6','秋霖即事聯句三十韻','白居易','唐','唐诗','tang','','[]','蕭索窮秋月，蒼茫苦雨天。',288,'全唐诗/poet.tang.43000.json','["蕭索窮秋月，蒼茫苦雨天。", "泄雲生棟上，行潦入庭前。", "苔色侵三徑，波聲想五弦。", "井蛙爭入戶，轍鮒亂歸泉。", "高𩅸愁晨坐，空階警夜眠。", "鶴鳴猶未已，蟻穴亦頻遷。", "散漫疎還密，空濛斷復連。", "竹霑青玉潤，荷滴白珠圓。", "地溼灰蛾滅，池添水馬憐。", "有苗霑霢霂，無月弄潺湲。", "籬菊潛開秀，園蔬已罷鮮。", "斷行隨雁翅，孤嘯聳鳶肩。", "橋柱黏黃菌，牆衣點綠錢。", "草荒行藥路，沙泛釣魚船。", "長者車猶阻，高人榻且懸。", "金烏何日見，玉爵幾時傳。", "近井桐先落，當檐石欲穿。", "趨風誠有戀，披霧邈無緣。", "廩米陳生醭，庖薪溼起煙。", "鳴雞潛報曉，急景暗彫年。", "蓋灑高松上，絲繁細柳邊。", "拂叢時起蝶，墮葉乍驚蟬。", "巾角皆爭墊，帬裾別似湔。", "人多蒙翠被，馬盡著連乾。"]'),
('702b8e84-8305-4d8d-ac54-5bf825966c20','喜晴聯句','白居易','唐','唐诗','tang','','[]','苦雨晴何喜，喜於未雨時。',288,'全唐诗/poet.tang.43000.json','["苦雨晴何喜，喜於未雨時。", "氣收雲物變，聲樂鳥烏知。", "蕙泛光風圃，蘭開皎月池。", "千峰分遠近，九陌好追隨。", "白日開天路，玄陰卷地維。", "餘清在林薄，新照入漣漪。", "碧樹涼先落，青蕪溼更滋。", "曬毛經浴鶴，曳尾出泥龜。", "舞去商羊速，飛來野馬遲。", "柱邊無潤礎，臺上有游絲。", "橋淨行塵息，堤長禁柳垂。", "宮城開睥睨，觀闕麗罘罳。", "洛水澄清鎮，嵩煙展翠帷。", "梁成虹乍見，市散蜃初移。", "藉草風猶暖，攀條露已晞。", "屋穿添碧瓦，牆缺召金鎚。", "迥徹來雙目，昏煩去四支。", "霞文晚煥爛，星影夕參差。", "爽助門庭肅，寒摧草木衰。", "黃乾向陽菊，紅洗得霜梨。", "假蓋閑誰惜，彈弦燥更悲。", "散蹄良馬穩，炙背野人宜。", "洞戶晨暉入，空庭宿霧披。", "推林出書目，傾笥上衣椸。"]'),
('e34b3adb-5e5a-49af-a42c-3d5ca6d61401','會昌春連宴即事','白居易','唐','唐诗','tang','','[]','元年寒食日，上巳暮春天。',288,'全唐诗/poet.tang.43000.json','["元年寒食日，上巳暮春天。", "雞黍三家會，鶯花二節連。", "光風初澹蕩，美景漸暄妍。", "簪組蘭亭上，車輿曲水邊。", "松聲添奏樂，草色助鋪筵。", "雀舫宜閑泛，螺杯任漫傳。", "園蔬香帶露，廚柳暗藏煙。", "麗句輕珠玉，清談勝管弦。", "陌喧金距鬬，樹動綵繩懸。", "姹女妝梳豔，遊童衣服鮮。", "圃香知種蕙，池暖憶開蓮。", "怪石雲疑觸，夭桃火欲然。", "正歡唯恐散，雖醉未思眠。", "嘯傲人間世，追隨地上僊。", "燕來雙涎涎，雁去累翩翩。", "行樂真吾事，尋芳獨我先。", "滯周慙太史，入洛繼先賢。", "昔恨多分手，今歡謬比肩。", "病猶陪讌飲，老更奉周旋。", "望重青雲客，情深白首年。", "徧嘗珍饌後，許入畫堂前。", "舞袖翻紅炬，歌鬟插寶蟬。", "斷金多感激，倚玉貴遷延。", "說史吞顏注，論詩笑鄭箋。"]'),
('f699ef22-319a-481b-8575-103300613ab9','僕射來示有三春向晚四者難幷之說誠哉是言輒引起題重爲聯句疲兵再戰勍敵難降下筆之時囅然自哂走呈僕射兼簡尚書','白居易','唐','唐诗','tang','','[]','三春今向晚，四者昔難幷。',288,'全唐诗/poet.tang.43000.json','["三春今向晚，四者昔難幷。", "借問低眉坐，何如攜手行。", "舊遊多過隙，新宴且尋盟。", "鸚鵡林須樂，麒麟閣未成。", "分陰當愛惜，遲景好逢迎。", "林野熏風起，樓臺穀雨晴。", "牆低山半出，池廣水初平。", "橋轉長虹曲，舟回小鷁輕。", "殘花猶布繡，密竹自聞笙。", "欲過芳菲節，難忘宴慰情。", "月輪行似箭，時物始如傾。", "見雁隨兄去，聽鶯求友聲。", "蕙長書帶展，菰嫩剪刀生。", "坐密衣裳暖，堂虛絲管清。", "峰巒侵碧落，草木近朱明。", "與點非沂水，陪膺是洛城。", "撥醅爭綠醑，臥酪待朱櫻。", "幾處能留客，何人喚解酲。", "舊儀尊右揆，新命寵春卿。", "有喜鵲頻語，無機鷗不驚。", "青林思小隱，白雪仰芳名。", "訪舊殊千里，登高賴九城。", "酇侯司管鑰，疏傅傲簪纓。", "綸綍曾同掌，煙霄即上征。"]'),
('06d93660-224b-4a79-baef-3f219bb7011f','城南聯句','韓愈','唐','唐诗','tang','','[]','竹影金瑣碎，泉音玉淙琤。',288,'全唐诗/poet.tang.43000.json','["竹影金瑣碎，泉音玉淙琤。", "琉璃翦木葉，翡翠開園英。", "流滑隨仄步，搜尋得深行。", "遙岑出寸碧，遠目增雙明。", "乾穟紛拄地，化蟲枯挶莖。", "木腐或垂耳，草珠競駢睛。", "浮虛有新斸，摧扤饒孤撐。", "囚飛黏網動，盜啅接彈驚。", "脫實自開坼，牽柔誰繞縈。", "禮鼠拱而立，駭牛躅且鳴。", "蔬甲喜臨社，田毛樂寬征。", "露螢不自暖，凍蝶尚思輕。", "宿羽有先曉，食鱗時半橫。", "菱飜紫角利，荷折碧圓傾。", "楚膩鱣鮪亂，獠羞蠃蟹幷。", "桑蠖見虛指，穴貍聞鬬獰。", "逗翳翅相築，擺幽尾交搒。", "蔓涎角出縮，樹啄頭敲鏗。", "修箭褭金餌，羣鮮沸池羹。", "岸殼坼玄兆，野麰漸豐萌。", "窰煙羃疏島，沙篆印迴平。", "㾕肌遭眊刺，啾耳聞雞生。", "奇慮恣迴轉，遐睎縱逢迎。", "顛林戢遠睫，縹氣夷空情。"]'),
('f9828863-e92e-4aad-bc05-209438dd31f5','會合聯句','韓愈','唐','唐诗','tang','','[]','離別言無期，會合意彌重。',288,'全唐诗/poet.tang.43000.json','["離別言無期，會合意彌重。", "病添兒女戀，老喪丈夫勇。", "劒心知未死，詩思猶孤聳。", "愁去劇箭飛，歡來若泉涌。", "析言多新貫，攄抱無昔壅。", "念難須勤追，悔易勿輕踵。", "吟巴山犖嶨，說楚波堆壟。", "馬辭虎豹怒，舟出蛟鼉恐。", "狂鯨時孤軒，幽狖雜百種。", "瘴衣常腥膩，蠻器多疎宂。", "剝苔弔斑林，角飯餌沈冢。", "忽爾銜遠命，歸歟舞新寵。", "鬼窟脫幽妖，天居覿清栱。", "京遊步方振，謫夢意猶恟。", "詩書誇舊知，酒食接新奉。", "嘉言寫清越，瘉病失肬腫。", "夏陰偶高庇，宵魄接虛擁。", "雪弦寂寂聽，茗盌纖纖捧。", "馳輝燭浮螢，幽響泄潛蛬。", "詩老獨何心，江疾有餘尰。", "我家本瀍穀，有地介臯鞏。", "休跡憶沈冥，峨冠慙闒𤾖。", "升朝高轡逸，振物羣聽悚。", "徒言濯幽泌，誰與薙荒茸。"]'),
('3932a98c-45b7-4754-9cb7-6e00eeb2971a','鬬雞聯句','韓愈','唐','唐诗','tang','','[]','大雞昂然來，小雞竦而待。',288,'全唐诗/poet.tang.43000.json','["大雞昂然來，小雞竦而待。", "崢嶸顛盛氣，洗刷凝鮮彩。", "高行若矜豪，側睨如伺殆。", "精光目相射，劒戟心獨在。", "既取冠爲胄，復以距爲鐓。", "天時得清寒，地利挾爽塏。", "磔毛各噤㾕，怒癭爭碨磊。", "俄膺忽爾低，植立瞥而改。", "腷膊戰聲喧，繽飜落羽皠。", "中休事未決，小挫勢益倍。", "妬腸務生敵，賊性專相醢。", "裂血失鳴聲，啄殷甚飢餒。", "對起何急驚，隨旋誠巧紿。", "毒手飽李陽，神槌困朱亥。", "惻心我以仁，碎首爾何罪。", "獨勝事有然，旁驚汗流浼。", "知雄欣動顏，怯負愁看賄。", "爭觀雲填道，助叫波飜海。", "事爪深難解，嗔睛時未怠。", "一噴一醒然，再接再礪乃。", "頭垂碎丹砂，翼搨拖錦綵。", "連軒尚賈餘，清厲比歸凱。", "選俊感收毛，受恩慙始隗。", "英心甘鬬死，義肉恥庖宰。"]'),
('bdb4a42a-f2dc-46bc-b47a-19434f475c22','納涼聯句','韓愈','唐','唐诗','tang','','[]','遞嘯取遙風，微微近秋朔。',288,'全唐诗/poet.tang.43000.json','["遞嘯取遙風，微微近秋朔。", "金柔氣尚低，火老候愈濁。", "熙熙炎光流，竦竦高雲擢。", "閃紅驚蚴虯，凝赤聳山嶽。", "目林恐焚燒，耳井憶瀺灂。", "仰懼失交泰，非時結冰雹。", "化鄧渴且多，奔河誠已慤。", "暍道者誰子，叩商者何樂。", "洗矣得滂沱，感然鳴鸑鷟。", "嘉願苟未從，前心空緬邈。", "清砌千迴坐，冷環再三握。", "煩懷却星星，高意還卓卓。", "龍沈劇煮鱗，牛喘甚焚角。", "蟬煩鳴轉喝，烏噪飢不啄。", "晝蠅食案繁，宵蚋肌血渥。", "單絺厭已褫，長䈉倦還捉。", "幸茲得佳朋，於此蔭華桷。", "青熒文簟施，淡澉甘瓜濯。", "大壁曠凝淨，古畫奇駁犖。", "淒如羾寒門，皓若攢玉璞。", "埽寬延鮮飆，汲冷漬香穱。", "篚實摘林珍，盤殽饋禽㲉。", "空堂喜淹留，貧饌羞齷齪。", "殷勤相勸勉，左右加礱斲。"]'),
('56fc63f1-446e-4b6a-96a2-cf0c34fac211','秋雨聯句','韓愈','唐','唐诗','tang','','[]','萬木聲號呼，百川氣交會。',288,'全唐诗/poet.tang.43000.json','["萬木聲號呼，百川氣交會。", "庭飜樹離合，牖變景明藹。", "潨瀉殊未終，飛浮亦云泰。", "牽懷到空山，屬聽邇驚瀨。", "檐垂白練直，渠漲清湘大。", "甘津澤祥禾，伏潤肥荒艾。", "主人吟有歡，客子歌無奈。", "侵陽日沈玄，剝節風搜兌。", "坱圠遊峽喧，颼飀臥江汰。", "微飄來枕前，高灑自天外。", "蛬穴何迫迮，蟬枝埽鳴噦。", "楥菊茂新芳，徑蘭銷晚馤。", "地鏡時昏曉，池星競漂沛。", "讙呶尋一聲，灌注咽羣籟。", "儒宮煙火溼，市舍煎熬忲。", "臥冷空避門，衣寒屢循帶。", "水怒已倒流，陰繁恐凝害。", "憂魚思舟檝，感禹勤畎澮。", "懷襄信可畏，疏決須有賴。", "筮命或馮蓍，卜晴將問蔡。", "庭商忽驚舞，墉禜亦親酹。", "氛醨稍疎映，雺亂還擁薈。", "陰旌時摎流，帝鼓鎮訇磕。", "棗圃落青璣，瓜畦爛文貝。"]'),
('6cf29ef3-76c8-420c-906a-3aab88dce825','征蜀聯句','韓愈','唐','唐诗','tang','','[]','日王忿違慠，有命事誅拔。',288,'全唐诗/poet.tang.43000.json','["日王忿違慠，有命事誅拔。", "蜀險豁關防，秦師縱橫猾。", "風旗匝地揚，雷鼓轟天殺。", "竹兵彼皴脆，鐵刃我槍䶪。", "刑神咤犛旄，陰燄颭犀札。", "飜霓紛偃蹇，塞野澒坱圠。", "生獰競掣跌，癡突爭填軋。", "渴鬬信豗呶，噉奸何噢嗗。", "更呼相簸蕩，交斫雙缺齾。", "火發激鋩腥，血漂騰足滑。", "飛猱無整陣，翩鶻有邪戛。", "江倒沸鯨鯤，山搖潰貙䝟。", "中離分二三，外變迷七八。", "逆頸盡徽索，仇頭恣髠鬝。", "怒鬚猶鬇鬡，斷臂仍𤬁𤫶。", "石潛設奇伏，穴覰騁精察。", "中矢類妖㺑，跳鋒狀驚豽。", "蹋飜聚林嶺，斗起成埃圿。", "斾亡多空杠，軸折鮮聯轄。", "剟膚浹瘡痍，敗面碎剠㓤。", "渾奔肆狂勷，捷竄脫趫黠。", "巖鉤踔狙猨，水漉雜鱣螖。", "投奅鬧䃔䃧，填隍𠋘㑻𠋚。", "強睛死不閉，獷眼困逾䀣。"]'),
('99aa50fb-e645-453d-9762-a6622be195ae','同宿聯句','韓愈','唐','唐诗','tang','','[]','自從別君來，遠出遭巧譖。',204,'全唐诗/poet.tang.43000.json','["自從別君來，遠出遭巧譖。", "斑斑落春淚，浩浩浮秋浸。", "毛奇覩象犀，羽怪見鵩鴆。", "朝行多危棧，夜臥饒驚枕。", "生榮今分踰，死棄昔情任。", "鵷行參綺陌，雞唱聞清禁。", "山晴指高標，槐密騖長蔭。", "直辭一以薦，巧舌千皆𦧈。", "匡鼎惟說詩，桓譚不讀讖。", "逸韻何嘈嗷，高名俟沽賃。", "紛葩歡屢填，曠朗憂早滲。", "爲君開酒腸，顛倒舞相飲。", "曦光霽曙物，景曜鑠宵祲。", "儒門雖大啓，奸首不敢闖。", "義泉雖至近，盜索不敢沁。", "清琴試一揮，白鶴叫相喑。", "欲知心同樂，雙繭抽作絍。"]'),
('991b8b2a-11e3-4ea8-8ed9-3e02c807a232','莎柵聯句','韓愈','唐','唐诗','tang','','[]','冰溪時咽絕，風櫪方軒舉。',24,'全唐诗/poet.tang.43000.json','["冰溪時咽絕，風櫪方軒舉。", "此處不斷腸，定知無斷處。"]'),
('34a198e6-7d61-4aac-b5d5-d92312e28649','雨中寄孟刑部幾道聯句','韓愈','唐','唐诗','tang','','[]','秋潦淹轍迹，高居限參拜。',288,'全唐诗/poet.tang.43000.json','["秋潦淹轍迹，高居限參拜。", "耿耿蓄良思，遙遙仰嘉話。", "一晨長隔歲，百步遠殊界。", "商聽饒清聳，悶懷空抑噫。", "美君知道腴，逸步謝天械。", "吟馨鑠紛雜，抱照瑩疑怪。", "撞宏聲不掉，輸邈瀾逾殺。", "檐瀉碎江喧，街流淺溪邁。", "念初相遭逢，幸免因媒介。", "祛煩類決癰，愜興劇爬疥。", "研文較幽玄，呼博騁雄快。", "今君軺方馳，伊我羽已鎩。", "溫存感深惠，琢切奉明誡。", "迨茲更凝情，暫阻若嬰瘵。", "欲知相從盡，靈珀拾纖芥。", "欲知相益多，神藥銷宿憊。", "德符仙山岸，永立難欹壞。", "氣涵秋天河，有朗無驚湃。", "祥鳳遺蒿鷃，雲韶掩夷靺。", "爭名求鵠徒，騰口甚蟬喝。", "未來聲已赫，始鼓敵前敗。", "鬬場再鳴先，遐路一飛屆。", "東野繼奇躅，修綸懸衆犗。", "穿空細丘垤，照日陋菅蒯。"]'),
('629687ee-7e6f-4b7a-8c3d-2034d5e752da','遠遊聯句','韓愈','唐','唐诗','tang','','[]','別腸車輪轉，一日一萬周。',288,'全唐诗/poet.tang.43000.json','["別腸車輪轉，一日一萬周。", "離思春冰泮，瀾漫不可收。", "馳光忽以迫，飛轡誰能留。", "取之詎灼灼，此去信悠悠。", "楚客宿江上，夜魂棲浪頭。", "曉日生遠岸，水芳綴孤舟。", "村飲泊好木，野蔬拾新柔。", "獨含悽悽別，中結鬱鬱愁。", "人憶舊行樂，鳥吟新得儔。", "靈瑟時窅窅，霠猨夜啾啾。", "憤濤氣尚盛，恨竹淚空幽。", "長懷絕無已，多感良自尤。", "即路涉獻歲，歸期眇涼秋。", "兩歡日牢落，孤悲坐綢繆。", "觀怪忽蕩漾，叩奇獨冥搜。", "海鯨吞明月，浪島沒大漚。", "我有一寸鈎，欲釣千丈流。", "良知忽然遠，壯志鬱無抽。", "魍魅暫出沒，蛟螭互蟠蟉。", "昌言拜舜禹，舉颿凌斗牛。", "懷糈餽賢屈，乘桴追聖丘。", "飄然天外步，豈肯區中囚。", "楚些待誰弔，賈辭緘恨投。", "翳明弗可曉，祕魂安所求。"]'),
('a0056864-b83d-42a0-8d6b-c0b3a654f67d','晚秋郾城夜會聯句','韓愈','唐','唐诗','tang','','[]','從軍古云樂，談笑青油幕。',288,'全唐诗/poet.tang.43000.json','["從軍古云樂，談笑青油幕。", "燈明夜觀棊，月暗秋城柝。", "羈客方寂歷，驚烏時落泊。", "語闌壯氣衰，酒醒寒砧作。", "遇主貴陳力，夷凶匪兼弱。", "百牢犒輿師，千戶購首惡。", "平生恥論兵，末暮不輕諾。", "徒然感恩義，誰復論勳爵。", "多士被霑汚，小夷施毒蠚。", "何當鑄劒戟，相與歸臺閣。", "室婦歡鳴鸛，家人祝喜鵲。", "終朝考蓍龜，何日親蒸礿。", "間使斷津梁，潛軍索林薄。", "紅塵羽書靖，大水沙囊涸。", "銘山子所工，插羽余何怍。", "未足煩刀俎，祗應輸管鑰。", "雨矢逐天狼，電矛驅海若。", "靈誅固無縱，力戰誰敢却。", "峨峨雲梯翔，赫赫火箭著。", "連空隳雉堞，照夜焚城郭。", "軍門宣一令，廟算建三略。", "雷鼓揭千槍，浮橋交萬筰。", "蹂野馬雲騰，映原旗火鑠。", "疲氓墜將拯，殘虜狂可縛。"]'),
('4d8d8c41-eb86-4279-84a8-f8c0ac204cdb','石鼎聯句','韓愈','唐','唐诗','tang','','[]','巧匠斲山骨，刳中事煎烹。',288,'全唐诗/poet.tang.43000.json','["巧匠斲山骨，刳中事煎烹。", "直柄未當權，塞口且吞聲。", "龍頭縮菌蠢，豕腹漲彭亨。", "外苞乾蘚文，中有暗浪驚。", "在冷足自安，遭焚意彌貞。", "謬當鼎鼐間，妄使水火爭。", "大似烈士膽，圓如戰馬纓。", "上比香爐尖，下與鏡面平。", "秋瓜未落蔕，凍芋強抽萌。", "一塊元氣閉，細泉幽竇傾。", "不值輸寫處，焉知懷抱清。", "方當洪爐然，益見小器盈。", "睆睆無刃迹，團團類天成。", "遙疑龜負圖，出曝曉正晴。", "旁有雙耳穿，上有孤髻撐。", "或訝短尾銚，又似無足鐺。", "可惜寒食毬，擲此傍路坑。", "何當出灰灺，無計離缾罌。", "陋質荷斟酌，狹中媿提擎。", "豈能煮仙藥，但未汙羊羹。", "形模婦女笑，度量兒童輕。", "徒示堅重性，不過升合盛。", "傍似廢轂仰，側見折軸橫。", "時於蚯蚓竅，微作蒼蠅鳴。"]'),
('6693bd3c-6a2b-4090-bcac-6d6a5a3538ee','有所思聯句','孟郊','唐','唐诗','tang','','[]','相思繞我心，日夕千萬重。',48,'全唐诗/poet.tang.43000.json','["相思繞我心，日夕千萬重。", "年光坐婉娩，春淚銷顏容。", "臺鏡晦舊暉，庭草滋深茸。", "望夫山上石，別劒水中龍。"]'),
('2a548bf0-2a16-46d1-9b9c-8db15d0bfc54','遣興聯句','孟郊','唐','唐诗','tang','','[]','我心隨月光，寫君庭中央。',144,'全唐诗/poet.tang.43000.json','["我心隨月光，寫君庭中央。", "月光有時晦，我心安所忘。", "常恐金石契，斷爲相思腸。", "平生無百歲，岐路有四方。", "四方各異俗，適異非所將。", "駑蹄顧挫秣，逸翮遺稻粱。", "時危抱獨沈，道泰懷同翔。", "獨居久寂默，相顧聊慨慷。", "慨慷丈夫志，可以曜鋒鋩。", "蘧甯知卷舒，孔顏識行藏。", "殷鑒諒不遠，佩蘭永芬芳。", "苟無夫子聽，誰使知音揚。"]'),
('5a6e9180-49c1-4713-be3d-a3fd53d50e5e','贈劒客李園聯句','孟郊','唐','唐诗','tang','','[]','天地有靈術，得之者惟君。',120,'全唐诗/poet.tang.43000.json','["天地有靈術，得之者惟君。", "築爐地區外，積火燒氛氳。", "照海鑠幽怪，滿空歊異氛。", "山磨電奕奕，水淬龍蝹蝹。", "太一裝以寶，列仙篆其文。", "可用懾百神，豈惟壯三軍。", "有時幽匣吟，忽似深潭聞。", "風胡久已死，此劒將誰分。", "行當獻天子，然後致殊勳。", "豈知豐城下，空有斗間雲。"]'),
('d4476668-8330-4664-a1ef-757a54961c56','過海聯句','賈島','唐','唐诗','tang','','[]','沙鳥浮還沒，山雲斷復連。',24,'全唐诗/poet.tang.43000.json','["沙鳥浮還沒，山雲斷復連。", "櫂穿波底月，船壓水中天。"]'),
('e78d31b7-0bc5-48a6-91ca-36cdca85bb93','妓席與杜牧之同詠','張祜','唐','唐诗','tang','','[]','骰子逡巡裹手拈，無因得見玉纖纖。',32,'全唐诗/poet.tang.43000.json','["骰子逡巡裹手拈，無因得見玉纖纖。", "但知報道金釵落，髣髴還應露指尖。"]'),
('fe6526d1-3f9e-400a-8220-65c922e28b3e','同趙二十二訪張明府郊居聯句','杜牧','唐','唐诗','tang','','[]','陶潛官罷酒缾空，門掩楊花一夜風。',64,'全唐诗/poet.tang.43000.json','["陶潛官罷酒缾空，門掩楊花一夜風。", "古調詩吟山色裏，無弦琴在月明中。", "遠檐高樹宜幽鳥，出岫孤雲逐晚虹。", "別後東籬數枝菊，不知閑醉與誰同。"]'),
('9b89cb78-6444-44c8-b05f-0c05369060c4','遊長安諸寺聯句 靖恭坊大興善寺 老松青桐聯二十字絕句','段成式','唐','唐诗','tang','','[]','有松堪繫馬，遇鉢更投鍼。',72,'全唐诗/poet.tang.43000.json','["有松堪繫馬，遇鉢更投鍼。", "記得湯師句，高禪助朗吟。", "乘晴入精舍，語默想東林。", "盡是忘機侶，誰驚息影禽。", "一雨微塵盡，支郎許數過。", "方同齅薝蔔，不用算多羅。"]'),
('d7e6edd9-f281-4e0b-ade7-6137f877c644','遊長安諸寺聯句 靖恭坊大興善寺 蛤像聯二十字絕句','段成式','唐','唐诗','tang','','[]','相好全如梵，端倪祗爲隋。',48,'全唐诗/poet.tang.43000.json','["相好全如梵，端倪祗爲隋。", "寧同蚌頑惡，但與鷸相持。", "雖因雀變化，不逐月虧盈。", "縱有天中匠，神工詎可成。"]'),
('ff52cb43-155a-47be-9d87-d830d5b151d4','遊長安諸寺聯句 靖恭坊大興善寺 聖柱聯句','段成式','唐','唐诗','tang','','[]','天心惟助善，聖跡此開陽。',48,'全唐诗/poet.tang.43000.json','["天心惟助善，聖跡此開陽。", "載恐雷輪重，絙疑電索長。", "上衝挾螮蝀，不動束鋃鐺。", "飢鳥未曾啄，乖龍寧敢藏。"]'),
('4d485a48-caca-4a64-91ad-894d91f93c80','遊長安諸寺聯句 長樂坊安國寺 紅樓聯句','段成式','唐','唐诗','tang','','[]','重疊碎晴空，餘霞更照紅。',48,'全唐诗/poet.tang.43000.json','["重疊碎晴空，餘霞更照紅。", "蟬蹤近鳷鵲，鳥道接相風。", "苔靜金輪路，雲輕白日宮。", "壁詩傳謝客，門牓占休公。"]'),
('4d391f36-31e3-44d7-8512-c40009a9a9ef','遊長安諸寺聯句 長樂坊安國寺 穗柏聯句','段成式','唐','唐诗','tang','','[]','一院暑難侵，莓苔共影深。',48,'全唐诗/poet.tang.43000.json','["一院暑難侵，莓苔共影深。", "標枝爭息鳥，餘吹正開襟。", "宿雨香添色，殘陽石在陰。", "乘閑動詩意，助靜入禪心。"]'),
('6a033932-752e-4e17-9cae-6f583594421e','遊長安諸寺聯句 長樂坊安國寺 題璘公院','段成式','唐','唐诗','tang','','[]','靜，虛。',70,'全唐诗/poet.tang.43000.json','["靜，虛。", "熱際，安居。", "龕燈斂，印香除。", "東林賓客，西澗圖書。", "檐外垂青豆，經中發白蕖。", "縱辯宗因衮衮，忘言理事如如。", "泉臺定將入流否，鄰笛足疑清梵餘。"]'),
('e54fae26-a908-43de-98df-93b05b447913','遊長安諸寺聯句 常樂坊趙景公寺 吳畫聯句','段成式','唐','唐诗','tang','','[]','慘澹十堵內，吳生縱狂跡。',120,'全唐诗/poet.tang.43000.json','["慘澹十堵內，吳生縱狂跡。", "風雲將逼人，神鬼如脫壁。", "其中龍最怪，張甲方汗栗。", "黑雲夜窸窣，焉知不霹靂。", "此際忽仙子，獵獵衣舃奕。", "妙瞬乍疑生，參差奪人魄。", "往往乘猛虎，衝梁聳奇石。", "蒼峭束高泉，角膝驚欹側。", "冥獄不可視，毛戴腋流液。", "苟能水成河，剎那沈火宅。"]'),
('7fd20295-962c-46f6-902a-984f83b730e3','遊長安諸寺聯句 常樂坊趙景公寺 題約公院','段成式','唐','唐诗','tang','','[]','印火熒熒，燈續燄青。',40,'全唐诗/poet.tang.43000.json','["印火熒熒，燈續燄青。", "七俱胝咒，四阿含經。", "各錄佳語，聊事素屏。", "丈室安居，延賓不扃。"]'),
('2bdb1a24-689f-41b3-881f-168934c13230','遊長安諸寺聯句 大同坊雲華寺 偶聯句','段成式','唐','唐诗','tang','','[]','共入夕陽寺，因窺甘露門。',72,'全唐诗/poet.tang.43000.json','["共入夕陽寺，因窺甘露門。", "清香惹苔蘚，忍草雜蘭蓀。", "捷偈飛鉗荅，新詩倚杖論。", "壞幡標古剎，聖畫煥崇垣。", "豈慕穿籠鳥，難防在牖猿。", "一音唯一性，三語更三幡。"]'),
('d5fc52f1-826f-44b8-8840-b0816da20c13','遊長安諸寺聯句 道政坊寶應寺 僧房聯句','段成式','唐','唐诗','tang','','[]','古畫思匡嶺，上方疑傅巖。',48,'全唐诗/poet.tang.43000.json','["古畫思匡嶺，上方疑傅巖。", "蝶閑移忍草，蟬曉揭高杉。", "香字消芝印，金經發茝函。", "井通松底脈，書坼洞中緘。"]'),
('5908ea6e-b35f-467c-9a2e-222033f8c47f','遊長安諸寺聯句 道政坊寶應寺 小小寫真聯句','段成式','唐','唐诗','tang','','[]','如生小小真，猶自未棲塵。',120,'全唐诗/poet.tang.43000.json','["如生小小真，猶自未棲塵。", "褕袂將離座，斜柯欲近人。", "昔時知出衆，情寵占橫陳。", "不遣遊張巷，豈教窺宋鄰。", "庾樓吹笛裂，弘閣賞歌新。", "蟬怯纖腰步，蛾驚半額嚬。", "圖形誰有術，買笑詎辭貧。", "複隴迷村徑，重泉隔漢津。", "同心知作羽，比目定爲鱗。", "殘月巫山夕，餘霞洛浦晨。"]'),
('1703e40e-b76e-405f-ae20-491c41427b05','遊長安諸寺聯句 平康坊菩薩寺 書事聯句','段成式','唐','唐诗','tang','','[]','悉爲無事者，任被俗流憎。',144,'全唐诗/poet.tang.43000.json','["悉爲無事者，任被俗流憎。", "客異干時客，僧非出院僧。", "遠聞疎牖磬，曉辨密龕燈。", "步觸珠旛響，吟窺鉢水澄。", "句饒方外趣，遊愜社中朋。", "靜裏已馴鴿，齋中亦好鷹。", "金塗筆是褧，彩溜紙非繒。", "錫杖已剋鍛，田衣從懷塍。", "占牀暫一脅，卷箔賴長肱。", "佛日初開照，魔天破幾層。", "咒中陳祕計，論處正先登。", "勇帶綻鍼石，危防丘井藤。"]'),
('d88a3098-c01c-4930-babe-d6c134afaad5','遊長安諸寺聯句 光宅坊光宅寺 中禪師影堂聯句','段成式','唐','唐诗','tang','','[]','名下固無虛，敖曹貌嚴毅。',120,'全唐诗/poet.tang.43000.json','["名下固無虛，敖曹貌嚴毅。", "洞達見空王，圓融入佛地。", "一言當要害，忽忽醒諸醉。", "不動須彌山，多方辯無匱。", "坦率對萬乘，偈荅無所避。", "爾如毘沙門，外形如脫履。", "但以理爲量，不語怪力事。", "木石摧貢高，慈悲引貪恚。", "當時乏支許，何人契深致。", "隨宜詎說三，直下開不二。"]'),
('e0b59988-260c-4e65-a5b5-d7c7d18b9268','遊長安諸寺聯句 翊善坊保壽寺 光天幀讚聯句','段成式','唐','唐诗','tang','','[]','觀音化身，厥形孔怪。',142,'全唐诗/poet.tang.43000.json','["觀音化身，厥形孔怪。", "胣腦淫厲，衆魔膜拜。", "指夢鴻紛，牓列區界。", "其事明張，何不可解。", "閻阿德川，大士先天。", "衆象參羅，福源田田。", "百億花發，百千燈然。", "膠如[絡繹]，浩汗連緜。", "燄摩界戚，洛迦苦霽。", "正念皈依，衆青如𥶙。", "戾滓可汰，癡膜可蛻。", "稽首如空，睟容若睇。", "闡提墨師，覩而面之。", "寸念不生，未遇乎而。"]'),
('55b3c9cc-9b0b-4ed7-92ee-29b01c690c9f','遊長安諸寺聯句 宣陽坊靜域寺 三階院聯句','段成式','唐','唐诗','tang','','[]','密密助堂堂，隋人歌檿桑。',120,'全唐诗/poet.tang.43000.json','["密密助堂堂，隋人歌檿桑。", "雙弧摧孔雀，一矢隕貪狼。", "百步望雲立，九規看月張。", "獲蛟徒破浪，中乙漫如牆。", "還似貫金鼓，更疑穿石梁。", "因添挽河力，爲滅射天狂。", "絕藝却南牧，英聲來鬼方。", "麗龜何足敵，殪豕未爲長。", "龍臂勝猨臂，星芒超箭芒。", "虛誇絕高鳥，垂拱議明堂。"]'),
('1bde6a3a-097b-4517-bd28-bc985819bf74','遊長安諸寺聯句 崇義坊招福院 贈諸上人聯句','段成式','唐','唐诗','tang','','[]','飜了西天偈，燒餘梵宇香。',96,'全唐诗/poet.tang.43000.json','["飜了西天偈，燒餘梵宇香。", "撚眉愁俗客，支頰背殘陽。", "洲號惟思沃，山名祗記匡。", "辨中摧世智，定裏破魔強。", "許叡禪心徹，湯休詩思長。", "朗吟疎磬斷，久語貫珠妨。", "乘興書芭葉，閑來入豆房。", "漫題存古壁，怪畫匝長廊。"]'),
('20d1e419-7b2a-4ef0-bef7-67de4d6a3e55','遊長安諸寺聯句 招國坊崇濟寺 奇松聯二十字絕句','段成式','唐','唐诗','tang','','[]','杉松何相疎，榆柳方迥屑。',120,'全唐诗/poet.tang.43000.json','["杉松何相疎，榆柳方迥屑。", "無人擅談柄，一枝不敢折。", "中庭苔蘚深，吹餘鳴佛禽。", "至於摧折枝，凡草猶避陰。", "僻徑根從露，閑房枝任侵。", "一株風正好，來助碧雲吟。", "時時埽窗聲，重露滴寒砌。", "風颭一枝遒，閑窺別生勢。", "偃蓋入樓妨，盤根侵井窄。", "高僧獨惆悵，爲與澄嵐隔。"]'),
('710c35fe-bd6c-4c1d-9175-2db7eb5541d6','遊長安諸寺聯句 永安坊永壽寺 閑中好','段成式','唐','唐诗','tang','','[]','閑中好，盡日松爲侶。',66,'全唐诗/poet.tang.43000.json','["閑中好，盡日松爲侶。", "此趣人不知，輕風度僧語。", "閑中好，塵務不縈心。", "坐對當窗木，看移三面陰。", "閑中好，幽磬度聲遲。", "卷上論題肇，畫中僧姓支。"]'),
('b5288376-7ae6-4eff-a3d3-f57639918688','遊長安諸寺聯句 崇仁坊資聖寺 諸畫聯句','段成式','唐','唐诗','tang','','[]','吳生畫勇矛戟攢，出變奇勢千萬端。',88,'全唐诗/poet.tang.43000.json','["吳生畫勇矛戟攢，出變奇勢千萬端。", "蒼蒼鬼怪層壁寬，覩之忽忽毛髮寒。", "稜伽之力所疲殫，李真周昉優劣難。", "活禽生卉推邊鸞，花房嫩彩猶未乾。", "韓幹變態如激湍，惜哉壁畫世未殫。", "後人新畫何汗漫。"]'),
('2299b727-1e00-43b6-92b9-54010cba43ef','北禪院避暑聯句','皮日休','唐','唐诗','tang','','[]','歊蒸何處避，來入戴顒宅。',288,'全唐诗/poet.tang.43000.json','["歊蒸何處避，來入戴顒宅。", "逍遙脫單絞，放曠拋輕策。", "爬搔林下風，偃仰澗中石。", "殘蟬煙外響，野鶴沙中跡。", "到此失煩襟，蕭然揖禪伯。", "藤懸疊霜蛻，桂倚支雲錫。", "清陰豎毛髮，爽氣舒筋脈。", "逐幽隨竹書，選勝鋪苮席。", "魚跳上紫芡，蝶化緣青壁。", "心是玉蓮徒，耳爲金磬敵。", "吾宗昔高尚，志在羲皇易。", "豈獨斷韋編，幾將刓鐵擿。", "天書既屢降，野抱難自適。", "一入承明廬，盱衡論今昔。", "流光不容寸，斯道甘枉尺。", "既起謝儒玄，亦飜商羽翼。", "封章帷幄徧，夢寐江湖白。", "擺落函谷塵，高欹華陽幘。", "詔去雲無信，歸來鶴相識。", "半病奪牛公，全慵捕魚客。", "少微光一點，落此芒磔索。", "釋子問池塘，門人廢幽賾。", "堪悲東序寶，忽變西方籍。", "不見步兵詩，空懷康樂屐。"]'),
('12b1c09c-67db-47cb-becf-3bab54672f16','寂上人院聯句','皮日休','唐','唐诗','tang','','[]','癭牀空默坐，清景不知斜。',144,'全唐诗/poet.tang.43000.json','["癭牀空默坐，清景不知斜。", "暗數菩提子，閑看薜茘花。", "有情惟墨客，無語是禪家。", "背日聊依桂，嘗泉欲試茶。", "石形蹲玉虎，池影閃金蛇。", "經笥安巖匼，缾囊挂樹椏。", "書傳滄海外，龕寄白雲涯。", "竹色寒凌箔，燈光靜隔紗。", "趁幽飜小品，逐勝講南華。", "莎彩融黃露，蓮衣染素霞。", "水堪傷聚沫，風合落天葩。", "若許傳心印，何辭古堞賒。"]'),
('b2958440-f0ed-4aaa-9e85-197165673259','獨在開元寺避暑頗懷魯望因飛筆聯句','皮日休','唐','唐诗','tang','','[]','煩署雖難避，僧家自有期。',144,'全唐诗/poet.tang.43000.json','["煩署雖難避，僧家自有期。", "泉甘於馬乳，苔滑似龍漦。", "任誕襟全散，臨幽榻旋移。", "松行將雅拜，篁陣欲交麾。", "望塔青𩩉識，登樓白鴿知。", "石經森欲動，珠像儼將怡。", "筠簟臨杉穗，紗巾透雨絲。", "靜譚蟬噪少，涼步鶴隨遲。", "煙重迴蕉扇，輕風拂桂帷。", "對碑吳地說，開卷梵天詞。", "積水魚梁壞，殘花病枕欹。", "懷君瀟灑處，孤夢繞罘罳。"]'),
('048624af-09cd-4637-820a-917a9eb1bc4a','寒夜文宴聯句','皮日休','唐','唐诗','tang','','[]','文星今夜聚，應在斗牛間。',120,'全唐诗/poet.tang.43000.json','["文星今夜聚，應在斗牛間。", "載石人方至，乘槎客未還。", "送觴繁露曲，徵句白雲顏。", "節奏惟聽竹，從容只話山。", "理窮傾祕藏，論猛折玄關。", "酃酒分中綠，巴箋擘處殷。", "清言聞後醒，強韻壓來艱。", "犀柄當風揖，瓊枝向月攀。", "松吟方㗫㗫，泉夢憶潺潺。", "一會文章草，昭明不可刪。"]'),
('9e72a645-d864-437f-be33-6d15dd640ec6','藥名聯句','皮日休','唐','唐诗','tang','','[]','爲待防風餅，須添薏苡杯。',144,'全唐诗/poet.tang.43000.json','["爲待防風餅，須添薏苡杯。", "香然柏子後，尊泛菊花來。", "石耳泉能洗，垣衣雨爲裁。", "從容犀局靜，斷續玉琴哀。", "白芷寒猶采，青箱醉尚開。", "馬銜衰草臥，烏啄蠹根迴。", "雨過蘭芳好，霜多桂末摧。", "朱兒應作粉，雲母詎成灰。", "藝可屠龍膽，家曾近燕胎。", "牆高牽薜茘，障輭撼玫瑰。", "鸓鼠啼書戶，蝸牛上研臺。", "誰能將藁本，封與玉泉才。"]'),
('d5cd830d-49e0-4f40-9a39-5c8eebbc2af3','寒夜聯句','陸龜蒙','唐','唐诗','tang','','[]','靜境揖神凝，寒華射林缺。',120,'全唐诗/poet.tang.43000.json','["靜境揖神凝，寒華射林缺。", "清知思緒斷，爽覺心源徹。", "高唱戛金奏，朗詠鏗玉節。", "我思方泬寥，君詞復淒切。", "況聞風篁上，擺落殘凍雪。", "寂爾萬籟清，皎然諸靄滅。", "西窗客無夢，南浦波應結。", "河光正如劒，月魄方似玦。", "短燼不禁挑，冷毫看欲折。", "何夕重相期，濁醪還爲設。"]'),
('99c5d9d3-a209-4bea-8308-dc8ddb05bfd3','開元寺樓看雨聯句','陸龜蒙','唐','唐诗','tang','','[]','海上風雨來，掀轟雜飛電。',288,'全唐诗/poet.tang.43000.json','["海上風雨來，掀轟雜飛電。", "登樓一凭檻，滿眼蛟龍戰。", "須臾造化慘，倏忽堪輿變。", "萬戶響戈鋋，千家披組練。", "羣飛拋輪石，雜下攻城箭。", "點急似摧胸，行斜如中面。", "細灑魂空冷，橫飄目能眩。", "垂檐珂珮喧，㩧瓦珠璣濺。", "無言九陔遠，瞬息馳應徧。", "密處正垂絚，微時又懸綫。", "寫作玉界破，吹爲羽林旋。", "飜傷列缺勞，却怕豐隆倦。", "遙瞻山露色，漸覺雲成片。", "遠樹欲鳴蟬，深檐尚藏燕。", "殘雷隱轔盡，反照依微見。", "天光潔似磨，湖彩熟於練。", "疎帆逗前渚，晚磬分涼殿。", "接思強揮毫，窺詞幾焚研。", "佶栗烏皮几，輕明白羽扇。", "畢景好疎吟，餘涼可清宴。", "君攜下高磴，僧引還深院。", "駮蘚淨鋪筵，低松濕垂鬋。", "齋明乍虛豁，林霽逾蔥蒨。", "早晚重登臨，欲去多離戀。"]'),
('3b15f6a0-dbba-497f-85ae-e7707462b28c','報恩寺南池聯句','陸龜蒙','唐','唐诗','tang','','[]','古岸涵碧落，虛軒明素波。',168,'全唐诗/poet.tang.43000.json','["古岸涵碧落，虛軒明素波。", "坐來魚陣變，吟久菊□多。", "秋草分杉露，危橋下竹坡。", "遠峰青髻竝，□□□髯和。", "趙論寒仍講，支硎僻亦過。", "齋心曾養鶴，揮翰好邀鵝。", "倚石收奇藥，臨溪藉淺莎。", "桂花晴似拭，荷鏡曉如磨。", "翠出牛頭聳，苔深馬跡跛。", "繖欹從野醉，巾側任田歌。", "跁跒松形矮，般跚檜樾矬。", "香飛僧印火，泉急使鑣珂。", "菱鈿真堪帖，蓴絲亦好拖。", "幾時無一事，相伴著煙蘿。"]'),
('ceb2ea65-f2ec-485f-9d4b-98de5ed0cd88','天台禪院聯句','安守範','唐','唐诗','tang','','[]','偶到天台院，因逢物外僧。',48,'全唐诗/poet.tang.43000.json','["偶到天台院，因逢物外僧。", "忘機同一祖，出語離三乘。", "樹老中庭寂，窗虛外境澄。", "片時松影下，聯續百千燈。"]'),
('4d24662a-0f13-4c53-88e8-b469e73accfc','講德聯句','清晝','唐','唐诗','tang','','[]','先王設位，以正邦國。',240,'全唐诗/poet.tang.43000.json','["先王設位，以正邦國。", "建立大官，封植有德。", "二南敷化，四岳述職。", "其言不朽，其儀不忒。", "暨於嬴劉，乃創程式。", "罷侯置守，剖竹分域。", "赫矣皇唐，康哉立極。", "精選藩翰，庸資正直。", "爰命我公，東土作則。", "克己恭儉，疲人休息。", "濟濟閭閈，油油黍稷。", "既富既教，足兵足食。", "恤其凋瘵，剪其荆棘。", "威懷逋叛，撲滅蝥賊。", "疾惡如讐，聞善不惑。", "哀矜鰥寡，旌禮儒墨。", "乃修隄防，乃濬溝洫。", "以利通商，以溉嘉穀。", "徵賦以節，計功以時。", "人胥懷惠，吏不能欺。", "我政載孚，我邦載綏。", "猛獸不暴，嘉魚維滋。", "肅恭明神，齊沐不虧。", "歲或驕陽，雨無愆期。"]'),
('73e0f126-bbe7-478b-8b6f-a9df1d75f331','講古文聯句','清晝','唐','唐诗','tang','','[]','帝出於震，文明始敷。',240,'全唐诗/poet.tang.43000.json','["帝出於震，文明始敷。", "山岳降氣，龜龍負圖。", "爰有書契，乃立典謨。", "先知孔聖，飛步天衢。", "漢承秦弊，尊儒尚學。", "百氏六經，九流七略。", "屈宋接武，班馬繼作。", "或頌燕然，或贊麟閣。", "降及三祖，始變二雅。", "仲宣閑和，公幹蕭灑。", "士衡安仁，不史不野。", "左張精奧，嵇阮高寡。", "暨于江表，其文鬱興。", "綺麗爭發，繁蕪則懲。", "詞曄春華，思清冬冰。", "景純跌宕，遊仙獨步。", "青雲其情，白璧其句。", "靈運山水，實多奇趣。", "遠派孤峰，龍騰鳳翥。", "陶令田園，匠意真直。", "春柳寒松，不凋不飾。", "江淹雜體，方見才力。", "擬之信工，似而不逼。", "鮑昭從軍，主意危苦。"]'),
('29948fcb-610b-4702-96d0-183b8bf69375','項王古祠聯句','清晝','唐','唐诗','tang','','[]','遺廟風塵積，荒途歲月侵。',72,'全唐诗/poet.tang.43000.json','["遺廟風塵積，荒途歲月侵。", "英靈今寂寞，容衛尚森沈。", "霸楚志何在，平秦功亦深。", "諸侯歸復背，青史古將今。", "星聚分已定，天亡力豈任。", "采蘩如可薦，舉酒瀝空林。"]'),
('aaa6498e-9cec-4447-afb2-c66bec5eb14a','還丹可成詩聯句','清晝','唐','唐诗','tang','','[]','羽化自仙骨，延年資養生。',144,'全唐诗/poet.tang.43000.json','["羽化自仙骨，延年資養生。", "金經啓靈秘，玉液流至精。", "八石思共煉，九丹知可成。", "吾心苟無妄，神理期合幷。", "封竈用六一，置門考休京。", "浮光含日彩，圓質煥雲英。", "持此保壽命，服之頤性情。", "跂予望仙侶，高詠昇天行。", "鶴駕方可致，霓裳定將迎。", "不因五色藥，安著七真名。", "揮妙在微密，全功知感誠。", "與君棄城市，攜手遊蓬瀛。"]'),
('4ca14765-40a4-4d02-8a76-ebdbe9d4be0e','建安寺西院喜王郎中遘恩命初至聯句','清晝','唐','唐诗','tang','','[]','跡就空門退，官從畫省遷。',72,'全唐诗/poet.tang.43000.json','["跡就空門退，官從畫省遷。", "住持良有願，朝謁宂無緣。", "身淨金繩內，心馳玉扆前。", "榮添一兩日，恩降九霄年。", "慕法能輕冕，追非欲佩弦。", "棲閑那可久，鴛鷺待行聯。"]'),
('0f407363-934c-4a6c-9976-49b1d57b33cb','建安寺夜會對雨懷皇甫侍御曾聯句','清晝','唐','唐诗','tang','','[]','相思非是遠，風雨遣情多。',72,'全唐诗/poet.tang.43000.json','["相思非是遠，風雨遣情多。", "願欲披雲見，難堪候曉過。", "夜長同歲月，地近極山河。", "戒相初傳授，文章舊切磋。", "時稱洛下詠，人許郢中歌。", "惆悵徒延首，其如一水何。"]'),
('c360fd75-008f-4049-a291-ba3fbaa680e2','泛長城東溪暝宿崇光寺寄處士陸羽聯句','清晝','唐','唐诗','tang','','[]','箬水青似箬，玉山碧於玉。',168,'全唐诗/poet.tang.43000.json','["箬水青似箬，玉山碧於玉。", "逼霄沓萬狀，截地分千曲。", "萍解深可窺，林豁遙在矚。", "已高物外賞，稍滌區中欲。", "野鶴翔又飛，世人羈且跼。", "沈吟跡所悞，放浪心自足。", "緬懷虛舟客，願寄生芻束。", "說詩整頹波，立義激浮俗。", "荆吳備登歷，風土隨編錄。", "恨與清景別，擬教長路促。", "溪鳥語鸝嘍，寺花翻躑躅。", "印圍水壇淨，香護蓮衣觸。", "捧經啓紗燈，收袵禮金粟。", "安得扣關子，玄言對吾屬。"]'),
('7692dc34-e8a1-4f8a-9d6e-d81a9078648b','與崔子向泛舟自招橘經箬里宿天居寺憶李侍御㟧渚山春遊後期不及聯一十六韻以寄之','清晝','唐','唐诗','tang','','[]','晴日春態深，寄遊恣所適。',192,'全唐诗/poet.tang.43000.json','["晴日春態深，寄遊恣所適。", "寧妨花木亂，轉學心耳寂。", "取性憐鶴高，謀閑任山僻。", "倚舷息空曲，捨屨行淺磧。", "渚箬入里逢，野梅到村摘。", "碑殘飛雉嶺，井翳潛龍宅。", "壞寺鄰壽陵，古壇留劫石。", "穿階筍節露，拂瓦松梢碧。", "天界細雲還，墙陰雜英積。", "懸燈寄前焰，遙月昇圓魄。", "何意清夜期，坐爲高峰隔。", "茗園可交袂，藤澗好停錫。", "微雨聽濕巾，迸流從點席。", "戲猨隔枝透，驚鹿逢人躑。", "覩物賞已奇，感時思彌極。", "芳菲如馳箭，望望共君惜。"]'),
('e6868844-ddae-466b-8960-c0449d267c82','渚山春暮會顧丞茗舍聯句效小庾體','清晝','唐','唐诗','tang','','[]','誰是惜暮人，相攜送春日。',144,'全唐诗/poet.tang.43000.json','["誰是惜暮人，相攜送春日。", "因君過茗舍，留客開蘭室。", "濕苔滑行屐，柔草低藉瑟。", "鵲喜語成雙，花狂落非一。", "煙濃山焙動，泉破水舂疾。", "莫抝挂瓢枝，會移閬書帙。", "頗容樵與隱，豈聞禪兼律。", "欄竹不求疎，網藤從更密。", "池添逸少墨，園雜莊生漆。", "景晏枕猶欹，酒醒頭懶櫛。", "雲教淡機慮，地可遺名實。", "應待御荈青，幽期踏芳出。"]'),
('0c3b38ad-a51b-4643-87f9-0007794803f8','與李司直令從荻塘聯句','清晝','唐','唐诗','tang','','[]','畫舸悠悠荻塘路，真僧與我相隨去。',128,'全唐诗/poet.tang.43000.json','["畫舸悠悠荻塘路，真僧與我相隨去。", "寒花似菊不知名，霜葉如楓是何樹。", "倦客經秋夜共歸，情多語盡明相顧。", "遙城候騎來仍少，傍嶺哀猨發無數。", "心閑清淨得禪寂，興逸縱橫問章句。", "蟲聲切切草間悲，螢影紛紛月前度。", "撩亂雲峰好賦詩，嬋娟水月堪爲喻。", "與君出處本不同，從此還依舊山住。"]'),
('70c2f932-1002-4d29-8d2a-a50a7b333090','遠意聯句','清晝','唐','唐诗','tang','','[]','家在炎州往朔方，豈知于闐望瀟湘。',64,'全唐诗/poet.tang.43000.json','["家在炎州往朔方，豈知于闐望瀟湘。", "曾經隴底復遼陽，更憶東去採扶桑。", "楂客三千路未央，燭龍之地日無光。", "將遊莽蒼窮大荒，車轍馬足逐周王。"]'),
('e468df90-3866-41f4-a47a-be0df85ae38f','暗思聯句','清晝','唐','唐诗','tang','','[]','斜風飄雨三十夜，隣女餘光不相借。',32,'全唐诗/poet.tang.43000.json','["斜風飄雨三十夜，隣女餘光不相借。", "跡滅塵生古人畫，洞房重扉無隟罅。"]'),
('602ea61b-bb96-4812-a74c-7cd2e37ce998','樂意聯句一首','清晝','唐','唐诗','tang','','[]','良朋益友自遠來，萬里鄉書對酒開。',41,'全唐诗/poet.tang.43000.json','["良朋益友自遠來，萬里鄉書對酒開。", "子孫蔓衍負奇才，承顏弄鳥詠南陔。", "鼓腹擊壤歌康哉！。"]'),
('376cf4d7-6267-4c32-a985-81a3ab4e8c22','恨意聯句','清晝','唐','唐诗','tang','','[]','同心同縣不相見，獨采蘼蕪詠團扇。',48,'全唐诗/poet.tang.43000.json','["同心同縣不相見，獨采蘼蕪詠團扇。", "莫聽東隣擣霜練，遠憶征人淚如霰。", "長信空階荒草遍，明妃初別昭陽殿。"]'),
('ee049069-51b7-4a78-90f6-ee9e92fead64','秋日盧郎中使君幼平泛舟聯句一首','清晝','唐','唐诗','tang','','[]','共載清秋客船，同瞻皂蓋朝天。',98,'全唐诗/poet.tang.43000.json','["共載清秋客船，同瞻皂蓋朝天。", "悔使比來相得，如今欲別潸然。", "漸驚徒馭分散，愁望雲山接連。", "魏闕馳心日日，吳城揮手年年。", "送遠已傷飛雁，裁詩更切嘶蟬。", "空懷鄠杜心醉，永望門欄脰捐。", "別思無窮無限，還如秋水秋煙。"]'),
('ea3d7bfe-2252-42ed-8efb-fb5a5ad07db5','重聯句一首','清晝','唐','唐诗','tang','','[]','相將惜別且遲遲，未到新豐欲醉時。',96,'全唐诗/poet.tang.43000.json','["相將惜別且遲遲，未到新豐欲醉時。", "去郡獨攜程氏酒，入朝可忘習家池。", "仍憐故吏依依戀，自有清光處處隨。", "晚景南徐何處宿，秋風北固不堪辭。", "吳中詩酒饒佳興，秦地關山引夢思。", "對酒已傷嘶馬去，銜恩只待掃門期。"]'),
('c1767154-bf52-46d9-b006-a675f3f16389','與潘述集湯衡宅懷李司直縱聯句','清晝','唐','唐诗','tang','','[]','幽獨何以慰，友人顧茅茨。',72,'全唐诗/poet.tang.43000.json','["幽獨何以慰，友人顧茅茨。", "已忘歲月念，載說清閑時。", "旭日舒朱槿，柔風引綠葹。", "迢迢青溪路，耿耿芳樹枝。", "執袵空躑躅，來城自逶迤。", "相思寄採掇，景晏獨驅馳。"]'),
('ecce1da3-7017-44f4-aa40-33d45e2bdad5','安吉崔明甫山院聯句一首','清晝','唐','唐诗','tang','','[]','人不擾，政已和。',32,'全唐诗/poet.tang.43000.json','["人不擾，政已和。", "世慮寡，山情多。", "禪客至，墨卿過。", "興既洽，情如何。"]'),
('af646dbf-0f1e-4333-aea2-fd40e7ac6e3a','重聯句一首','清晝','唐','唐诗','tang','','[]','肅肅清院，翛翛碧鮮。',40,'全唐诗/poet.tang.43000.json','["肅肅清院，翛翛碧鮮。", "已見心遠，何關地偏。", "自公退食，升堂草玄。", "紛紛已隔，雲心澹然。"]'),
('ea3b915e-8ed6-44f2-ab79-68f74f3c94d4','重聯句一首','清晝','唐','唐诗','tang','','[]','瀑溜聞窗外，晴風逼座間。',24,'全唐诗/poet.tang.43000.json','["瀑溜聞窗外，晴風逼座間。", "挂冠徒有意，芳桂杳難攀。"]'),
('8065e9aa-32cd-4342-b1f0-81973c4af66f','重聯句一首','清晝','唐','唐诗','tang','','[]','清高素非宦侶，疎散從來道流。',56,'全唐诗/poet.tang.43000.json','["清高素非宦侶，疎散從來道流。", "今日還輕墨綬，知君意在滄洲。", "浮雲任從飄蕩，寄隱也信沈浮。", "不似漳南地僻，道安爲我淹留。"]'),
('c3a865b0-5636-43b4-b4c6-fe45689317d3','重聯句一首','清晝','唐','唐诗','tang','','[]','劉令興多常步履，柴桑事少但援琴。',64,'全唐诗/poet.tang.43000.json','["劉令興多常步履，柴桑事少但援琴。", "閑招法侶從山寺，每掇幽芳傍竹林。", "卷簾只愛荆峰色，入坐偏宜郢客吟。", "誰許近來輕印綬，因君昨日悟禪心。"]'),
('5f415cc5-04ce-4d46-b74f-e956ea07b324','道觀中和潘丞觀青溪圖聯句','清晝','唐','唐诗','tang','','[]','畫得青溪樣，宜於紫府觀。',48,'全唐诗/poet.tang.43000.json','["畫得青溪樣，宜於紫府觀。", "日明煙靄薄，風落水容寬。", "畫野高低接，商工井邑攢。", "疏川因稼穡，出使問艱難。"]'),
('af83c5e6-a0af-469a-adbf-74198bc442b7','春日對雨聯句一首','清晝','唐','唐诗','tang','','[]','春煙帶微雨，漠漠連城邑。',144,'全唐诗/poet.tang.43000.json','["春煙帶微雨，漠漠連城邑。", "桐葉生微陰，桃花更宜濕。", "蕭條暗楊柳，散漫下原隰。", "歸路不我從，遙心空佇立。", "林低山影近，岸轉水流急。", "芳草自堪遊，白雲如可揖。", "尋山禪客意，苦雨陶公什。", "遊衍情未終，歸飛暮相及。", "峰高日色轉，潭淨天光入。", "却欲學神仙，空思謝朋執。", "爲道貴逍遙，趍時多苦集。", "瓊英若可飱，青紫徒勞拾。"]'),
('8caf899a-3988-4d77-8845-6f3d90300cf5','春日會韓武康章後亭聯句','清晝','唐','唐诗','tang','','[]','後園堪寄賞，日日對春風。',120,'全唐诗/poet.tang.43000.json','["後園堪寄賞，日日對春風。", "客位繁陰下，公牆細柳中。", "坐看青嶂遠，心與白雲同。", "林暗花煙入，池深遠水通。", "井桃新長蘂，欄藥未成叢。", "松竹宜禪客，山泉入謝公。", "砌香翻芍藥，簷靜倚梧桐。", "外慮宜簾卷，忘情與道空。", "楚僧招惠遠，蜀客挹楊雄。", "便寄柴桑隱，何勞訪剡東。"]'),
('c72857a4-1806-4af6-806d-de660cc4cda1','康錄事宅送僧聯句','清晝','唐','唐诗','tang','','[]','蓮衣宜著雨，竹錫好隨雲。',24,'全唐诗/poet.tang.43000.json','["蓮衣宜著雨，竹錫好隨雲。", "見鶴還應養，逢鷗自作羣。"]'),
('658b06d0-8baa-425c-9fba-edd48eadf149','與邢端公李台題庭石聯句','清晝','唐','唐诗','tang','','[]','共題詩句遍，爭坐蘚文稀。',12,'全唐诗/poet.tang.43000.json','["共題詩句遍，爭坐蘚文稀。"]'),
('041b8c0f-c5e7-48ad-bc12-dc3dd81b74a0','冬日建安寺西院喜晝公自吳興至聯句一首','清晝','唐','唐诗','tang','','[]','宗系傳康樂，精修學遠公。',72,'全唐诗/poet.tang.43000.json','["宗系傳康樂，精修學遠公。", "相尋當暮歲，行李犯寒風。", "累積浮生裏，機慙半偈中。", "傳家知業墜，繼祖忝聲同。", "雲與輕帆至，山將本寺空。", "向來忘起滅，留我宿花宮。"]'),
('facca95a-e528-4bd4-9a92-f227f68202aa','秋日潘述自長城至霅上與晝公湯評事遊集累日時司直李公瑕往蘇州有阻良會因與二公聯句以寄之','清晝','唐','唐诗','tang','','[]','離念非前期，秋風忽已至。',84,'全唐诗/poet.tang.43000.json','["離念非前期，秋風忽已至。", "芸黃衆芳晚，搖蕩居人思。", "白霜淒以積，高梧颯而墜。", "悠然越山川，復此恨離異。", "時景易遷謝，懽□難兼遂。", "惜分緩迴舟，懷遙企歸駟。", "休澣情自高，來思日云未。"]'),
('e5a7c702-6006-4e89-aa92-08fc28a65494','喜晝公尋山迴相遇聯句一首','清晝','唐','唐诗','tang','','[]','幾年無此會，今日喜相從。',48,'全唐诗/poet.tang.43000.json','["幾年無此會，今日喜相從。", "後夏仍多病，前書達幾封。", "水華迎暮雨，松吹引疎鐘。", "出谷隨初月，尋僧說五峰。"]'),
('7b1edf3b-2939-40c4-be65-259d560bb55c','送晝公聯句','清晝','唐','唐诗','tang','','[]','相逢情不厭，惜別意難爲。',96,'全唐诗/poet.tang.43000.json','["相逢情不厭，惜別意難爲。", "吾道應無住，前期未可知。", "輕霜凋古木，寒水縮荒陂。", "賓雁依沙嶼，浮雲慘路岐。", "林疎看野迥，岸轉覺山移。", "寄賞驚搖落，歸心歎別離。", "草堂思偃蹇，麈尾去相隨。", "勿謂光陰遠，禪房會一窺。"]'),
('18fc8b41-2a36-47ce-8e22-09db3143aa9a','與羅隱之聯句','鄭遨','唐','唐诗','tang','','[]','一壺天上有名物，兩個世間無事人。',32,'全唐诗/poet.tang.43000.json','["一壺天上有名物，兩個世間無事人。", "醉却隱之雲叟外，不知何處是天真。"]'),
