('8da5f8c8-4b93-46cf-a3c6-88aaeed895c1','句','臨川小吏','唐','唐诗','tang','','[]','三月能辭千日醉，一生能得幾回看。',16,'全唐诗/poet.tang.43000.json','["三月能辭千日醉，一生能得幾回看。"]'),
('25a1d6e2-c8b1-4251-9f7c-6b1934db348a','句','韓熙載客','唐','唐诗','tang','','[]','最是五更留不住，向人枕畔著衣裳。',16,'全唐诗/poet.tang.43000.json','["最是五更留不住，向人枕畔著衣裳。"]'),
('86b91114-d63c-4d7e-9480-111771d66c9a','句','段義宗','唐','唐诗','tang','','[]','懸心秋夜月，萬里照鄉關。',44,'全唐诗/poet.tang.43000.json','["懸心秋夜月，萬里照鄉關。", "玉排複道珊瑚殿，金錯危椆翡翠樓。", "此花不與衆花同，爲感高僧護法功。"]'),
('1a6125bc-b864-4d6a-b16b-7cbfb86d4dcc','無名氏之散句','無名氏','唐','唐诗','tang','','[]','都來消帝力，全不用兵防。',288,'全唐诗/poet.tang.43000.json','["都來消帝力，全不用兵防。", "道遠擎空鉢，深山踏落花。", "船中江上景，晚泊早行時。", "山寺鐘樓月，江城鼓角風。", "雨過花爭出，雲空月半生。", "鳥正啼隋柳，人須入楚山。", "高松飄雨雪，一室掩香燈。", "遂有冥心者，還尋此境來。", "又因風雨夜，重到古松門。", "道晦金雞伏，時來木馬鳴。", "誰來看山寺，自去掃松門。", "此生還自喜，餘事不相侵。", "白鬢無心鑷，青山得意多。", "一春能幾日，無雨亦多風。", "苦雨秋濤漲，狂風野燒翻。", "須知三尺劍，只爲不平磨。", "要路爭先進，閑門肯暫過。", "已難消永夜，況復聽秋霖。", "大雪路亦宿，深山水也吞。", "卷簾黃葉落，鏁印子規啼。", "亡國空流水，孤祠掩落花。", "山魅隔窗舞，鵩鳥入簾飛。", "萬里八九月，一身西北風。", "磴危攀薜荔，石滑疎莓苔。"]'),
('ff686ccf-4c4b-4ab6-850a-9903cf1ca49b','離別難','武后宮人','唐','唐诗','tang','','[]','此別難重陳，花飛復戀人。',48,'全唐诗/poet.tang.43000.json','["此別難重陳，花飛復戀人。", "來時梅覆雪，去日柳含春。", "物候催行客，歸途淑氣新。", "剡川今已遠，魂夢暗相親。"]'),
('18e47a78-465f-4459-8acf-e344b9139445','袍中詩','開元宮人','唐','唐诗','tang','','[]','沙場征戍客，寒苦若爲眠。',48,'全唐诗/poet.tang.43000.json','["沙場征戍客，寒苦若爲眠。", "戰袍經手作，知落阿誰邊。", "蓄意多添線，含情更著綿。", "今生已過也，結取後生緣。"]'),
('d2d9fa8e-5872-480a-ad45-b1b62af3619a','題洛苑梧葉上','天寶宮人','唐','唐诗','tang','','[]','舊寵悲秋扇，新恩寄早春。',24,'全唐诗/poet.tang.43000.json','["舊寵悲秋扇，新恩寄早春。", "聊題一片葉，將寄接流人。"]'),
('71077c12-3f1e-40bc-b453-2fa73f3be4aa','又題洛苑梧葉上','天寶宮人','唐','唐诗','tang','','[]','一葉題詩出禁城，誰人酬和獨含情。',32,'全唐诗/poet.tang.43000.json','["一葉題詩出禁城，誰人酬和獨含情。", "自嗟不及波中葉，蕩漾乘春取次行。"]'),
('2cd54f56-4ee1-4e91-827b-d6874acd09b2','題花葉詩','德宗宮人','唐','唐诗','tang','','[]','一入深宮裏，無由得見春。',24,'全唐诗/poet.tang.43000.json','["一入深宮裏，無由得見春。", "題詩花葉上，寄與接流人。"]'),
('50ec05b8-7d2f-4fe9-b430-3192a631661b','題紅葉','宣宗宮人','唐','唐诗','tang','','[]','流水何太急，深宮盡日閑。',24,'全唐诗/poet.tang.43000.json','["流水何太急，深宮盡日閑。", "殷勤謝紅葉，好去到人間。"]'),
('16a3b6dc-330d-40ed-8745-330e6be43447','金鎖詩','僖宗宮人','唐','唐诗','tang','','[]','玉燭製袍夜，金刀呵手裁。',24,'全唐诗/poet.tang.43000.json','["玉燭製袍夜，金刀呵手裁。", "鎖寄千里客，鎖心終不開。"]'),
('6ccb9964-33a0-4f10-9f05-a329230f87a9','隨駕遊青城','李舜弦','唐','唐诗','tang','','[]','因隨八馬上仙山，頓隔塵埃物象閑。',32,'全唐诗/poet.tang.43000.json','["因隨八馬上仙山，頓隔塵埃物象閑。", "只恐西追王母宴，却憂難得到人間。"]'),
('1fdc3682-bfe8-409c-86b5-e50451643c6b','蜀宮應制','李舜弦','唐','唐诗','tang','','[]','濃樹禁花開後庭，飲筵中散酒微醒。',32,'全唐诗/poet.tang.43000.json','["濃樹禁花開後庭，飲筵中散酒微醒。", "濛濛雨草瑤階溼，鐘曉愁吟獨倚屏。"]'),
('1d9f6363-173c-4bf8-b124-d154ad6f4694','釣魚不得','李舜弦','唐','唐诗','tang','','[]','盡日池邊釣錦鱗，芰荷香裏暗消魂。',32,'全唐诗/poet.tang.43000.json','["盡日池邊釣錦鱗，芰荷香裏暗消魂。", "依稀縱有尋香餌，知是金鉤不肯吞。"]'),
('9dafb0d6-94c1-4eeb-b795-bf3e74ee3f12','宮詞','李玉簫','唐','唐诗','tang','','[]','鴛鴦瓦上瞥然聲，晝寢宮娥夢裏驚。',32,'全唐诗/poet.tang.43000.json','["鴛鴦瓦上瞥然聲，晝寢宮娥夢裏驚。", "元是我王金彈子，海棠花下打流鶯。"]'),
('d1004be4-46d5-429b-9ae1-435191c5c1cc','太平詩','金真德','唐','唐诗','tang','','[]','大唐開鴻業，巍巍皇猷昌。',120,'全唐诗/poet.tang.43000.json','["大唐開鴻業，巍巍皇猷昌。", "止戈戎衣定，修文繼百王。", "統天崇雨施，理物體含章。", "深仁諧日月，撫運邁時康。", "幡旗既赫赫，鉦鼓何鍠鍠。", "外夷違命者，翦覆被大殃。", "和風凝宇宙，遐邇競呈祥。", "四時調玉燭，七曜巡萬方。", "維嶽降宰輔，維帝用忠良。", "三五咸一德，昭我皇家唐。"]'),
('34aabcf6-f33a-4d3b-8f64-a4e3c1c631c3','句','寶曆宮人','唐','唐诗','tang','','[]','寶帳香重重，一雙紅芙蓉。',12,'全唐诗/poet.tang.43000.json','["寶帳香重重，一雙紅芙蓉。"]'),
('b0e68e7b-b6ee-46ff-8ac7-702e23414bb6','宮詞 一','花蕊夫人徐氏','唐','唐诗','tang','','[]','五雲樓閣鳳城間，花木長新日月閑。',32,'全唐诗/poet.tang.43000.json','["五雲樓閣鳳城間，花木長新日月閑。", "三十六宮連內苑，太平天子住崑山。"]'),
('248c8d76-79f4-4eec-85d2-787450337820','宮詞 二','花蕊夫人徐氏','唐','唐诗','tang','','[]','會真廣殿約宮牆，樓閣相扶倚太陽。',32,'全唐诗/poet.tang.43000.json','["會真廣殿約宮牆，樓閣相扶倚太陽。", "淨甃玉階橫水岸，御爐香氣撲龍牀。"]'),
('85c09fb6-e343-437b-b967-43c186bbbd21','宮詞 三','花蕊夫人徐氏','唐','唐诗','tang','','[]','龍池九曲遠相通，楊柳絲牽兩岸風。',32,'全唐诗/poet.tang.43000.json','["龍池九曲遠相通，楊柳絲牽兩岸風。", "長似江南好風景，畫船來去碧波中。"]'),
('40caafff-5129-45fd-b9b6-a5c3501231b6','宮詞 四','花蕊夫人徐氏','唐','唐诗','tang','','[]','東內斜將紫禁通，龍池鳳苑夾城中。',32,'全唐诗/poet.tang.43000.json','["東內斜將紫禁通，龍池鳳苑夾城中。", "曉鐘聲斷嚴妝罷，院院紗窗海日紅。"]'),
('e0c34c15-54bc-46fa-a176-61985afd55b3','宮詞 五','花蕊夫人徐氏','唐','唐诗','tang','','[]','殿名新立號重光，島上亭臺盡改張。',32,'全唐诗/poet.tang.43000.json','["殿名新立號重光，島上亭臺盡改張。", "但是一人行幸處，黃金閣子鎖牙牀。"]'),
('0cddbb9e-766e-4e82-b2ef-004211eea6a3','宮詞 六','花蕊夫人徐氏','唐','唐诗','tang','','[]','夾城門與內門通，朝罷巡遊到苑中。',32,'全唐诗/poet.tang.43000.json','["夾城門與內門通，朝罷巡遊到苑中。", "每日日高祗候處，滿堤紅豔立春風。"]'),
('8923a856-4edb-4529-8be2-492e398640cf','宮詞 七','花蕊夫人徐氏','唐','唐诗','tang','','[]','廚船進食簇時新，侍宴無非列近臣。',32,'全唐诗/poet.tang.43000.json','["廚船進食簇時新，侍宴無非列近臣。", "日午殿頭宣索鱠，隔花催喚打魚人。"]'),
('df9ffa54-6b61-4ae1-89f6-616c8b15da28','宮詞 八','花蕊夫人徐氏','唐','唐诗','tang','','[]','立春日進內園花，紅蕊輕輕嫩淺霞。',32,'全唐诗/poet.tang.43000.json','["立春日進內園花，紅蕊輕輕嫩淺霞。", "跪到玉階猶帶露，一時宣賜與宮娃。"]'),
('84659c6c-c707-4f17-9df2-aa892fb5b57e','宮詞 九','花蕊夫人徐氏','唐','唐诗','tang','','[]','三面宮城盡夾牆，苑中池水白茫茫。',32,'全唐诗/poet.tang.43000.json','["三面宮城盡夾牆，苑中池水白茫茫。", "直從獅子門前入，旋見亭臺遶岸傍。"]'),
('a76cfded-dd13-4e10-9879-b9986bfa6479','宮詞 十','花蕊夫人徐氏','唐','唐诗','tang','','[]','離宮別院遶宮城，金版輕敲合鳳笙。',32,'全唐诗/poet.tang.43000.json','["離宮別院遶宮城，金版輕敲合鳳笙。", "夜夜月明花樹底，傍池長有按歌聲。"]'),
('49c4ade2-3c03-43b7-a436-c68a466222e7','宮詞 十一','花蕊夫人徐氏','唐','唐诗','tang','','[]','御製新翻曲子成，六宮纔唱未知名。',32,'全唐诗/poet.tang.43000.json','["御製新翻曲子成，六宮纔唱未知名。", "盡將觱篥來抄譜，先按君王玉笛聲。"]'),
('fb749e60-9a7b-47ab-89d3-417862aa13c5','宮詞 十二','花蕊夫人徐氏','唐','唐诗','tang','','[]','旋移紅樹斲新苔，宣使龍池更鑿開。',32,'全唐诗/poet.tang.43000.json','["旋移紅樹斲新苔，宣使龍池更鑿開。", "展得綠波寬似海，水心樓殿勝蓬萊。"]'),
('55935bb7-f84b-42f2-8830-b523fff9e21d','宮詞 十三','花蕊夫人徐氏','唐','唐诗','tang','','[]','太虛高閣凌虛殿，背倚城牆面枕池。',32,'全唐诗/poet.tang.43000.json','["太虛高閣凌虛殿，背倚城牆面枕池。", "諸院各分娘子位，羊車到處不教知。"]'),
('1bf754a5-ebf0-4ef3-874a-df35b53f255b','宮詞 十四','花蕊夫人徐氏','唐','唐诗','tang','','[]','修儀承寵住龍池，掃地焚香日午時。',32,'全唐诗/poet.tang.43000.json','["修儀承寵住龍池，掃地焚香日午時。", "等候大家來院裏，看教鸚鵡念新詩。"]'),
('ee6b11ed-3b5b-421e-83bd-cb093aaf78c5','宮詞 十五','花蕊夫人徐氏','唐','唐诗','tang','','[]','才人出入每參隨，筆硯將行遶曲池。',32,'全唐诗/poet.tang.43000.json','["才人出入每參隨，筆硯將行遶曲池。", "能向彩箋書大字，忽防御製寫新詩。"]'),
('a0ce5d58-e64e-4569-b749-a30cfc26a057','宮詞 十六','花蕊夫人徐氏','唐','唐诗','tang','','[]','六宮官職總新除，宮女安排入畫圖。',32,'全唐诗/poet.tang.43000.json','["六宮官職總新除，宮女安排入畫圖。", "二十四司分六局，御前頻見錯相呼。"]'),
('32120a22-ff49-4fb9-8518-9c5f11fcaeca','宮詞 十七','花蕊夫人徐氏','唐','唐诗','tang','','[]','春風一面曉妝成，偷折花枝傍水行。',32,'全唐诗/poet.tang.43000.json','["春風一面曉妝成，偷折花枝傍水行。", "却被內監遙覷見，故將紅豆打黃鶯。"]'),
('654404eb-2ef9-494b-aeba-e142d003a53f','宮詞 十八','花蕊夫人徐氏','唐','唐诗','tang','','[]','殿前排宴賞花開，宮女侵晨探幾回。',32,'全唐诗/poet.tang.43000.json','["殿前排宴賞花開，宮女侵晨探幾回。", "斜望花開遙舉袖，傳聲宣喚近臣來。"]'),
('1d0a6499-4d0b-4de2-96ef-783ccc74bbd3','宮詞 十九','花蕊夫人徐氏','唐','唐诗','tang','','[]','小毬場近曲池頭，宣喚勳臣試打毬。',32,'全唐诗/poet.tang.43000.json','["小毬場近曲池頭，宣喚勳臣試打毬。", "先向畫樓排御幄，管絃聲動立浮油。"]'),
('d1d2f5d3-9e7a-46f4-b89d-0867d8ed1797','宮詞 二十','花蕊夫人徐氏','唐','唐诗','tang','','[]','供奉頭籌不敢爭，上棚等喚近臣名。',32,'全唐诗/poet.tang.43000.json','["供奉頭籌不敢爭，上棚等喚近臣名。", "內人酌酒纔宣賜，馬上齊呼萬歲聲。"]'),
('822d14a4-1c98-47d7-8913-857af3d27b28','宮詞 二十一','花蕊夫人徐氏','唐','唐诗','tang','','[]','殿前宮女總纖腰，初學乘騎怯又嬌。',32,'全唐诗/poet.tang.43000.json','["殿前宮女總纖腰，初學乘騎怯又嬌。", "上得馬來纔欲走，幾回拋鞚抱鞍橋。"]'),
('17e00c36-8e47-48a1-8126-f271ea47eea8','宮詞 二十二','花蕊夫人徐氏','唐','唐诗','tang','','[]','自教宮娥學打毬，玉鞍初跨柳腰柔。',32,'全唐诗/poet.tang.43000.json','["自教宮娥學打毬，玉鞍初跨柳腰柔。", "上棚知是官家認，遍遍長贏第一籌。"]'),
('a851e76d-9982-41f1-a67a-19f36de8f98f','宮詞 二十三','花蕊夫人徐氏','唐','唐诗','tang','','[]','翔鸞閣外夕陽天，樹影花光遠接連。',32,'全唐诗/poet.tang.43000.json','["翔鸞閣外夕陽天，樹影花光遠接連。", "望見內家來往處，水門斜過罨樓船。"]'),
('0c619599-1e16-455f-a361-a3b3448b50ec','宮詞 二十四','花蕊夫人徐氏','唐','唐诗','tang','','[]','內家追逐採蓮時，驚起沙歐兩岸飛。',32,'全唐诗/poet.tang.43000.json','["內家追逐採蓮時，驚起沙歐兩岸飛。", "蘭棹把來齊拍水，並船相鬬溼羅衣。"]'),
('8691e473-cdce-47ca-aee2-a81b29942d4b','宮詞 二十五','花蕊夫人徐氏','唐','唐诗','tang','','[]','新秋女伴各相逢，罨畫船飛別浦中。',32,'全唐诗/poet.tang.43000.json','["新秋女伴各相逢，罨畫船飛別浦中。", "旋折荷花伴歌舞，夕陽斜照滿衣紅。"]'),
('dca209ec-eaa3-453c-b63d-c8647d55f7d3','宮詞 二十六','花蕊夫人徐氏','唐','唐诗','tang','','[]','少年相逐採蓮回，羅帽羅衫巧製裁。',32,'全唐诗/poet.tang.43000.json','["少年相逐採蓮回，羅帽羅衫巧製裁。", "每到岸頭長拍水，競提纖手出船來。"]'),
('27071504-abb7-427a-8c4a-7bb8429d61ae','宮詞 二十七','花蕊夫人徐氏','唐','唐诗','tang','','[]','早春楊柳引長條，倚岸沿堤一面高。',32,'全唐诗/poet.tang.43000.json','["早春楊柳引長條，倚岸沿堤一面高。", "稱與畫船牽錦纜，暖風搓出綵絲縧。"]'),
