('c8a78b67-36f3-4d4e-b52a-28013dfe7677','宮詞 一五七','花蕊夫人徐氏','唐','唐诗','tang','','[]','窗窗戶戶院相當，總有珠簾玳瑁牀。',32,'全唐诗/poet.tang.43000.json','["窗窗戶戶院相當，總有珠簾玳瑁牀。", "雖道君王不來宿，帳中長是炷牙香。"]'),
('5923651a-6a7a-4f09-8b2b-b40ae5d0f5b2','述國亡詩','花蕊夫人徐氏','唐','唐诗','tang','','["\u7231\u56fd"]','君王城上豎降旗，妾在深宮那得知。',32,'全唐诗/poet.tang.43000.json','["君王城上豎降旗，妾在深宮那得知。", "十四萬人齊解甲，寧無一箇是男兒。"]'),
('86b5a7dd-165a-44d3-b6f3-06b381ddf34e','新妝詩','楊容華','唐','唐诗','tang','','[]','啼鳥驚眠罷，房櫳乘曉開。',48,'全唐诗/poet.tang.43000.json','["啼鳥驚眠罷，房櫳乘曉開。", "鳳釵金作縷，鸞鏡玉爲臺。", "妝似臨池出，人疑向月來。", "自憐終不見，欲去復裴回。"]'),
('99a38e7c-68df-4432-938a-38925d44330c','贈外','魏氏','唐','唐诗','tang','','[]','浮萍依綠水，弱蔦寄青松。',204,'全唐诗/poet.tang.43000.json','["浮萍依綠水，弱蔦寄青松。", "與君結大義，移天得所從。", "翰林無雙鳥，劒水不分龍。", "諧和類琴瑟，堅固同膠漆。", "義重恩欲深，夷險貴如一。", "本自身不令，積多嬰痛疾。", "朝夕倦牀枕，形體恥巾櫛。", "遊子倦風塵，從官初解巾。", "束裝赴南郢，脂駕出西秦。", "比翼終難遂，銜雌苦未因。", "徒悲楓岸遠，空對柳園春。", "男兒不重舊，丈夫多好新。", "新人喜新聘，朝朝臨粉鏡。", "兩鴛固無比，雙蛾誰與競。", "詎憐愁思人，銜啼嗟薄命。", "蕣華不足恃，松枝有餘勁。", "所願好九思，勿令虧百行。"]'),
('36de2690-e81e-47f5-8c68-89759bf3c62d','詠破簾','喬氏','唐','唐诗','tang','','[]','已漏風聲罷，繩持也不禁。',24,'全唐诗/poet.tang.43000.json','["已漏風聲罷，繩持也不禁。", "一從經落後，無復有貞心。"]'),
('febe0c8d-ba4a-4237-a6b2-60217f730bbb','送兄','七歲女子','唐','唐诗','tang','','["\u9001\u522b", "\u5199\u666f", "\u611f\u53f9"]','別路雲初起，離亭葉正飛。',24,'全唐诗/poet.tang.43000.json','["別路雲初起，離亭葉正飛。", "所嗟人異鴈，不作一行歸。"]'),
('56b4df17-a710-403f-833e-bb07e31937cf','送男左貶詩','林氏','唐','唐诗','tang','','[]','他日初投杼，勤王在飲冰。',96,'全唐诗/poet.tang.43000.json','["他日初投杼，勤王在飲冰。", "有辭期不罰，積毀竟相仍。", "謫宦今何在，銜冤猶未勝。", "天涯分越徼，驛騎速毘陵。", "腸斷腹非苦，書傳寫豈能。", "淚添江水遠，心劇海雲蒸。", "明月珠難識，甘泉賦可稱。", "但將忠報主，何懼點青蠅。"]'),
('5165fe9c-eb8f-43b4-a41e-30fa96c19d2e','古興 一','趙氏','唐','唐诗','tang','','[]','鬱蒸夏將半，暑氣扇飛閣。',72,'全唐诗/poet.tang.43000.json','["鬱蒸夏將半，暑氣扇飛閣。", "驟雨滿空來，當軒卷羅幕。", "度雲開夕霽，宇宙何清廓。", "明月流素光，輕風換炎鑠。", "孤鸞傷對影，寶瑟悲別鶴。", "君子去不還，遙心欲何託。"]'),
('6e0cd288-b30f-484a-a024-45a61bc07930','古興 二','趙氏','唐','唐诗','tang','','[]','金菊延清霜，玉壺多美酒。',48,'全唐诗/poet.tang.43000.json','["金菊延清霜，玉壺多美酒。", "良人猶不歸，芳菲豈常有。", "不惜芳菲歇，但傷別離久。", "含情罷斟酌，凝怨對窗牖。"]'),
('139c0e4f-780a-4837-9244-fefe2f900967','古興 三','趙氏','唐','唐诗','tang','','[]','霽雪舒長野，寒雲半幽谷。',72,'全唐诗/poet.tang.43000.json','["霽雪舒長野，寒雲半幽谷。", "嚴風振枯條，猨啼抱冰木。", "所嗟遊宦子，少小荷天祿。", "前程未云至，悽愴對車僕。", "歲寒成詠歌，日暮棲林樸。", "不憚行險道，空悲年運促。"]'),
('9a598058-c6a3-46f7-a640-f9ae0f7d9d5c','寄夫','郭紹蘭','唐','唐诗','tang','','[]','我壻去重湖，臨窗泣血書。',24,'全唐诗/poet.tang.43000.json','["我壻去重湖，臨窗泣血書。", "殷勤憑燕翼，寄與薄情夫。"]'),
('46d3c974-cf0b-406f-9fa2-5e4bed0392c6','同夫遊秦','王韞秀','唐','唐诗','tang','','[]','路掃飢寒跡，天哀志氣人。',24,'全唐诗/poet.tang.43000.json','["路掃飢寒跡，天哀志氣人。", "休零離別淚，攜手入西秦。"]'),
('1f0b25a6-6dd1-4adf-984d-a68fc2e99751','夫入相寄姨妹','王韞秀','唐','唐诗','tang','','[]','相國已隨麟閣貴，家風第一右丞詩。',32,'全唐诗/poet.tang.43000.json','["相國已隨麟閣貴，家風第一右丞詩。", "笄年解笑鳴機婦，恥見蘇秦富貴時。"]'),
('30eb9d67-9d1d-41e5-835e-3e3e48a10c14','喻夫阻客','王韞秀','唐','唐诗','tang','','[]','楚竹燕歌動畫梁，春蘭重換舞衣裳。',32,'全唐诗/poet.tang.43000.json','["楚竹燕歌動畫梁，春蘭重換舞衣裳。", "公孫開閣招嘉客，知道浮榮不久長。"]'),
('3be0d6ff-3bc2-40c5-9ffe-e4c52a36364e','古意','張夫人','唐','唐诗','tang','','[]','轆轤曉轉素絲綆，桐聲夜落蒼苔塼。',48,'全唐诗/poet.tang.43000.json','["轆轤曉轉素絲綆，桐聲夜落蒼苔塼。", "涓涓吹溜若時雨，濯濯佳蔬非用天。", "丈夫不解此中意，抱甕當時徒自賢。"]'),
('e786966d-f862-48a9-b4d4-c83986043b2b','拜新月','張夫人','唐','唐诗','tang','','[]','拜新月，拜月出堂前。',120,'全唐诗/poet.tang.43000.json','["拜新月，拜月出堂前。", "暗魄初籠桂，虛弓未引弦。", "拜新月，拜月妝樓上。", "鸞鏡始安臺，蛾眉已相向。", "拜新月，拜月不勝情，庭花風露清。", "月臨人自老，人望月長明。", "東家阿母亦拜月，一拜一悲聲斷絕。", "昔年拜月逞容輝，如今拜月雙淚垂。", "回看衆女拜新月，却憶紅閨年少時。"]'),
('133ea4a3-3f55-4c7c-ad31-5cd91d95577e','柳絮','張夫人','唐','唐诗','tang','','[]','靄靄芳春朝，雪絮起青條。',48,'全唐诗/poet.tang.43000.json','["靄靄芳春朝，雪絮起青條。", "或值花同舞，不因風自飄。", "過尊浮綠醑，拂幌綴紅綃。", "那用持愁翫，春懷不自聊。"]'),
('4c469973-b3dc-46ad-8b36-7c2f1a87875a','拾得韋氏花鈿以詩寄贈','張夫人','唐','唐诗','tang','','[]','今朝妝閣前，拾得舊花鈿。',48,'全唐诗/poet.tang.43000.json','["今朝妝閣前，拾得舊花鈿。", "粉汚痕猶在，塵侵色尚鮮。", "曾經纖手裏，拈向翠眉邊。", "能助千金笑，如何忍棄捐。"]'),
('a139233c-3f0e-4c5d-8558-a04a325dfd5b','誚喜鵲','張夫人','唐','唐诗','tang','','[]','疇昔鴛鴦侶，朱門賀客多。',24,'全唐诗/poet.tang.43000.json','["疇昔鴛鴦侶，朱門賀客多。", "如今無此事，好去莫相過。"]'),
('ffd905fa-df58-43a5-acdf-d5bd8786add6','句','張夫人','唐','唐诗','tang','','[]','遊蜂乍起驚落墀，黃鳥銜來却上枝。',40,'全唐诗/poet.tang.43000.json','["遊蜂乍起驚落墀，黃鳥銜來却上枝。", "臨風重回首，掩淚向庭花。", "鏡中春色老，枕前秋夜長。"]'),
('c24d6aa4-8171-4821-b560-19d4889e5995','書石壁','王氏','唐','唐诗','tang','','[]','何事潘郎戀別筵，歡情未斷妾心懸。',32,'全唐诗/poet.tang.43000.json','["何事潘郎戀別筵，歡情未斷妾心懸。", "汰王灘下相思處，猨叫山山月滿船。"]'),
('cd5d2bee-7b17-4b7f-af2b-f2e1840b3144','荅微之','裴淑','唐','唐诗','tang','','[]','侯門初擁節，御苑柳絲新。',48,'全唐诗/poet.tang.43000.json','["侯門初擁節，御苑柳絲新。", "不是悲殊命，唯愁別近親。", "黃鶯遷古木，朱履從清塵。", "想到千山外，滄江正暮春。"]'),
('aaf7bb38-5886-4d7a-8e0f-b569a2a91b36','夫下第','趙氏','唐','唐诗','tang','','[]','良人的的有奇才，何事年年被放回。',32,'全唐诗/poet.tang.43000.json','["良人的的有奇才，何事年年被放回。", "如今妾面羞君面，君若來時近夜來。"]'),
('d9edb62b-8ab0-468e-bcae-dee78ce204db','雜言寄杜羔','趙氏','唐','唐诗','tang','','[]','君從淮海遊，再過蘭杜秋。',100,'全唐诗/poet.tang.43000.json','["君從淮海遊，再過蘭杜秋。", "歸來未須臾，又欲向梁州。", "梁州秦嶺西，棧道與雲齊。", "羌蠻萬餘落，矛戟自高低。", "已念寡儔侶，復慮勞攀躋。", "丈夫重志氣，兒女空悲啼。", "臨邛滯遊地，肯顧濁水泥。", "人生賦命有厚薄，君但遨遊我寂寞。"]'),
('dd00995d-e299-4636-aaef-1e769b0e384b','聞夫杜羔登第','趙氏','唐','唐诗','tang','','[]','長安此去無多地，鬱鬱蔥蔥佳氣浮。',32,'全唐诗/poet.tang.43000.json','["長安此去無多地，鬱鬱蔥蔥佳氣浮。", "良人得意正年少，今夜醉眠何處樓。"]'),
('9967e41d-2fdc-4b5c-86f3-87909843bee6','雜言','趙氏','唐','唐诗','tang','','[]','上林園中青青桂，折得一枝好夫壻。',32,'全唐诗/poet.tang.43000.json','["上林園中青青桂，折得一枝好夫壻。", "杏花如雪柳垂絲，春風蕩颺不同枝。"]'),
('23f88ea8-4327-4059-8981-cda65ecb2099','寄夫 一','張氏','唐','唐诗','tang','','[]','久無音信到羅幃，路遠迢迢遣問誰。',32,'全唐诗/poet.tang.43000.json','["久無音信到羅幃，路遠迢迢遣問誰。", "聞君折得東堂桂，折罷那能不暫歸。"]'),
('6c2792ef-c3af-4ebe-8b1f-e9134da8680b','寄夫 二','張氏','唐','唐诗','tang','','[]','驛使今朝過五湖，殷勤爲我報狂夫。',32,'全唐诗/poet.tang.43000.json','["驛使今朝過五湖，殷勤爲我報狂夫。", "從來誇有龍泉劒，試割相思得斷無。"]'),
('cc2bfccd-37f6-4a0b-8ded-da844d9ed7b6','贈鄭女郎','薛馧','唐','唐诗','tang','','[]','豔陽灼灼河洛神，珠簾繡戶青樓春。',128,'全唐诗/poet.tang.43000.json','["豔陽灼灼河洛神，珠簾繡戶青樓春。", "能彈箜篌弄纖指，愁殺門前少年子。", "笑開一面紅粉妝，東園幾樹桃花死。", "朝理曲，暮理曲，獨坐窗前一片玉。", "行也嬌，坐也嬌，見之令人魂魄銷。", "堂前錦褥紅地鑪，綠沈香榼傾屠蘇。", "解佩時時歇歌管，芙蓉帳裏蘭麝滿。", "晚起羅衣香不斷，滅燭每嫌秋夜短。"]'),
('72c62b15-4e1c-44bd-bb61-e005b0ed0114','古意','薛馧','唐','唐诗','tang','','[]','昨夜巫山中，失却陽臺女。',24,'全唐诗/poet.tang.43000.json','["昨夜巫山中，失却陽臺女。", "朝來香閣裏，獨伴楚王語。"]'),
('a403a234-449e-4e71-bc97-3e589db2feab','贈故人','薛馧','唐','唐诗','tang','','[]','昔別容如玉，今來鬢若絲。',24,'全唐诗/poet.tang.43000.json','["昔別容如玉，今來鬢若絲。", "淚痕應共見，腸斷阿誰知。"]'),
('6102ecfa-9b06-43e2-a6b0-d2061fae8521','句','薛馧','唐','唐诗','tang','','[]','寂寞相思處，雕梁落燕泥。',12,'全唐诗/poet.tang.43000.json','["寂寞相思處，雕梁落燕泥。"]'),
('28b4c653-7b79-44d0-9ee3-d51a6c1b12ca','題奉慈寺','楊德麟','唐','唐诗','tang','','[]','日月金輪動，旃檀碧樹秋。',24,'全唐诗/poet.tang.43000.json','["日月金輪動，旃檀碧樹秋。", "塔分鴻鴈翅，鐘挂鳳凰樓。"]'),
('3e48dd05-26ac-4058-a8e3-96f1814b880e','述懷','崔氏','唐','唐诗','tang','','[]','不怨盧郎年紀大，不怨盧郎官職卑。',32,'全唐诗/poet.tang.43000.json','["不怨盧郎年紀大，不怨盧郎官職卑。", "自恨妾身生較晚，不及盧郎年少時。"]'),
('c84fc5e4-d883-4858-a2a9-0feac1154bab','寄夫','陳玉蘭','唐','唐诗','tang','','["\u601d\u5ff5", "\u5987\u5973", "\u5973\u5b50", "\u5173\u6000"]','夫戍邊關妾在吳，西風吹妾妾憂夫。',32,'全唐诗/poet.tang.43000.json','["夫戍邊關妾在吳，西風吹妾妾憂夫。", "一行書信千行淚，寒到君邊衣到無。"]'),
('682d9a63-2f12-41dc-a146-257f67f17984','寫真寄夫','薛媛','唐','唐诗','tang','','[]','欲下丹青筆，先拈寶鏡寒。',48,'全唐诗/poet.tang.43000.json','["欲下丹青筆，先拈寶鏡寒。", "已經顏索寞，漸覺鬢凋殘。", "淚眼描將易，愁腸寫出難。", "恐君渾忘却，時展畫圖看。"]'),
('5a44ca13-827a-4b80-9192-6b0e6dcf3846','聞琴','孫氏','唐','唐诗','tang','','[]','玉指朱弦軋復清，湘妃愁怨最難聽。',64,'全唐诗/poet.tang.43000.json','["玉指朱弦軋復清，湘妃愁怨最難聽。", "初疑颯颯涼風勁，又似蕭蕭暮雨零。", "近比流泉來碧嶂，遠如玄鶴下青冥。", "夜深彈罷堪惆悵，露溼叢蘭月滿庭。"]'),
('b6dc6340-5ae0-4a87-a04c-cc0074982856','白蠟燭詩','孫氏','唐','唐诗','tang','','[]','景勝銀釭香比蘭，一條白玉偪人寒。',32,'全唐诗/poet.tang.43000.json','["景勝銀釭香比蘭，一條白玉偪人寒。", "他時紫禁春風夜，醉草天書仔細看。"]'),
('58219b41-0a15-4288-a2e2-1ebf982ec88b','謝人送酒','孫氏','唐','唐诗','tang','','[]','謝將清酒寄愁人，澄澈甘香氣味真。',32,'全唐诗/poet.tang.43000.json','["謝將清酒寄愁人，澄澈甘香氣味真。", "好是綠窗風月夜，一杯搖蕩滿懷春。"]'),
('363fd601-bcab-4f51-a099-a7ae9b4cd96c','詩','張立本女','唐','唐诗','tang','','[]','危冠廣袖楚宮妝，獨步閑庭逐夜涼。',32,'全唐诗/poet.tang.43000.json','["危冠廣袖楚宮妝，獨步閑庭逐夜涼。", "自把玉簪敲砌竹，清歌一曲月如霜。"]'),
('bf21db2d-a170-4b69-87bd-1643742ed924','繡龜形詩','侯氏','唐','唐诗','tang','','[]','暌離已是十秋強，對鏡那堪重理妝。',64,'全唐诗/poet.tang.43000.json','["暌離已是十秋強，對鏡那堪重理妝。", "聞鴈幾迴修尺素，見霜先爲製衣裳。", "開箱疊練先垂淚，拂杵調砧更斷腸。", "繡作龜形獻天子，願教征客早還鄉。"]'),
('7d3fe8f4-5d2e-47c8-a3ab-5541f2824fe0','感夫詩','慎氏','唐','唐诗','tang','','[]','當時心事已相關，雨散雲飛一餉間。',32,'全唐诗/poet.tang.43000.json','["當時心事已相關，雨散雲飛一餉間。", "便是孤帆從此去，不堪重上望夫山。"]'),
('52470403-70a0-4488-bf26-4ce55173e96a','謠','薛瑤','唐','唐诗','tang','','[]','化雲心兮思淑貞，洞寂滅兮不見人。',31,'全唐诗/poet.tang.43000.json','["化雲心兮思淑貞，洞寂滅兮不見人。", "瑤草芳兮思芬蒀，將奈何兮青春。"]'),
('65bc9a75-4cee-4066-8037-23cd7f988f6e','題唐安寺閣壁','王霞卿','唐','唐诗','tang','','[]','春來引步暫尋遊，愁見風光倚寺樓。',32,'全唐诗/poet.tang.43000.json','["春來引步暫尋遊，愁見風光倚寺樓。", "正好開懷對煙月，雙眉不覺自如鉤。"]'),
('42c45940-942a-4c90-a13e-32ed4430d218','荅鄭殷彝','王霞卿','唐','唐诗','tang','','[]','君是煙霄折桂身，聖朝方切用儒珍。',32,'全唐诗/poet.tang.43000.json','["君是煙霄折桂身，聖朝方切用儒珍。", "正堪西上文場戰，空向途中泥婦人。"]'),
('f3e0ac13-0145-43b5-b587-fa2a9e714f35','喜盧郎及第','竇梁賓','唐','唐诗','tang','','[]','曉妝初罷眼初瞤，小玉驚人踏破帬。',32,'全唐诗/poet.tang.43000.json','["曉妝初罷眼初瞤，小玉驚人踏破帬。", "手把紅箋書一紙，上頭名字有郎君。"]'),
('6980f51a-151a-4502-a77b-93394915a5bd','雨中看牡丹','竇梁賓','唐','唐诗','tang','','[]','東風未放曉泥乾，紅藥花開不奈寒。',32,'全唐诗/poet.tang.43000.json','["東風未放曉泥乾，紅藥花開不奈寒。", "待得天晴花已老，不如攜手雨中看。"]'),
('aa3898fa-cc2a-4e9a-8535-911cf2be322e','書桐葉','任氏','唐','唐诗','tang','','[]','拭翠斂蛾眉，鬱鬱心中事。',84,'全唐诗/poet.tang.43000.json','["拭翠斂蛾眉，鬱鬱心中事。", "搦管下庭除，書成相思字。", "此字不書石，此字不書紙。", "書在桐葉上，願逐秋風起。", "天下有心人，盡解相思死。", "天下負心人，不識相思字。", "有心與負心，不知落何地。"]'),
('59967f24-5e84-4ceb-8cf3-f57ea305919d','下獄貢詩','黃崇嘏','唐','唐诗','tang','','[]','偶辭幽隱在臨邛，行止堅貞比澗松。',32,'全唐诗/poet.tang.43000.json','["偶辭幽隱在臨邛，行止堅貞比澗松。", "何事政清如水鏡，絆他野鶴在深籠。"]'),
('6f3490a4-e938-481e-8a93-c415b7ccbc20','辭蜀相妻女詩','黃崇嘏','唐','唐诗','tang','','[]','一辭拾翠碧江湄，貧守蓬茅但賦詩。',64,'全唐诗/poet.tang.43000.json','["一辭拾翠碧江湄，貧守蓬茅但賦詩。", "自服藍衫居郡掾，永拋鸞鏡畫蛾眉。", "立身卓爾青松操，挺志鏗然白璧姿。", "幕府若容爲坦腹，願天速變作男兒。"]'),
('a45ceb95-2a3e-4844-a36f-9e46ea2e3b2f','荅諸姊妹戒飲','蔣氏','唐','唐诗','tang','','[]','平生偏好酒，勞爾勸吾餐。',24,'全唐诗/poet.tang.43000.json','["平生偏好酒，勞爾勸吾餐。", "但得杯中滿，時光度不難。"]'),
('02ef842b-bb93-4a59-8960-3dde22d8d6b2','書壁','周仲美','唐','唐诗','tang','','[]','愛妾不愛子，爲問此何理。',84,'全唐诗/poet.tang.43000.json','["愛妾不愛子，爲問此何理。", "棄官更棄妻，人情寧可已。", "永訣泗之濱，遺言空在耳。", "三載無朝昏，孤幃淚如洗。", "婦人義從夫，一節誓生死。", "江鄉感殘春，腸斷晚煙起。", "西望太華峰，不知幾千里。"]'),
('745a9b04-89e7-4b5d-bf35-d328d2403ecc','溪口雲','張文姬','唐','唐诗','tang','','[]','溶溶溪口雲，纔向溪中吐。',24,'全唐诗/poet.tang.43000.json','["溶溶溪口雲，纔向溪中吐。", "不復歸溪中，還作溪中雨。"]'),
('ded41575-fb8a-4f5b-99d6-3c339fd75dc6','池上竹','張文姬','唐','唐诗','tang','','[]','此君臨此池，枝低水相近。',24,'全唐诗/poet.tang.43000.json','["此君臨此池，枝低水相近。", "碧色綠波中，日日流不盡。"]'),
('ba2fd465-d362-495b-a27e-b01e371d8470','沙上鷺','張文姬','唐','唐诗','tang','','[]','沙頭一水禽，鼓翼揚清音。',24,'全唐诗/poet.tang.43000.json','["沙頭一水禽，鼓翼揚清音。", "只待高風便，非無雲漢心。"]'),
('e614ecf9-9216-4c20-9e30-b2215fcac6cd','雙槿樹','張文姬','唐','唐诗','tang','','[]','綠影競扶疎，紅姿相照灼。',24,'全唐诗/poet.tang.43000.json','["綠影競扶疎，紅姿相照灼。", "不學桃李花，亂向春風落。"]'),
('426e4caa-937e-46b9-ba0b-10f149c2ba3b','獄中書情上使君','程長文','唐','唐诗','tang','','[]','妾家本住鄱陽曲，一片貞心比孤竹。',240,'全唐诗/poet.tang.43000.json','["妾家本住鄱陽曲，一片貞心比孤竹。", "當年二八盛容儀，紅牋草隸恰如飛。", "盡日閑窗刺繡坐，有時極浦採蓮歸。", "誰道居貧守都邑，幽閨寂寞無人識。", "海燕朝歸衾枕寒，山花夜落階墀溼。", "強暴之男何所爲，手持白刃向簾幃。", "一命任從刀下死，千金豈受暗中欺。", "我心匪石情難轉，志奪秋霜意不移。", "血濺羅衣終不恨，瘡黏錦袖亦何辭。", "縣僚曾未知情緒，即便教人縶囹圄。", "朱脣滴瀝獨銜冤，玉筯闌干歎非所。", "十月寒更堪思人，一聞擊柝一傷神。", "高髻不梳雲已散，蛾眉罷埽月仍新。", "三尺嚴章難可越，百年心事向誰說。", "但看洗雪出圜扉，始信白圭無玷缺。"]'),
('f90106b9-fcd0-431c-99f5-47f7b728524b','銅雀臺怨','程長文','唐','唐诗','tang','','[]','君王去後行人絕，簫箏不響歌喉咽。',64,'全唐诗/poet.tang.43000.json','["君王去後行人絕，簫箏不響歌喉咽。", "雄劒無威光彩沈，寶琴零落金星滅。", "玉階寂寞墜秋露，月照當時歌舞處。", "當時歌舞人不迴，化爲今日西陵灰。"]'),
('e800e312-b8d9-4708-ae5b-00d2aa31be4c','春閨怨','程長文','唐','唐诗','tang','','[]','[綺]陌香飄柳如線，時光瞬息如流電。',34,'全唐诗/poet.tang.43000.json','["[綺]陌香飄柳如線，時光瞬息如流電。", "良人何處事功名，十載相思不相見。"]'),
('5c1c52e6-2e37-4d73-8a28-b3eb6b6bfbc0','荅韓翃','柳氏','唐','唐诗','tang','','[]','楊柳枝，芳菲節，可恨年年贈離別。',32,'全唐诗/poet.tang.43000.json','["楊柳枝，芳菲節，可恨年年贈離別。", "一葉隨風忽報秋，縱使君來豈堪折。"]'),
('a7196d94-63d7-4fe4-aef6-6a8a65d0a5d0','歸李江州後寄別王氏','程洛賓','唐','唐诗','tang','','[]','魚鴈回時寫報音，難憑剉蘖數年心。',32,'全唐诗/poet.tang.43000.json','["魚鴈回時寫報音，難憑剉蘖數年心。", "雖然情斷沙吒後，爭奈平生怨恨深。"]'),
('43897f0e-e5bc-499e-b38a-f13fa2bdd7b3','憶崔生','紅綃妓','唐','唐诗','tang','','[]','深洞鶯啼恨阮郎，偷來花下解珠璫。',32,'全唐诗/poet.tang.43000.json','["深洞鶯啼恨阮郎，偷來花下解珠璫。", "碧雲飄斷音書絕，空倚玉簫愁鳳皇。"]'),
('5f4006c4-d20f-452e-b5ce-9842d8b77e31','寄文茂','晁采','唐','唐诗','tang','','[]','花箋製葉寄郎邊，的的尋魚爲妾傳。',32,'全唐诗/poet.tang.43000.json','["花箋製葉寄郎邊，的的尋魚爲妾傳。", "幷蒂已看靈鵲報，倩郎早覓買花船。"]'),
('38d5772d-c185-4c22-a232-caddf97c2ecc','秋日再寄','晁采','唐','唐诗','tang','','[]','珍簟生涼夜漏餘，夢中恍惚覺來初。',64,'全唐诗/poet.tang.43000.json','["珍簟生涼夜漏餘，夢中恍惚覺來初。", "魂離不得空成病，面見無由浪寄書。", "窗外江村鐘響絕，枕邊梧葉雨聲疎。", "此時最是思君處，腸斷寒猨定不如。"]'),
('1236566a-1088-490a-91e9-16760e6bb973','春日送夫之長安','晁采','唐','唐诗','tang','','[]','思君遠別妾心愁，踏翠江邊送畫舟。',32,'全唐诗/poet.tang.43000.json','["思君遠別妾心愁，踏翠江邊送畫舟。", "欲待相看遲此別，只憂紅日向西流。"]'),
('6566189d-711d-4771-a6c0-d265def3635d','雨中憶夫 一','晁采','唐','唐诗','tang','','[]','窗前細雨日啾啾，妾在閨中獨自愁。',32,'全唐诗/poet.tang.43000.json','["窗前細雨日啾啾，妾在閨中獨自愁。", "何事玉郎久離別，忘憂總對豈忘憂。"]'),
('911f631b-dcb2-4a6a-8890-9ae0fdf31057','雨中憶夫 二','晁采','唐','唐诗','tang','','[]','春風送雨過窗東，忽憶良人在客中。',32,'全唐诗/poet.tang.43000.json','["春風送雨過窗東，忽憶良人在客中。", "安得妾身今似雨，也隨風去與郎同。"]'),
('8d39d972-81c8-40ce-a3d2-9fb82a1daa0b','子夜歌十八首 一','晁采','唐','唐诗','tang','','[]','儂既剪雲鬟，郎亦分絲髮。',24,'全唐诗/poet.tang.43000.json','["儂既剪雲鬟，郎亦分絲髮。", "覓向無人處，綰作同心結。"]'),
('cee37ed2-dbe3-411d-b652-d274e05b7702','子夜歌十八首 二','晁采','唐','唐诗','tang','','[]','夜夜不成寐，擁被啼終夕。',24,'全唐诗/poet.tang.43000.json','["夜夜不成寐，擁被啼終夕。", "郎不信儂時，但看枕上跡。"]'),
('64df80be-7000-42bb-9c86-decf28286053','子夜歌十八首 三','晁采','唐','唐诗','tang','','[]','何時得成匹，離恨不復牽。',24,'全唐诗/poet.tang.43000.json','["何時得成匹，離恨不復牽。", "金針刺菡萏，夜夜得見蓮。"]'),
('82e22c1d-77a5-4561-9dba-7005a5c737c2','子夜歌十八首 四','晁采','唐','唐诗','tang','','[]','相逢逐涼候，黃花忽復香。',24,'全唐诗/poet.tang.43000.json','["相逢逐涼候，黃花忽復香。", "顰眉臘月露，愁殺未成霜。"]'),
('c174ebbf-0dc4-44c4-8348-6a41a4d13262','子夜歌十八首 五','晁采','唐','唐诗','tang','','[]','明窗弄玉指，指甲如水晶。',24,'全唐诗/poet.tang.43000.json','["明窗弄玉指，指甲如水晶。", "翦之特寄郎，聊當攜手行。"]'),
('fc9e96e8-466a-4de7-b71b-1646656baa78','子夜歌十八首 六','晁采','唐','唐诗','tang','','[]','寄語閨中娘，顏色不常好。',24,'全唐诗/poet.tang.43000.json','["寄語閨中娘，顏色不常好。", "含笑對棘實，歡娛須是棗。"]'),
('b05e9e06-1e7a-4bfc-af7c-0fb9205563df','子夜歌十八首 七','晁采','唐','唐诗','tang','','[]','良會終有時，勸郎莫得怒。',24,'全唐诗/poet.tang.43000.json','["良會終有時，勸郎莫得怒。", "薑蘖畏春蠶，要綿須辛苦。"]'),
('53ff9de3-f372-4951-b7b1-0516bc449c9b','子夜歌十八首 八','晁采','唐','唐诗','tang','','[]','醉夢幸逢郎，無奈烏啞啞。',24,'全唐诗/poet.tang.43000.json','["醉夢幸逢郎，無奈烏啞啞。", "中山如有酒，敢借千金價。"]'),
('dd25c1b1-34ef-4ef7-be11-dea18d41bc53','子夜歌十八首 九','晁采','唐','唐诗','tang','','[]','信使無虛日，玉醞寄盈觥。',24,'全唐诗/poet.tang.43000.json','["信使無虛日，玉醞寄盈觥。", "一年一日雨，底事太多晴。"]'),
('b5cc3885-ba50-4465-9665-6b220aad4ea4','子夜歌十八首 十','晁采','唐','唐诗','tang','','[]','繡房擬會郎，四窗日離離。',24,'全唐诗/poet.tang.43000.json','["繡房擬會郎，四窗日離離。", "手自施屏障，恐有女伴窺。"]'),
('9109c348-3946-40cd-a55a-229f94d9c690','子夜歌十八首 十一','晁采','唐','唐诗','tang','','[]','相思百餘日，相見苦無期。',24,'全唐诗/poet.tang.43000.json','["相思百餘日，相見苦無期。", "褰裳摘藕花，要蓮敢恨池。"]'),
('26ce7874-d932-4474-b787-d96bc75fddd7','子夜歌十八首 十二','晁采','唐','唐诗','tang','','[]','金盆盥素手，焚香誦普門。',24,'全唐诗/poet.tang.43000.json','["金盆盥素手，焚香誦普門。", "來生何所願，與郎爲一身。"]'),
('46bdf6bb-df79-4811-bd72-d49e5a54d514','子夜歌十八首 十三','晁采','唐','唐诗','tang','','[]','花池多芳水，玉杯挹贈郎。',24,'全唐诗/poet.tang.43000.json','["花池多芳水，玉杯挹贈郎。", "避人藏袖裏，溼却素羅裳。"]'),
('e17e862d-214b-4ebd-ae94-a96b4afc6b25','子夜歌十八首 十四','晁采','唐','唐诗','tang','','[]','感郎金鍼贈，欲報物俱輕。',24,'全唐诗/poet.tang.43000.json','["感郎金鍼贈，欲報物俱輕。", "一雙連素縷，與郎聊定情。"]'),
('14407943-9c68-4823-902d-516291d26e7d','子夜歌十八首 十五','晁采','唐','唐诗','tang','','[]','寒風響枯木，通夕不得臥。',24,'全唐诗/poet.tang.43000.json','["寒風響枯木，通夕不得臥。", "早起遣問郎，昨宵何以過。"]'),
('3b8a76d2-d017-4cda-8f8a-3021c48c378a','子夜歌十八首 十六','晁采','唐','唐诗','tang','','[]','得郎日嗣音，令人不可覩。',24,'全唐诗/poet.tang.43000.json','["得郎日嗣音，令人不可覩。", "熊膽磨作墨，書來字字苦。"]'),
('f9587780-178c-4756-8251-9af0eb6cc636','子夜歌十八首 十七','晁采','唐','唐诗','tang','','[]','輕巾手自製，顏色爛含桃。',24,'全唐诗/poet.tang.43000.json','["輕巾手自製，顏色爛含桃。", "先懷儂袖裏，然後約郎腰。"]'),
('3f146ab5-f1a2-4b9e-9e1d-04c7486bfdfd','子夜歌十八首 十八','晁采','唐','唐诗','tang','','[]','儂贈綠絲衣，郎遺玉鉤子。',24,'全唐诗/poet.tang.43000.json','["儂贈綠絲衣，郎遺玉鉤子。", "即欲繫儂心，儂思著郎體。"]'),
('07bdeb64-f528-4187-9b4c-525f1d5e6e5b','荅張生','崔鶯鶯','唐','唐诗','tang','','[]','待月西廂下，迎風戶半開。',24,'全唐诗/poet.tang.43000.json','["待月西廂下，迎風戶半開。", "拂牆花影動，疑是玉人來。"]'),
('4eb5b013-93f1-48bd-a808-2793bb75920d','寄詩','崔鶯鶯','唐','唐诗','tang','','[]','自從銷瘦減容光，萬轉千迴嬾下牀。',32,'全唐诗/poet.tang.43000.json','["自從銷瘦減容光，萬轉千迴嬾下牀。", "不爲傍人羞不起，爲郎憔悴却羞郎。"]'),
('7c211667-c614-419c-97da-fd7c8d73fb6c','告絕詩','崔鶯鶯','唐','唐诗','tang','','[]','棄置今何道，當時且自親。',24,'全唐诗/poet.tang.43000.json','["棄置今何道，當時且自親。", "還將舊來意，憐取眼前人。"]'),
('5fdf5b41-d838-4c3a-8866-9ce89ac30990','荅趙子','步非煙','唐','唐诗','tang','','[]','綠慘雙蛾不自持，只緣幽恨在新詩。',32,'全唐诗/poet.tang.43000.json','["綠慘雙蛾不自持，只緣幽恨在新詩。", "郎心應似琴心怨，脈脈春情更泥誰。"]'),
('661ebc1b-808b-418f-955d-204d5ca66807','又荅趙象獨坐','步非煙','唐','唐诗','tang','','[]','無力嚴妝倚繡櫳，暗題蟬錦思難窮。',32,'全唐诗/poet.tang.43000.json','["無力嚴妝倚繡櫳，暗題蟬錦思難窮。", "近來贏得傷春病，柳弱花敧怯曉風。"]'),
('d427c8bb-101f-4974-984b-a1b920df8480','寄懷','步非煙','唐','唐诗','tang','','[]','畫簷春燕須同宿，蘭浦雙鴛肯獨飛。',32,'全唐诗/poet.tang.43000.json','["畫簷春燕須同宿，蘭浦雙鴛肯獨飛。", "長恨桃源諸女伴，等閑花裏送郎歸。"]'),
('939d8171-0196-4fb4-9eb5-faa10768dce0','荅趙象','步非煙','唐','唐诗','tang','','[]','相思只恨難相見，相見還愁却別君。',32,'全唐诗/poet.tang.43000.json','["相思只恨難相見，相見還愁却別君。", "願得化爲松上鶴，一雙飛去入行雲。"]'),
('e5552adc-0429-470b-a7a3-45d70100bd97','臨行獻李尚書','崔紫雲','唐','唐诗','tang','','[]','從來學製斐然詩，不料霜臺御史知。',32,'全唐诗/poet.tang.43000.json','["從來學製斐然詩，不料霜臺御史知。", "忽見便教隨命去，戀恩腸斷出門時。"]'),
('c6def4d8-1454-4dbc-81d2-cc36cbe54c25','怨詩效徐淑體','姚月華','唐','唐诗','tang','','[]','妾生兮不辰，盛年兮逢屯。',216,'全唐诗/poet.tang.43000.json','["妾生兮不辰，盛年兮逢屯。", "寒暑兮心結，夙夜兮眉顰。", "循環兮不息，如彼兮車輪。", "車輪兮可歇，妾心兮焉伸。", "雜沓兮無緒，如彼兮絲棼。", "絲棼兮可理，妾心兮焉分。", "空閨兮岑寂，妝閣兮生塵。", "萱草兮徒樹，茲憂兮豈泯。", "幸逢兮君子，許結兮殷勤。", "分香兮翦髮，贈玉兮共珍。", "指天兮結誓，願爲兮一身。", "所遭兮多舛，玉體兮難親。", "損餐兮減寢，帶緩兮羅裙。", "菱鑑兮慵啓，博鑪兮焉熏。", "整襪兮欲舉，塞路兮荆榛。", "逢人兮欲語，鞈匝兮頑嚚。", "煩冤兮憑胸，何時兮可論。", "願君兮見察，妾死兮何瞋。"]'),
('f6ce334f-8962-4a1e-af61-2abc7ebf27e4','製履贈楊達','姚月華','唐','唐诗','tang','','[]','金刀翦紫羢，與郎作輕履。',24,'全唐诗/poet.tang.43000.json','["金刀翦紫羢，與郎作輕履。", "願化雙仙鳧，飛來入閨裏。"]'),
('c1294222-3a2c-4827-b4e1-0fa0b4a6571a','有期不至','姚月華','唐','唐诗','tang','','[]','銀燭清尊久延佇，出門入門天欲曙。',32,'全唐诗/poet.tang.43000.json','["銀燭清尊久延佇，出門入門天欲曙。", "月落星稀竟不來，煙柳朧朣鵲飛去。"]'),
('564dbde0-e6ed-4e73-b800-719862aa9011','怨詩寄楊達 一','姚月華','唐','唐诗','tang','','[]','春水悠悠春草綠，對此思君淚相續。',32,'全唐诗/poet.tang.43000.json','["春水悠悠春草綠，對此思君淚相續。", "羞將離恨向東風，理盡秦箏不成曲。"]'),
('c444dd3d-0512-41a5-b1bb-96f6e84eccab','怨詩寄楊達 二','姚月華','唐','唐诗','tang','','[]','與君形影分吳越，玉枕經年對離別。',32,'全唐诗/poet.tang.43000.json','["與君形影分吳越，玉枕經年對離別。", "登臺北望煙雨深，回身泣向寥天月。"]'),
('1621b0d9-b848-4127-bb11-a003297f475a','楚妃怨','姚月華','唐','唐诗','tang','','[]','梧桐葉下黃金井，橫架轆轤牽素綆。',32,'全唐诗/poet.tang.43000.json','["梧桐葉下黃金井，橫架轆轤牽素綆。", "美人初起天未明，手拂銀瓶秋水冷。"]'),
('84896f78-dbd0-46e1-a52b-f7170773fd3b','獨遊家園','孟氏','唐','唐诗','tang','','[]','可惜春時節，依前獨自遊。',24,'全唐诗/poet.tang.43000.json','["可惜春時節，依前獨自遊。", "無端兩行淚，長只對花流。"]'),
('dcf51fd3-bc36-4bac-9c61-b200cba4fd88','荅少年','孟氏','唐','唐诗','tang','','[]','誰家少年兒，心中暗自欺。',24,'全唐诗/poet.tang.43000.json','["誰家少年兒，心中暗自欺。", "不道終不可，可即恐郎知。"]'),
('632e2169-cc1f-4863-9f98-c1a128f6c138','寄情','趙氏','唐','唐诗','tang','','[]','春風白馬紫絲韁，正值蠶娘未採桑。',64,'全唐诗/poet.tang.43000.json','["春風白馬紫絲韁，正值蠶娘未採桑。", "五夜有心隨暮雨，百年無節抱秋霜。", "重尋繡帶朱藤合，却忍羅裙碧草長。", "爲報西遊減離恨，阮郎纔去嫁劉郎。"]'),
('4f0750ec-0fd5-4a06-bbd3-9f60a31d6748','書紅綃帕 一','李節度姬','唐','唐诗','tang','','[]','囊裹真香誰見竊，鮫綃滴淚染成紅。',32,'全唐诗/poet.tang.43000.json','["囊裹真香誰見竊，鮫綃滴淚染成紅。", "殷勤遺下輕綃意，好與情郎懷袖中。"]'),
('d8076177-1331-45f7-a771-fbf8f6987a71','書紅綃帕 二','李節度姬','唐','唐诗','tang','','[]','金珠富貴吾家事，常渴佳期乃寂寥。',32,'全唐诗/poet.tang.43000.json','["金珠富貴吾家事，常渴佳期乃寂寥。", "偶用志誠求雅合，良媒未必勝紅綃。"]'),
('039b706f-19ca-45b0-a622-fa8049f1895e','會張生述懷','李節度姬','唐','唐诗','tang','','[]','門前畫戟尋常設，堂上犀簪取次看。',32,'全唐诗/poet.tang.43000.json','["門前畫戟尋常設，堂上犀簪取次看。", "最是惱人情緒處，鳳皇樓上月華寒。"]'),
('f349de32-aed1-4e1d-8ef3-b62508aa1df2','別韋洵美詩','崔素娥','唐','唐诗','tang','','[]','妾閉閑房君路岐，妾心君恨兩依依。',32,'全唐诗/poet.tang.44000.json','["妾閉閑房君路岐，妾心君恨兩依依。", "神魂倘遇巫娥伴，猶逐朝雲暮雨歸。"]'),
('5b0a781a-b0e6-4fb2-9f68-74d97725152e','送韋生酒','鮑家四弦','唐','唐诗','tang','','[]','白露溼庭砌，皓月臨前軒。',24,'全唐诗/poet.tang.44000.json','["白露溼庭砌，皓月臨前軒。", "此時去留恨，含思獨無言。"]'),
('348d83bb-ab8d-420b-bbbc-6e7fbaf9ea04','送鮑生酒','鮑家四弦','唐','唐诗','tang','','[]','風颭荷珠難暫圓，多情信有短姻緣。',32,'全唐诗/poet.tang.44000.json','["風颭荷珠難暫圓，多情信有短姻緣。", "西樓今夜三更月，還照離人泣斷弦。"]'),
('3f43e36e-87d8-47e2-a45e-ddf115e77c37','贈別','[嚴]續姬','唐','唐诗','tang','','[]','風柳搖搖無定枝，陽臺雲雨夢中歸。',32,'全唐诗/poet.tang.44000.json','["風柳搖搖無定枝，陽臺雲雨夢中歸。", "他年蓬島音塵絕，留取尊前舊舞衣。"]'),
('5f445666-231e-415d-8e86-7f9f7ef1b621','採桑','郎大家宋氏','唐','唐诗','tang','','[]','春來南鴈歸，日去西蠶遠。',24,'全唐诗/poet.tang.44000.json','["春來南鴈歸，日去西蠶遠。", "妾思粉何極，客遊殊未返。"]'),
('67710f4c-2d97-4ce1-8b4d-aa983d74b963','宛轉歌二首 一','郎大家宋氏','唐','唐诗','tang','','[]','風已清，月朗琴復鳴。',44,'全唐诗/poet.tang.44000.json','["風已清，月朗琴復鳴。", "掩抑非千態，殷勤是一聲。", "歌宛轉，宛轉和且長。", "願爲雙鴻鵠，比翼共翺翔。"]'),
('e585dee0-0fc8-4b06-86b9-7531598d5d4f','宛轉歌二首 二','郎大家宋氏','唐','唐诗','tang','','[]','日已暮，長簷鳥聲度。',50,'全唐诗/poet.tang.44000.json','["日已暮，長簷鳥聲度。", "此時望君君不來，此時思君君不顧。", "歌宛轉，宛轉那能異棲宿。", "願爲形與影，出入恆相逐。"]'),
('f6b704e7-b568-4c5c-a17c-2f16efcf67b3','長相思','郎大家宋氏','唐','唐诗','tang','','[]','長相思，久離別。',40,'全唐诗/poet.tang.44000.json','["長相思，久離別。", "關山阻，風煙絕。", "臺上鏡文銷，袖中書字滅。", "不見君形影，何曾有歡悅。"]'),
('7e46a7b6-1e3a-4a44-a4c1-a44687af1022','朝雲引','郎大家宋氏','唐','唐诗','tang','','[]','巴西巫峽指巴東，朝雲觸石上朝空。',50,'全唐诗/poet.tang.44000.json','["巴西巫峽指巴東，朝雲觸石上朝空。", "巫山巫峽高何已，行雨行雲一時起。", "一時起，三春暮。", "若言來，且就陽臺路。"]'),
('a7607e42-9b69-40e6-b963-6e02393010bc','宿巫山寄遠人','梁瓊','唐','唐诗','tang','','[]','巫山雲，巫山雨，朝雲暮雨無定所。',112,'全唐诗/poet.tang.44000.json','["巫山雲，巫山雨，朝雲暮雨無定所。", "南峰忽暗北峰晴，空裏仙人語笑聲。", "曾侍荆王枕席處，直至如今如有靈。", "春風澹澹白雲閑，驚湍流水響千山。", "一夜此中對明月，憶得此中與君別。", "感物情懷如舊時，君今渺渺在天涯。", "曉看襟上淚流處，點點血痕猶在衣。"]'),
('e04bafcb-6d5c-4b40-83c1-67dfa8fe205c','昭君怨','梁瓊','唐','唐诗','tang','','[]','自古無和親，貽災到妾身。',48,'全唐诗/poet.tang.44000.json','["自古無和親，貽災到妾身。", "朔風嘶去馬，漢月出行輪。", "衣薄狼山雪，妝成虜塞春。", "迴看父母國，生死畢胡塵。"]'),
('14aaf7ac-4e70-4ce6-b3c1-4fd0594f2844','銅雀臺','梁瓊','唐','唐诗','tang','','[]','歌扇向陵開，齊行奠玉杯。',48,'全唐诗/poet.tang.44000.json','["歌扇向陵開，齊行奠玉杯。", "舞時飛燕列，夢裏片雲來。", "月色空餘恨，松聲莫更哀。", "誰憐未死妾，掩袂下銅臺。"]'),
('20348cf3-482b-4139-ac8d-cb71ecd3fe29','遠意','梁瓊','唐','唐诗','tang','','[]','脉脉長攄氣，微微不離心。',24,'全唐诗/poet.tang.44000.json','["脉脉長攄氣，微微不離心。", "叩頭從此去，煩惱阿誰禁。"]'),
('9ecb7481-6658-45ad-af00-4b0817d856b7','句','梁瓊','唐','唐诗','tang','','[]','玉枕空流別後淚，羅衣已盡去時香。',16,'全唐诗/poet.tang.44000.json','["玉枕空流別後淚，羅衣已盡去時香。"]'),
('022554eb-12fc-47cb-882e-522994b100b1','有所思','劉雲','唐','唐诗','tang','','[]','朝亦有所思，暮亦有所思。',52,'全唐诗/poet.tang.44000.json','["朝亦有所思，暮亦有所思。", "登樓望君處，藹藹蕭關道。", "掩淚向浮雲，誰知妾懷抱。", "玉井蒼苔春院深，桐花落盡無人埽。"]'),
('58977f8f-2c1b-4aa8-b6d6-6da8742d923a','婕妤怨','劉雲','唐','唐诗','tang','','[]','君恩不可見，妾豈如秋扇。',40,'全唐诗/poet.tang.44000.json','["君恩不可見，妾豈如秋扇。", "秋扇尚有時，妾身永微賤。", "莫言朝花不復落，嬌容幾奪昭陽殿。"]'),
('6613ee43-6bdb-45eb-9b35-3c2ba5400fd7','望月','劉雲','唐','唐诗','tang','','[]','天漢涼秋夜，澄澄一鏡明。',24,'全唐诗/poet.tang.44000.json','["天漢涼秋夜，澄澄一鏡明。", "山空猨屢嘯，林靜鵲頻驚。"]'),
('8a287784-fd73-4e42-8204-45f245be1b09','古意','崔萱','唐','唐诗','tang','','[]','灼灼葉中花，夏萎春又芳。',72,'全唐诗/poet.tang.44000.json','["灼灼葉中花，夏萎春又芳。", "明明天上月，蟾缺圓復光。", "未如君子情，朝違夕已忘。", "玉帳枕猶暖，紈扇思何長。", "願因西南風，吹上玳瑁牀。", "嬌眠錦衾裏，展轉雙鴛鴦。"]'),
('5f81228e-9ff6-4963-97a9-886011eddae0','敘別','崔萱','唐','唐诗','tang','','[]','碧池漾漾春水綠，中有佳禽暮棲宿。',32,'全唐诗/poet.tang.44000.json','["碧池漾漾春水綠，中有佳禽暮棲宿。", "願持此意永相貽，祗慮君情中反覆。"]'),
('7df18d30-ba0e-477a-9cac-b0bc87005307','豪家子','崔萱','唐','唐诗','tang','','[]','年少家藏累代金，紅樓盡日醉沈沈。',32,'全唐诗/poet.tang.44000.json','["年少家藏累代金，紅樓盡日醉沈沈。", "馬非躞蹀寧酬價，人不嬋娟肯動心。"]'),
('253445ea-863a-4807-80c4-c280e4ac96e4','句','崔萱','唐','唐诗','tang','','[]','豈知一隻鳳釵價，沽得數村蝸舍人。',16,'全唐诗/poet.tang.44000.json','["豈知一隻鳳釵價，沽得數村蝸舍人。"]'),
('4e2dc532-9d81-43c0-ad23-e222570b599c','贈所思','崔仲容','唐','唐诗','tang','','[]','所居幸接隣，相見不相親。',48,'全唐诗/poet.tang.44000.json','["所居幸接隣，相見不相親。", "一似雲間月，何殊鏡裏人。", "丹誠空有夢，腸斷不禁春。", "願作梁間燕，無由變此身。"]'),
('d7c7644e-06d3-4446-96ef-7c560ee9d785','戲贈','崔仲容','唐','唐诗','tang','','[]','暫到崑崙未得歸，阮郎何事教人非。',32,'全唐诗/poet.tang.44000.json','["暫到崑崙未得歸，阮郎何事教人非。", "如今身佩上清籙，莫遣落花霑羽衣。"]'),
('9e3e0148-8399-4005-a0af-d3248343a9c8','贈歌姬','崔仲容','唐','唐诗','tang','','[]','水翦雙眸霧翦衣，當筵一曲媚春輝。',64,'全唐诗/poet.tang.44000.json','["水翦雙眸霧翦衣，當筵一曲媚春輝。", "瀟湘夜瑟怨猶在，巫峽曉雲愁不稀。", "皓齒乍分寒玉細，黛眉輕蹙遠山微。", "渭城朝雨休重唱，滿眼陽關客未歸。"]'),
('2c8a4ae5-8871-4227-ac2e-350b29222c34','句','崔仲容','唐','唐诗','tang','','[]','妾心合君心，一似影隨形。',52,'全唐诗/poet.tang.44000.json','["妾心合君心，一似影隨形。", "梁燕無情困，雙棲語此時。", "不覺紅顏去，空嗟白髮生。", "桐花落盡春又盡，紫塞征人猶未歸。"]'),
('92a3eaf7-155e-4e0b-b601-776f35aea623','獨夜詞','崔公遠','唐','唐诗','tang','','[]','晴天霜落寒風急，錦帳羅幃羞更入。',32,'全唐诗/poet.tang.44000.json','["晴天霜落寒風急，錦帳羅幃羞更入。", "秦箏不復續斷弦，回身掩淚挑燈立。"]'),
('c75e95b1-23b1-4b83-b595-671bd6fb55d9','句','崔公遠','唐','唐诗','tang','','[]','看花獨不語，裴回雙淚澘。',28,'全唐诗/poet.tang.44000.json','["看花獨不語，裴回雙淚澘。", "君今遠戍在何處，遣妾秋來長望天。"]'),
('2ddb055c-d9e1-48c6-8f85-b050b76fed21','春詞二首 一','張琰','唐','唐诗','tang','','[]','垂柳鳴黃鸝，關關若求友。',36,'全唐诗/poet.tang.44000.json','["垂柳鳴黃鸝，關關若求友。", "春情不可耐，愁殺閨中婦。", "日暮登高樓，誰憐小垂手。"]'),
('4b52f305-e197-4c72-a5a6-3087de41607d','春詞二首 二','張琰','唐','唐诗','tang','','[]','昨日桃花飛，今朝梨花吐。',36,'全唐诗/poet.tang.44000.json','["昨日桃花飛，今朝梨花吐。", "春色能幾時，那堪此愁緒。", "蕩子遊不歸，春來淚如雨。"]'),
('70e737a7-547d-4d01-8280-03a4b2d374e9','銅雀臺','張琰','唐','唐诗','tang','','[]','君王冥漠不可見，銅雀歌舞空裴回。',44,'全唐诗/poet.tang.44000.json','["君王冥漠不可見，銅雀歌舞空裴回。", "西陵嘖嘖悲宿鳥，高殿沈沈閉青苔。", "青苔無人跡，紅粉空自哀。"]'),
('9f7bfbd7-17d6-4a8f-a738-6d1278d2bc94','句','張琰','唐','唐诗','tang','','[]','年年人自老，日日水東流。',24,'全唐诗/poet.tang.44000.json','["年年人自老，日日水東流。", "庭芳自搖落，永念結中腸。"]'),
('245ce2db-d956-4851-a514-faa5a56bad89','哭夫二首 一','裴羽仙','唐','唐诗','tang','','[]','風卷平沙日欲曛，狼煙遙認犬羊羣。',32,'全唐诗/poet.tang.44000.json','["風卷平沙日欲曛，狼煙遙認犬羊羣。", "李陵一戰無歸日，望斷胡天哭塞雲。"]'),
('19d0cc5c-d597-4a67-a87c-24437cfd4a78','哭夫二首 二','裴羽仙','唐','唐诗','tang','','[]','良人平昔逐蕃渾，力戰輕行出塞門。',32,'全唐诗/poet.tang.44000.json','["良人平昔逐蕃渾，力戰輕行出塞門。", "從此不歸成萬古，空留賤妾怨黃昏。"]'),
('eefaeb9a-a9a2-4c8d-96ac-4d49dcb5bda4','長門怨 一','劉媛','唐','唐诗','tang','','[]','雨滴梧桐秋夜長，愁心和雨到昭陽。',32,'全唐诗/poet.tang.44000.json','["雨滴梧桐秋夜長，愁心和雨到昭陽。", "淚痕不學君恩斷，拭却千行更萬行。"]'),
('41047ebd-0b03-47ca-8ea8-1b7a9d2d9358','長門怨 二','劉媛','唐','唐诗','tang','','[]','學畫蛾眉獨出羣，當時人道便承恩。',32,'全唐诗/poet.tang.44000.json','["學畫蛾眉獨出羣，當時人道便承恩。", "經年不見君王面，花落黃昏空掩門。"]'),
('10048cdb-c87c-4f88-8286-a4fca4960105','送遠','劉媛','唐','唐诗','tang','','[]','聞道瞿塘灩澦堆，青山流水近陽臺。',32,'全唐诗/poet.tang.44000.json','["聞道瞿塘灩澦堆，青山流水近陽臺。", "知君此去無還日，妾亦隨波不復迴。"]'),
('d0b58412-a066-4c0c-b4d9-2e9f2a9e080c','句','劉媛','唐','唐诗','tang','','[]','春風報梅柳，一夜發南枝。',28,'全唐诗/poet.tang.44000.json','["春風報梅柳，一夜發南枝。", "傍人那得知心事，一面殘妝空淚痕。"]'),
('653cf90b-8503-48b6-8ec2-aa75ae6b16cf','懷良人','葛鵶兒','唐','唐诗','tang','','[]','蓬鬢荆釵世所稀，布裙猶是嫁時衣。',32,'全唐诗/poet.tang.44000.json','["蓬鬢荆釵世所稀，布裙猶是嫁時衣。", "胡麻好種無人種，正是歸時不見歸。"]'),
('9a22d583-2fd0-44d0-a399-e798fd738936','會仙詩 一','葛鵶兒','唐','唐诗','tang','','[]','彩鳳搖搖下翠微，煙光漠漠徧芳枝。',32,'全唐诗/poet.tang.44000.json','["彩鳳搖搖下翠微，煙光漠漠徧芳枝。", "玉窗仙會何人見，唯有春風仔細知。"]'),
('fcac029e-2cce-449b-a39d-1264307f8e34','會仙詩 二','葛鵶兒','唐','唐诗','tang','','[]','煙霞迤邐接蓬萊，宮殿參差曉日開。',32,'全唐诗/poet.tang.44000.json','["煙霞迤邐接蓬萊，宮殿參差曉日開。", "羣玉山前人別處，紫鸞飛起望仙臺。"]'),
('f2d5ac7b-8c72-4d84-a819-b732fef697cd','暗別離','劉瑤','唐','唐诗','tang','','[]','槐花結子桐葉焦，單飛越鳥啼青霄。',80,'全唐诗/poet.tang.44000.json','["槐花結子桐葉焦，單飛越鳥啼青霄。", "翠軒輾雲輕遙遙，燕脂淚迸紅線條。", "瑤草歇芳心耿耿，玉佩無聲畫屏冷。", "朱弦暗斷不見人，風動花枝月中影。", "青鸞脉脉西飛去，海闊天高不知處。"]'),
('05042944-c6de-4a97-b22f-32965fbb0774','古意曲','劉瑤','唐','唐诗','tang','','[]','梧桐階下月團團，洞房如水秋夜闌。',48,'全唐诗/poet.tang.44000.json','["梧桐階下月團團，洞房如水秋夜闌。", "吳刀翦破機頭錦，茱萸花墜相思枕。", "綠窗寂寞背燈時，暗數寒更不成寢。"]'),
('d45f6b65-1141-41ac-9666-31b4735f19bb','闔閭城懷古','劉瑤','唐','唐诗','tang','','[]','五湖春水接遙天，國破君亡不記年。',32,'全唐诗/poet.tang.44000.json','["五湖春水接遙天，國破君亡不記年。", "唯有妖娥曾舞處，古臺寂寞起愁煙。"]'),
('dca98db5-1fdc-47d1-a17c-45a52aa94b83','峽中即事','廉氏','唐','唐诗','tang','','[]','清秋三峽此中去，鳴鳥孤猨不可聞。',48,'全唐诗/poet.tang.44000.json','["清秋三峽此中去，鳴鳥孤猨不可聞。", "一道水聲多亂石，四時天色少晴雲。", "日暮泛舟溪漵口，那堪夜永思氛氳。"]'),
('eeb4c966-5e88-4788-8764-4181d8a30ffa','懷遠','廉氏','唐','唐诗','tang','','[]','隟塵何微微，朝夕通其輝。',48,'全唐诗/poet.tang.44000.json','["隟塵何微微，朝夕通其輝。", "人生各有託，君去獨不歸。", "青林有蟬響，赤日無鳥飛。", "裴回東南望，雙淚空霑衣。"]'),
('5849d3ad-78b6-4993-8282-6fc8a82c09e0','寄征人','廉氏','唐','唐诗','tang','','[]','淒淒北風吹鴛被，娟娟西月生蛾眉。',32,'全唐诗/poet.tang.44000.json','["淒淒北風吹鴛被，娟娟西月生蛾眉。", "誰知獨夜相思處，淚滴寒塘蕙草時。"]'),
('9820b8b8-cd3f-4f5a-8c00-44a17c5e7327','寄遠','田娥','唐','唐诗','tang','','[]','憶昨會詩酒，終日相逢迎。',48,'全唐诗/poet.tang.44000.json','["憶昨會詩酒，終日相逢迎。", "今來成故事，歲月令人驚。", "淚流紅粉薄，風度羅衣輕。", "難爲子猷志，虛負文君名。"]'),
('5d9d9ede-c866-4998-a3ad-56b555fda913','攜手曲','田娥','唐','唐诗','tang','','[]','攜手共惜芳菲節，鶯啼錦花滿城闕。',48,'全唐诗/poet.tang.44000.json','["攜手共惜芳菲節，鶯啼錦花滿城闕。", "行樂逶迤念容色，色衰秪恐君恩歇。", "鳳笙龍管白日陰，盈虧自感青天月。"]'),
('c4cb36e5-ee18-4734-96bd-bdccb2fee3b1','長信宮','田娥','唐','唐诗','tang','','[]','團圓手中扇，昔爲君所持。',36,'全唐诗/poet.tang.44000.json','["團圓手中扇，昔爲君所持。", "今日君棄捐，復值秋風時。", "悲將入篋笥，自歎知何爲。"]'),
('b974b7b2-1ab0-4f2f-9edb-4f5660769962','句','田娥','唐','唐诗','tang','','[]','春至偏無興，秋來秪是眠。',12,'全唐诗/poet.tang.44000.json','["春至偏無興，秋來秪是眠。"]'),
('ab994ff1-9f7f-40d8-af58-7966593e7c08','中秋夜泊武昌','劉淑柔','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','兩城相對峙，一水向東流。',48,'全唐诗/poet.tang.44000.json','["兩城相對峙，一水向東流。", "今夜素娥月，何年黃鶴樓。", "悠悠蘭棹晚，渺渺荻花秋。", "無奈柔腸斷，關山總是愁。"]'),
('8835ee02-a5ec-4f9c-b812-e2d9d373607c','賦荆門','薛瓊','唐','唐诗','tang','','[]','黃鳥翻紅樹，青牛臥綠苔。',24,'全唐诗/poet.tang.44000.json','["黃鳥翻紅樹，青牛臥綠苔。", "渚宮歌舞地，輕霧鎖樓臺。"]'),
('db8979f4-2816-450f-8c0d-f42aa28489b2','戲贈','趙虛舟','唐','唐诗','tang','','[]','砌下梧桐葉正齊，花繁雨後壓枝低。',32,'全唐诗/poet.tang.44000.json','["砌下梧桐葉正齊，花繁雨後壓枝低。", "報道不須鵶鳥亂，他家自有鳳凰棲。"]'),
('ae42fd73-831d-4411-919e-0fc62a2218b0','銅雀臺','張瑛','唐','唐诗','tang','','[]','君王冥漠不可見，銅雀歌舞空裴回。',44,'全唐诗/poet.tang.44000.json','["君王冥漠不可見，銅雀歌舞空裴回。", "西陵嘖嘖悲宿鳥，高殿沈沈閉青苔。", "青苔無人跡，紅粉空相哀。"]'),
('39862216-ed03-4c0f-9d5f-6e8745f0dd67','望月','張瑛','唐','唐诗','tang','','[]','天漢涼秋夜，澄澄一鏡明。',24,'全唐诗/poet.tang.44000.json','["天漢涼秋夜，澄澄一鏡明。", "山空猨屢嘯，林靜鶴頻驚。"]'),
('691c2c25-fefa-4a1b-8976-1e51bb881ab4','荅外','長孫佐轉妻','唐','唐诗','tang','','[]','征人去年戍邊水，夜得邊書字盈紙。',96,'全唐诗/poet.tang.44000.json','["征人去年戍邊水，夜得邊書字盈紙。", "揮刀就燭裁紅綺，結作同心荅千里。", "君寄邊書書莫絕，妾荅同心心自結。", "同心再解不心離，離字頻看字愁滅。", "結成一衣和淚封，封書只在懷袖中。", "莫如書故字難久，願學同心長可同。"]'),
('05f044ce-6285-45b0-916a-10849d942b1b','早梅','劉元載妻','唐','唐诗','tang','','[]','南枝向暖北枝寒，一種春風有兩般。',32,'全唐诗/poet.tang.44000.json','["南枝向暖北枝寒，一種春風有兩般。", "憑仗高樓莫吹笛，大家留取倚闌干。"]'),
('eb2b878b-df90-4d93-8cb0-590dd31e1453','明月堂 一','劉氏婦','唐','唐诗','tang','','[]','蟬鬢驚秋華髮新，可憐紅隙盡埃塵。',32,'全唐诗/poet.tang.44000.json','["蟬鬢驚秋華髮新，可憐紅隙盡埃塵。", "西山一夢何年覺，明月堂前不見人。"]'),
('cabfa0f5-1f99-47b2-b9e5-047fd7ff7657','明月堂 二','劉氏婦','唐','唐诗','tang','','[]','玉鉤風急響丁東，回首西山似夢中。',32,'全唐诗/poet.tang.44000.json','["玉鉤風急響丁東，回首西山似夢中。", "明月堂前人不到，庭梧一夜老秋風。"]'),
('92556558-bf3f-4720-888b-78a4a0c5e634','和潘雍','葛氏女','唐','唐诗','tang','','[]','九天天遠瑞煙濃，駕鶴驂鸞意已同。',32,'全唐诗/poet.tang.44000.json','["九天天遠瑞煙濃，駕鶴驂鸞意已同。", "從此三山山上月，瓊花開處照春風。"]'),
('99654625-2d53-4cb0-9bf6-83c88b781506','寄詩','李主簿姬','唐','唐诗','tang','','[]','去時盟約與心違，秋日離家春不歸。',32,'全唐诗/poet.tang.44000.json','["去時盟約與心違，秋日離家春不歸。", "應是維揚風景好，恣情歡笑到芳菲。"]'),
('5aa2d13b-6f5a-4a95-b875-0998ec6f9fc4','題興元明珠亭','京兆女子','唐','唐诗','tang','','[]','寂寥滿地落花紅，獨有離人萬恨中。',32,'全唐诗/poet.tang.44000.json','["寂寥滿地落花紅，獨有離人萬恨中。", "回首池塘更無語，手彈珠淚與春風。"]'),
('802382ff-a138-439a-99c2-5697ae2ef2f4','題玉泉溪','湘驛女子','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u6101\u82e6"]','紅葉醉秋色，碧溪彈夜弦。',24,'全唐诗/poet.tang.44000.json','["紅葉醉秋色，碧溪彈夜弦。", "佳期不可再，風雨杳如年。"]'),
('43597c78-90ae-45d4-90d7-206258606649','題三鄉詩','若耶溪女子','唐','唐诗','tang','','[]','昔逐良人西入關，良人身歿妾空還。',32,'全唐诗/poet.tang.44000.json','["昔逐良人西入關，良人身歿妾空還。", "謝娘衛女不相待，爲雨爲雲歸此山。"]'),
('4ad62f19-486f-4c9e-aedb-2839b134bd27','題沙鹿門','誰氏女','唐','唐诗','tang','','[]','昔逐良人去上京，良人身歿妾東征。',32,'全唐诗/poet.tang.44000.json','["昔逐良人去上京，良人身歿妾東征。", "同來不得同歸去，永負朝雲暮雨情。"]'),
('a14f739c-f704-4690-bc56-3d64a436d84a','聯句','光	威	裒','唐','唐诗','tang','','[]','朱樓影直日當午，玉樹陰低月已三。',192,'全唐诗/poet.tang.44000.json','["朱樓影直日當午，玉樹陰低月已三。", "膩粉暗銷銀鏤合，錯刀閑翦泥金衫。", "繡牀怕引烏龍吠，錦字愁教青鳥銜。", "百味鍊來憐益母，千花開處鬬宜男。", "鴛鴦有伴誰能羨，鸚鵡無言我自慚。", "浪喜游蜂飛撲撲，佯驚孤燕語喃喃。", "偏憐愛數螆蛦掌，每憶光抽玳瑁簪。", "煙洞幾年悲尚在，星橋一夕帳空含。", "窗前時節羞虛擲，世上風流笑苦諳。", "獨結香綃偷餉送，暗垂檀袖學通參。", "須知化石心難定，却是爲雲分易甘。", "看見風光零落盡，弦聲猶逐望江南。"]'),
('1d939efa-882f-4309-a6d1-e308c20efafb','聯句','越溪楊女','唐','唐诗','tang','','[]','珠簾半牀月，青竹滿林風。',24,'全唐诗/poet.tang.44000.json','["珠簾半牀月，青竹滿林風。", "何事今宵景，無人解語同。"]'),
('c5851073-c8d2-4767-9aa4-368b0ddf5241','春日','越溪楊女','唐','唐诗','tang','','[]','春盡花隨盡，其如自是花。',48,'全唐诗/poet.tang.44000.json','["春盡花隨盡，其如自是花。", "從來說花意，不過此容華。", "明月易虧輪，好花難戀春。", "常將花月恨，幷作可憐人。"]'),
('cdd65817-92c0-418b-b438-ae8a2191bfde','句','曹文姬','唐','唐诗','tang','','[]','鑿開天外長生地，煉出人間不死丹。',16,'全唐诗/poet.tang.44000.json','["鑿開天外長生地，煉出人間不死丹。"]'),
('ff3fa1e4-a19d-4174-a3a2-df0cc4d92e6f','燕子樓三首 一','關盼盼','唐','唐诗','tang','','[]','樓上殘燈伴曉霜，獨眠人起合歡牀。',32,'全唐诗/poet.tang.44000.json','["樓上殘燈伴曉霜，獨眠人起合歡牀。", "相思一夜情多少，地角天涯不是長。"]'),
('ac228bec-b314-4f29-9055-f6a7656826cc','燕子樓三首 二','關盼盼','唐','唐诗','tang','','[]','北邙松柏鎖愁煙，燕子樓中思悄然。',32,'全唐诗/poet.tang.44000.json','["北邙松柏鎖愁煙，燕子樓中思悄然。", "自埋劒履歌塵散，紅袖香銷一十年。"]'),
('90de0390-09b6-4600-93f9-785b76ad77bb','燕子樓三首 三','關盼盼','唐','唐诗','tang','','[]','適看鴻雁岳陽迴，又覩玄禽逼社來。',32,'全唐诗/poet.tang.44000.json','["適看鴻雁岳陽迴，又覩玄禽逼社來。", "瑤瑟玉簫無意緒，任從蛛網任從灰。"]'),
('2a0a4812-c838-4110-aaed-21557ce2cc49','和白公詩','關盼盼','唐','唐诗','tang','','[]','自守空樓斂恨眉，形同春後牡丹枝。',32,'全唐诗/poet.tang.44000.json','["自守空樓斂恨眉，形同春後牡丹枝。", "舍人不會人深意，訝道泉臺不去隨。"]'),
('0d13dcd5-c6c6-4bf8-92fd-b2e2aee78e3b','句','關盼盼','唐','唐诗','tang','','[]','兒童不識沖天物，漫把青泥污雪毫。',16,'全唐诗/poet.tang.44000.json','["兒童不識沖天物，漫把青泥污雪毫。"]'),
('e858f015-2cf5-420c-870a-621f1e85dd2c','囉嗊曲六首 一','劉采春','唐','唐诗','tang','','[]','不喜秦淮水，生憎江上船。',24,'全唐诗/poet.tang.44000.json','["不喜秦淮水，生憎江上船。", "載兒夫壻去，經歲又經年。"]'),
('c693bf0e-7b67-4502-a0b6-19753aa799bb','囉嗊曲六首 二','劉采春','唐','唐诗','tang','','[]','借問東園柳，枯來得幾年。',24,'全唐诗/poet.tang.44000.json','["借問東園柳，枯來得幾年。", "自無枝葉分，莫怨太陽偏。"]'),
('a2a74af8-d559-4941-80f0-1b7d3c427f52','囉嗊曲六首 三','劉采春','唐','唐诗','tang','','[]','莫作商人婦，金釵當卜錢。',24,'全唐诗/poet.tang.44000.json','["莫作商人婦，金釵當卜錢。", "朝朝江口望，錯認幾人船。"]'),
('3f3b5d49-4baf-4326-b9f7-8ca654d0c3f9','囉嗊曲六首 四','劉采春','唐','唐诗','tang','','["\u95fa\u6028"]','那年離別日，只道住桐廬。',24,'全唐诗/poet.tang.44000.json','["那年離別日，只道住桐廬。", "桐廬人不見，今得廣州書。"]'),
('80f7584f-ac84-40ce-b4ec-86e8edbb9637','囉嗊曲六首 五','劉采春','唐','唐诗','tang','','["\u9ec4\u6cb3"]','昨日勝今日，今年老去年。',24,'全唐诗/poet.tang.44000.json','["昨日勝今日，今年老去年。", "黃河清有日，白髮黑無緣。"]'),
('5b3b6c87-dfbf-47d5-8b47-ff210190740e','囉嗊曲六首 六','劉采春','唐','唐诗','tang','','[]','昨日北風寒，牽船浦裏安。',24,'全唐诗/poet.tang.44000.json','["昨日北風寒，牽船浦裏安。", "潮來打纜斷，搖櫓始知難。"]'),
('daa34fe1-59ef-4a15-8c16-882b758d5e06','寄歐陽詹','太原妓','唐','唐诗','tang','','["\u601d\u5ff5", "\u7231\u60c5"]','自從別後減容光，半是思郎半恨郎。',32,'全唐诗/poet.tang.44000.json','["自從別後減容光，半是思郎半恨郎。", "欲識舊來雲髻樣，爲奴開取縷金箱。"]'),
('dfef5c19-8a9c-4c05-be51-d24cb2c1ce76','續韋蟾句','武昌妓','唐','唐诗','tang','','[]','悲莫悲兮生別離，登山臨水送將歸。',32,'全唐诗/poet.tang.44000.json','["悲莫悲兮生別離，登山臨水送將歸。", "武昌無限新栽柳，不見楊花撲面飛。"]'),
('aef49398-d683-436d-9884-3145cfb7f8a8','獻李觀察','舞柘枝女','唐','唐诗','tang','','[]','湘江舞罷忽成悲，便脫蠻靴出絳帷。',32,'全唐诗/poet.tang.44000.json','["湘江舞罷忽成悲，便脫蠻靴出絳帷。", "誰是蔡邕琴酒客，魏公懷舊嫁文姬。"]'),
('13ca1660-45c6-4d77-81a1-8e6d98d0f75b','贈盧夫人','常浩','唐','唐诗','tang','','[]','佳人惜顏色，恐逐芳菲歇。',48,'全唐诗/poet.tang.44000.json','["佳人惜顏色，恐逐芳菲歇。", "日暮出畫堂，下堦拜新月。", "拜月如有詞，傍人那得知。", "歸來投玉枕，始覺淚痕垂。"]'),
('42213986-9ad5-4b3a-bbe9-38f1aaf69cc8','寄遠','常浩','唐','唐诗','tang','','[]','年年二月時，十年期別期。',88,'全唐诗/poet.tang.44000.json','["年年二月時，十年期別期。", "春風不知信，軒蓋獨遲遲。", "今日無端捲珠箔，始見庭花復零落。", "人心一往不復歸，歲月來時未嘗錯。", "可憐熒熒玉鏡臺，塵飛冪冪幾時開。", "却念容華非昔好，畫眉猶自待君來。"]'),
('574c4ef0-3e5f-402e-9663-c34a9e871094','送武補闕','襄陽妓','唐','唐诗','tang','','[]','弄珠灘上欲銷魂，獨把離懷寄酒尊。',32,'全唐诗/poet.tang.44000.json','["弄珠灘上欲銷魂，獨把離懷寄酒尊。", "無限煙花不留意，忍教芳草怨王孫。"]'),
('39c27e90-6c08-4eca-91f4-d595476a3c43','題孫棨詩後','王福娘','唐','唐诗','tang','','[]','苦把文章邀勸人，吟看好箇語言新。',32,'全唐诗/poet.tang.44000.json','["苦把文章邀勸人，吟看好箇語言新。", "雖然不及相如賦，也直黃金一二斤。"]'),
('2003f214-004c-47e5-ba88-3b3d0922ae2e','問棨詩','王福娘','唐','唐诗','tang','','[]','日日悲傷未有圖，嬾將心事話凡夫。',32,'全唐诗/poet.tang.44000.json','["日日悲傷未有圖，嬾將心事話凡夫。", "非同覆水應收得，只問仙郎有意無。"]'),
('0c6b743d-67eb-4201-97cf-1ae1b8d8fd7c','謝棨詩','王福娘','唐','唐诗','tang','','[]','久賦恩情欲託身，已將心事再三陳。',32,'全唐诗/poet.tang.44000.json','["久賦恩情欲託身，已將心事再三陳。", "泥蓮既沒移栽分，今日分離莫恨人。"]'),
('fdc0e48f-426e-49f6-b00a-3c0b056323ce','荅小子弟詩','楊萊兒','唐','唐诗','tang','','[]','黃口小兒口莫憑，逡巡看取第三名。',32,'全唐诗/poet.tang.44000.json','["黃口小兒口莫憑，逡巡看取第三名。", "孝廉持水添缾子，莫向街頭亂椀鳴。"]'),
('705323cd-0250-475f-99fc-de605dd37c80','和趙光遠題壁','楊萊兒','唐','唐诗','tang','','[]','長者車塵每到門，長卿非慕卓王孫。',64,'全唐诗/poet.tang.44000.json','["長者車塵每到門，長卿非慕卓王孫。", "定知羽翼難隨鳳，却喜波濤未化鯤。", "嬌別翠鈿黏去袂，醉歌金雀碎殘尊。", "多情多病年應促，早辦名香爲返魂。"]'),
('001f0948-aab3-462e-abab-bb2b819cda0a','貽鄭昌圖','楚兒','唐','唐诗','tang','','[]','應是前生有宿冤，不期今世惡因緣。',64,'全唐诗/poet.tang.44000.json','["應是前生有宿冤，不期今世惡因緣。", "蛾眉欲碎巨靈掌，雞肋難勝子路拳。", "秪擬嚇人傳鐵券，未應教我踏青蓮。", "曲江昨日君相遇，當下遭他數十鞭。"]'),
('c9cd16aa-876f-4bb9-b871-ea629ceb4104','和李標','王蘇蘇','唐','唐诗','tang','','[]','怪得犬驚雞亂飛，羸童瘦馬老麻衣。',32,'全唐诗/poet.tang.44000.json','["怪得犬驚雞亂飛，羸童瘦馬老麻衣。", "阿誰亂引閑人到，留住青蚨熱趕歸。"]'),
('87bd24e2-01df-4a79-abfb-efb95d837171','臨終召客','顏令賓','唐','唐诗','tang','','[]','氣餘三五喘，花剩兩三枝。',24,'全唐诗/poet.tang.44000.json','["氣餘三五喘，花剩兩三枝。", "話別一尊酒，相邀無後期。"]'),
('57168810-72bc-4465-9d8d-469e45e3d948','寄故人','張窈窕','唐','唐诗','tang','','[]','淡淡春風花落時，不堪愁望更相思。',32,'全唐诗/poet.tang.44000.json','["淡淡春風花落時，不堪愁望更相思。", "無金可買長門賦，有恨空吟團扇詩。"]'),
('d78fc260-abdc-4de9-a29b-58274b9636a6','上成都在事','張窈窕','唐','唐诗','tang','','[]','昨日賣衣裳，今日賣衣裳。',36,'全唐诗/poet.tang.44000.json','["昨日賣衣裳，今日賣衣裳。", "衣裳渾賣盡，羞見嫁時箱。", "有賣愁仍緩，無時心轉傷。"]'),
('e2ffe758-af77-4a7c-b246-fe47ca00414b','春思二首 一','張窈窕','唐','唐诗','tang','','[]','門前梅柳爛春輝，閉妾深閨繡舞衣。',32,'全唐诗/poet.tang.44000.json','["門前梅柳爛春輝，閉妾深閨繡舞衣。", "雙燕不知腸欲斷，銜泥故故傍人飛。"]'),
('7dfdd875-80b6-4595-b41a-af4bf573f2d1','春思二首 二','張窈窕','唐','唐诗','tang','','[]','井上梧桐是妾移，夜來花發最高枝。',32,'全唐诗/poet.tang.44000.json','["井上梧桐是妾移，夜來花發最高枝。", "若教不向深閨種，春過門前爭得知。"]'),
('4074a45c-dec2-4bbd-bc7d-683b73ac7fac','西江行','張窈窕','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','日下西塞山，南來洞庭客。',24,'全唐诗/poet.tang.44000.json','["日下西塞山，南來洞庭客。", "晴空白鳥度，萬里秋光碧。"]'),
('e699650a-5b53-4a8a-b058-69a4d0835457','贈所思','張窈窕','唐','唐诗','tang','','[]','與君咫尺長離別，遣妾容華爲誰說。',32,'全唐诗/poet.tang.44000.json','["與君咫尺長離別，遣妾容華爲誰說。", "夕望層城眼欲穿，曉臨明鏡腸堪絕。"]'),
('9cedf269-5e30-4b83-8152-021819148eac','句','張窈窕','唐','唐诗','tang','','[]','滿院花飛人不到，含情欲語燕雙雙。',16,'全唐诗/poet.tang.44000.json','["滿院花飛人不到，含情欲語燕雙雙。"]'),
('82b32c76-2612-4e64-bafa-62900044331c','贈裴思謙','平康妓','唐','唐诗','tang','','[]','銀釭斜背解明璫，小語偷聲賀玉郎。',32,'全唐诗/poet.tang.44000.json','["銀釭斜背解明璫，小語偷聲賀玉郎。", "從此不知蘭麝貴，夜來新惹桂枝香。"]'),
('88bb632d-cfbf-49dd-803b-69f1a5de4eac','迷香洞','史鳳','唐','唐诗','tang','','[]','洞口飛瓊佩羽霓，香風飄拂使人迷。',32,'全唐诗/poet.tang.44000.json','["洞口飛瓊佩羽霓，香風飄拂使人迷。", "自從邂逅芙蓉帳，不數桃花流水溪。"]'),
('477dd50e-337e-4b46-b80d-22c5db42b19e','神雞枕','史鳳','唐','唐诗','tang','','[]','枕繪鴛鴦久與棲，新裁霧縠鬬神雞。',32,'全唐诗/poet.tang.44000.json','["枕繪鴛鴦久與棲，新裁霧縠鬬神雞。", "與郎酣夢渾忘曉，雞亦留連不肯啼。"]'),
('6b354f44-4b85-44a9-8077-e85f01a4ea23','鎖蓮燈','史鳳','唐','唐诗','tang','','[]','燈鎖蓮花花照罍，翠鈿同醉楚臺巍。',32,'全唐诗/poet.tang.44000.json','["燈鎖蓮花花照罍，翠鈿同醉楚臺巍。", "殘灰剔罷攜纖手，也勝金蓮送轍回。"]'),
('05cab70c-2a39-4101-b376-1931d6ecdc98','鮫紅被','史鳳','唐','唐诗','tang','','[]','肱被當年僅禦寒，青樓慣染血猩紈。',32,'全唐诗/poet.tang.44000.json','["肱被當年僅禦寒，青樓慣染血猩紈。", "牙牀舒卷鵷鸞共，正值窗櫺月一團。"]'),
('fa8419f0-2bb4-4017-8f7c-95df04afc84f','傳香枕','史鳳','唐','唐诗','tang','','[]','韓壽香從何處傳，枕邊芳馥戀嬋娟。',32,'全唐诗/poet.tang.44000.json','["韓壽香從何處傳，枕邊芳馥戀嬋娟。", "休疑粉黛加鋌刃，玉女旃檀侍佛前。"]'),
('1f9e5ad2-b4ed-43a1-a234-31a80c2ec780','八分羊','史鳳','唐','唐诗','tang','','[]','党家風味足肥羊，綺閣留人漫較量。',32,'全唐诗/poet.tang.44000.json','["党家風味足肥羊，綺閣留人漫較量。", "萬羊亦是男兒事，莫學狂夫取次嘗。"]'),
('ee8c9fc6-237d-4f41-bf87-6988452fde55','閉門羮','史鳳','唐','唐诗','tang','','[]','一豆聊供游冶郎，去時忙喚鎖倉琅。',32,'全唐诗/poet.tang.44000.json','["一豆聊供游冶郎，去時忙喚鎖倉琅。", "入門獨慕相如侶，欲撥瑤琴彈鳳凰。"]'),
('779b5d60-21da-4e85-900d-6454a7ad0972','突厥三臺','盛小叢','唐','唐诗','tang','','[]','雁門山上雁初飛，馬邑闌中馬正肥。',32,'全唐诗/poet.tang.44000.json','["雁門山上雁初飛，馬邑闌中馬正肥。", "日旰山西逢驛使，殷勤南北送征衣。"]'),
